window.PACTO.acts["reg-2019-1896"]={"label": "REGOLAMENTO (UE) 2019/1896 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2019/1896", "file": "ext-reg-2019-1896.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2019/1896/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento istituisce una guardia di frontiera e costiera europea per garantire una gestione europea integrata alle frontiere esterne, allo scopo di gestire tali frontiere efficacemente e nel pieno rispetto dei diritti fondamentali e aumentare l'efficienza della politica dei rimpatri dell'Unione.</p>"], [null, "<p class=\"oj-normal\">Il presente regolamento considera le sfide migratorie e le potenziali sfide e minacce future alle frontiere esterne, garantendo un livello elevato di sicurezza interna nell'Unione, nel pieno rispetto dei diritti fondamentali, e salvaguardando al contempo la libera circolazione delle persone al suo interno. Contribuisce a individuare, prevenire e combattere la criminalità transfrontaliera alle frontiere esterne.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento si applicano le seguenti definizioni:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«frontiere esterne»: le frontiere esterne come definite all'articolo 2, punto 2, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«valico di frontiera»: il valico di frontiera come definito all'articolo 2, punto 8, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">3)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«controllo di frontiera»: il controllo di frontiera come definito all'articolo 2, punto 10, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">4)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«verifiche di frontiera»: le verifiche di frontiera come definite all'articolo 2, punto 11, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">5)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«sorveglianza di frontiera»: la sorveglianza di frontiera come definita all'articolo 2, punto 12, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">6)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«sorveglianza delle frontiere aeree»: la sorveglianza di qualsiasi volo di un aeromobile con o senza equipaggio e dei suoi passeggeri o merci diretto o proveniente dal territorio degli Stati membri, che non sia un volo interno quale definito all'articolo 2, punto 3, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">7)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«conoscenza situazionale»: la capacità di monitorare, individuare, identificare, localizzare e comprendere le attività transfrontaliere illegali allo scopo di trovare fondati motivi per misure di reazione, combinando nuove informazioni alle conoscenze già acquisite, ed essere maggiormente in grado di ridurre le perdite di vite di migranti alle frontiere esterne, lungo le stesse o in loro prossimità;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">8)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«capacità di reazione»: la capacità di intraprendere azioni dirette a contrastare attività transfrontaliere illegali alle frontiere esterne, lungo le stesse o in loro prossimità, compresi i mezzi e i tempi necessari per reagire adeguatamente;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">9)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«Eurosur»: il quadro per lo scambio di informazioni e la cooperazione tra gli Stati membri e l'Agenzia europea della guardia di frontiera e costiera;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">10)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«quadro situazionale»: un'aggregazione di informazioni e dati georeferenziati quasi in tempo reale trasmessi da varie autorità, sensori, piattaforme e altre fonti mediante canali di comunicazione e informazione sicuri, che possono essere trattati e visualizzati in modo selettivo ed essere condivisi con altre autorità pertinenti allo scopo di ottenere una conoscenza situazionale e sostenere la capacità di reazione alle frontiere esterne, lungo le stesse o in loro prossimità e nella zona pre-frontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">11)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«sezione di frontiera esterna»: l'intera frontiera esterna di uno Stato membro o parte di essa, come definita dal diritto nazionale o determinata dal centro nazionale di coordinamento o da altra autorità nazionale responsabile;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">12)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«reato di criminalità transfrontaliera»: un reato grave avente una dimensione transfrontaliera consumato o tentato alle frontiere esterne, lungo le stesse o in loro prossimità;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">13)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«zona pre-frontaliera»: l'area geografica situata oltre le frontiere esterne che è rilevante ai fini della gestione delle frontiere esterne tramite l'analisi dei rischi e la conoscenza situazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">14)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«episodio»: una situazione connessa all'immigrazione illegale, alla criminalità transfrontaliera o a un rischio per la vita dei migranti alle frontiere esterne, lungo le stesse o in loro prossimità;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">15)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«personale statutario»: il personale alle dipendenze dell'Agenzia europea della guardia di frontiera e costiera conformemente allo statuto dei funzionari dell'Unione europea («statuto dei funzionari») e al regime applicabile agli altri agenti dell'Unione europea stabiliti dal regolamento (CEE, Euratom, CECA) n. 259/68 del Consiglio (<span class=\"oj-super oj-note-tag\">34</span>);</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">16)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«personale operativo»: le guardie di frontiera, le scorte per i rimpatri, gli esperti in materia di rimpatrio e altro personale competente facente parte del corpo permanente della guardia di frontiera e costiera europea conformemente alle quattro categorie di cui all'articolo 54, paragrafo 1, che agiscono in qualità di membri delle squadre aventi poteri esecutivi, se del caso, e il personale statutario responsabile del funzionamento dell'unità centrale del sistema europeo d'informazione e autorizzazione di viaggio (ETIAS) che non possono essere schierati come membri delle squadre;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">17)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«membri delle squadre»: i membri del corpo permanente della guardia di frontiera e costiera europea impiegati nell'ambito delle squadre per la gestione delle frontiere, delle squadre di sostegno per la gestione della migrazione e delle squadre per il rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">18)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«squadre per la gestione delle frontiere»: le squadre formate dal corpo permanente della guardia di frontiera e costiera europea, da impiegare nelle operazioni congiunte alle frontiere esterne e negli interventi rapidi alle frontiere negli Stati membri e nei paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">19)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«squadre di sostegno per la gestione della migrazione»: le squadre di esperti che forniscono un rinforzo tecnico e operativo agli Stati membri, anche nei punti di crisi, composte da personale operativo, esperti dell'EASO ed Europol e, se del caso, da esperti provenienti dall'Agenzia dell'Unione europea per i diritti fondamentali (FRA) e da altri organi, uffici e agenzie dell'Unione e degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">20)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«Stato membro ospitante»: lo Stato membro nel quale ha luogo o dal quale prende avvio un'operazione congiunta o un intervento rapido alle frontiere, un'operazione di rimpatrio o un intervento di rimpatrio, o nel quale è impiegata una squadra di sostegno per la gestione della migrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">21)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«Stato membro di appartenenza»: lo Stato membro dal quale un membro del personale è impiegato o distaccato presso il corpo permanente della guardia di frontiera e costiera europea;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">22)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«Stato membro partecipante»: lo Stato membro che partecipa a un'operazione congiunta, a un intervento rapido alle frontiere, a un'operazione di rimpatrio, a un intervento di rimpatrio o all'invio di una squadra di sostegno per la gestione della migrazione, fornendo attrezzatura tecnica o personale per i corpo permanente della guardia di frontiera e costiera europea, nonché lo Stato membro che partecipa a operazioni di rimpatrio o interventi di rimpatrio fornendo attrezzatura tecnica o personale, diverso dallo Stato membro ospitante;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">23)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«punto di crisi» (<span class=\"oj-italic\">hotspot</span>): una zona creata su richiesta dello Stato membro ospitante in cui lo Stato membro ospitante, la Commissione, le agenzie competenti dell'Unione e gli Stati membri partecipanti cooperano allo scopo di gestire una sfida migratoria sproporzionata, reale o potenziale, caratterizzata da un aumento significativo del numero di migranti in arrivo alla frontiera esterna;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">24)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«rimpatrio»: il rimpatrio come definito all'articolo 3, punto 3, della direttiva 2008/115/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">25)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«decisione di rimpatrio»: una decisione amministrativa o giudiziale ovvero un atto che attesti o dichiari l'illegalità del soggiorno di un cittadino di paese terzo e imponga o attesti l'obbligo di rimpatrio, nel rispetto della direttiva 2008/115/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">26)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«rimpatriando»: il cittadino di paese terzo il cui soggiorno è irregolare e che è soggetto a una decisione di rimpatrio esecutiva;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">27)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«operazione di rimpatrio»: un'operazione organizzata o coordinata dall'Agenzia europea della guardia di frontiera e costiera che implichi un rinforzo tecnico e operativo a uno o più Stati membri, nell'ambito della quale rimpatriandi provenienti da uno o più Stati membri sono rimpatriati in modo forzato o su base volontaria, indipendentemente dal mezzo di trasporto;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">28)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«intervento di rimpatrio»: un'attività dell'Agenzia europea della guardia di frontiera e costiera che fornisce agli Stati membri un'assistenza tecnica e operativa rafforzata mediante l'impiego di squadre per il rimpatrio e l'organizzazione di operazioni di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">29)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«squadre per il rimpatrio»: le squadre formate a partire dal corpo permanente della guardia di frontiera e costiera europea, da impiegare nelle operazioni di rimpatrio, negli interventi di rimpatrio negli Stati membri o in altre attività operative connesse all'attuazione dei compiti attinenti al rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">30)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«funzionario di collegamento incaricato dell'immigrazione»: il funzionario di collegamento incaricato dell'immigrazione come definito all'articolo 2, punto 1, del regolamento (UE) 2019/1240 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">35</span>).</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Gestione europea integrata delle frontiere", "anchor": "art_3", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La gestione europea integrata delle frontiere comprende i seguenti elementi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controllo di frontiera, comprese misure volte ad agevolare l'attraversamento legale delle frontiere e, se del caso: misure connesse alla prevenzione e all'individuazione della criminalità transfrontaliera alle frontiere esterne, in particolare il traffico di migranti, la tratta di esseri umani e il terrorismo; e meccanismi e procedure per l'identificazione delle persone vulnerabili e dei minori non accompagnati e che consentano l'identificazione delle persone che necessitano di protezione internazionale o intendono chiedere protezione, la fornitura di informazioni a tali persone e la presa in carico delle stesse;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">operazioni di ricerca e soccorso per le persone in pericolo in mare, avviate e svolte a norma del regolamento (UE) n. 656/2014 e del diritto internazionale, che hanno luogo e sono avviate in situazioni che possono verificarsi nel corso di operazioni di sorveglianza delle frontiere in mare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">analisi dei rischi per la sicurezza interna e analisi delle minacce che possono pregiudicare il funzionamento o la sicurezza delle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambio di informazioni e cooperazione tra gli Stati membri nei settori contemplati dal presente regolamento, nonché lo scambio di informazioni e la cooperazione tra gli Stati membri e l'Agenzia europea della guardia di frontiera e costiera, incluso il sostegno coordinato dalla medesima Agenzia europea della guardia di frontiera e costiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperazione inter-agenzia tra le autorità nazionali di ciascuno Stato membro responsabili del controllo di frontiera o di altri compiti svolti alle frontiere e tra le autorità responsabili del rimpatrio di ciascuno Stato membro, compreso lo scambio regolare di informazioni tramite gli strumenti di scambio di informazioni esistenti, inclusa, se del caso, la cooperazione con gli organi nazionali incaricati di tutelare i diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperazione tra le istituzioni, gli organi, gli uffici e le agenzie competenti dell'Unione nei settori contemplati dal presente regolamento, anche tramite lo scambio regolare di informazioni;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperazione con i paesi terzi nei settori contemplati dal presente regolamento, con particolare attenzione ai paesi del vicinato e ai paesi terzi che sono stati individuati tramite un'analisi dei rischi come paesi di origine e/o di transito dell'immigrazione illegale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">misure tecniche e operative nello spazio Schengen che sono connesse al controllo di frontiera e destinate ad affrontare l'immigrazione illegale e a combattere la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il rimpatrio di cittadini di paesi terzi soggetti a decisioni di rimpatrio adottate da uno Stato membro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'uso di tecnologie avanzate, compresi sistemi d'informazione su larga scala;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un meccanismo di controllo della qualità, in particolare il meccanismo di valutazione Schengen, la valutazione delle vulnerabilità ed eventuali meccanismi nazionali, per garantire l'applicazione del diritto dell'Unione nel settore della gestione delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">meccanismi di solidarietà, in particolare gli strumenti di finanziamento dell'Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I diritti fondamentali, l'istruzione e la formazione, nonché la ricerca e l'innovazione, sono elementi generali dell'attuazione della gestione europea integrata delle frontiere.</p>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Guardia di frontiera e costiera europea", "anchor": "art_4", "frags": [[null, "<p class=\"oj-normal\">Le autorità nazionali degli Stati membri preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, le autorità nazionali responsabili in materia di rimpatrio, e l'Agenzia europea della guardia di frontiera e costiera («Agenzia») costituiscono la guardia di frontiera e costiera europea.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Agenzia europea della guardia di frontiera e costiera", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia è disciplinata dal presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia comprende il corpo permanente della guardia di frontiera e costiera europea («corpo permanente») di cui all'articolo 54, con una capacità massima di personale operativo di 10 000 membri, ai sensi dell'allegato I.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Per assicurare una gestione europea integrata delle frontiere coerente, l'Agenzia facilita e rende più efficace l'applicazione delle misure dell'Unione relative alla gestione delle frontiere esterne, in particolare il regolamento (UE) 2016/399, e delle misure dell'Unione relative al rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia contribuisce a un'applicazione continua e uniforme del diritto dell'Unione, compreso l'<span class=\"oj-italic\">acquis</span> dell'Unione in materia di diritti fondamentali, in particolare la Carta dei diritti fondamentali dell'Unione europea («Carta»), alle frontiere esterne dell'Unione. Il suo contributo include lo scambio di buone prassi.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Responsabilità", "anchor": "art_6", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia risponde del proprio operato al Parlamento europeo e al Consiglio, ai sensi del presente regolamento.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Responsabilità condivisa", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La guardia di frontiera e costiera europea attua la gestione europea integrata delle frontiere come responsabilità condivisa tra l'Agenzia e le autorità nazionali preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono operazioni di sorveglianza delle frontiere marittime e qualsiasi altro compito di controllo di frontiera. Gli Stati membri mantengono la responsabilità primaria della gestione delle loro sezioni di frontiera esterna.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia fornisce assistenza tecnica e operativa nell'attuazione delle misure relative ai rimpatri di cui all'articolo 48 del presente regolamento, su richiesta dello Stato membro interessato o di propria iniziativa e in accordo con lo Stato membro interessato. Gli Stati membri mantengono la responsabilità esclusiva dell'emissione delle decisioni di rimpatrio e dell'adozione delle misure attinenti al trattenimento dei rimpatriandi ai sensi della direttiva 2008/115/CE.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri provvedono alla gestione delle proprie frontiere esterne e all'esecuzione delle decisioni di rimpatrio, in stretta cooperazione con l'Agenzia, nel proprio interesse e nell'interesse comune di tutti gli Stati membri, nel pieno rispetto del diritto dell'Unione, anche per quanto concerne il rispetto dei diritti fondamentali, e ai sensi del ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere, di cui all'articolo 8.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia sostiene l'applicazione delle misure dell'Unione relative alla gestione delle frontiere esterne e all'esecuzione delle decisioni di rimpatrio potenziando, valutando e coordinando gli interventi degli Stati membri e fornendo assistenza tecnica e operativa nell'attuazione di tali misure, nonché in materia di rimpatrio. L'Agenzia non sostiene alcuna misura né interviene in attività relative ai controlli alle frontiere interne. L'Agenzia è pienamente responsabile e rende conto di qualsiasi decisione da essa adottata e di qualsiasi attività per la quale ha responsabilità esclusiva a norma del presente regolamento.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri possono collaborare a livello operativo con altri Stati membri o paesi terzi qualora tale cooperazione sia compatibile con i compiti dell'Agenzia. Gli Stati membri si astengono da qualsiasi attività che possa mettere a rischio il funzionamento dell'Agenzia o il raggiungimento dei suoi obiettivi. Gli Stati membri riferiscono all'Agenzia in merito a tale cooperazione operativa con altri Stati membri o paesi terzi alle frontiere esterne e in materia di rimpatrio. Il direttore esecutivo informa il consiglio di amministrazione su tali questioni periodicamente e almeno una volta all'anno.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione e la guardia di frontiera e costiera europea garantiscono l'efficacia della gestione europea integrata delle frontiere attraverso un ciclo politico strategico pluriennale che è adottato secondo la procedura di cui al paragrafo 4.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere fissa le modalità per rispondere in modo coerente, integrato e sistematico alle sfide nel settore della gestione delle frontiere e dei rimpatri. Esso fissa le priorità politiche e fornisce orientamenti strategici per un periodo di cinque anni in merito agli elementi di cui all'articolo 3.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere consta delle quattro fasi descritte ai paragrafi da 4 a 7 del presente articolo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione elabora un documento di orientamento contenente una politica strategica pluriennale per la gestione europea integrata delle frontiere, sulla base dell'analisi strategica dei rischi per la gestione europea integrata delle frontiere di cui all'articolo 29, paragrafo 2. Tale documento di orientamento è presentato dalla Commissione al Parlamento europeo e al Consiglio per essere discusso. In seguito a tale discussione, la Commissione adotta una comunicazione che definisce la politica strategica pluriennale per la gestione europea integrata delle frontiere.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Al fine di attuare la politica strategica pluriennale per la gestione europea integrata delle frontiere, l'Agenzia, con decisione del consiglio di amministrazione e sulla base di una proposta del direttore esecutivo, elaborata in stretta collaborazione con gli Stati membri e la Commissione, definisce una strategia tecnica e operativa per la gestione europea integrata delle frontiere. Ove giustificato, l'Agenzia tiene conto delle situazioni specifiche degli Stati membri, in particolare della loro ubicazione geografica. Detta strategia tecnica e operativa è conforme all'articolo 3 e alla politica strategica pluriennale per la gestione europea integrata delle frontiere. Essa promuove e sostiene l'attuazione della gestione europea integrata delle frontiere in tutti gli Stati membri.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Al fine di attuare la politica strategica pluriennale per la gestione europea integrata delle frontiere, gli Stati membri definiscono le strategie nazionali per la gestione europea integrata delle frontiere, in stretta cooperazione con tutte le autorità nazionali responsabili della gestione delle frontiere esterne e del rimpatrio. Dette strategie nazionali sono conformi all'articolo 3, alla politica strategica pluriennale per la gestione europea integrata delle frontiere e alla strategia tecnica e operativa.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Quattro anni dopo l'adozione della politica strategica pluriennale per la gestione europea integrata delle frontiere, la Commissione effettua una valutazione approfondita della sua attuazione. I risultati di tale valutazione sono presi in considerazione nella preparazione del ciclo successivo di politica strategica pluriennale. Gli Stati membri e l'Agenzia forniscono tempestivamente alla Commissione le informazioni necessarie per l'effettuazione di tale valutazione. La Commissione comunica i risultati di tale valutazione al Parlamento europeo e al Consiglio.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Qualora la situazione alle frontiere esterne o nel settore del rimpatrio richieda una modifica delle priorità politiche, la Commissione modifica la politica strategica pluriennale per la gestione europea integrata delle frontiere o parti pertinenti della stessa secondo la procedura di cui al paragrafo 4.</p>\n<p class=\"oj-normal\">Qualora la Commissione modifichi la politica strategica pluriennale di cui al primo comma, la strategia tecnica e operativa e le strategie nazionali sono adattate ove necessario.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Pianificazione integrata", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Sulla base del ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere, la guardia di frontiera e costiera europea stabilisce una procedura di pianificazione integrata per la gestione delle frontiere e i rimpatri, che comprende le procedure di pianificazione operativa, pianificazione di emergenza e pianificazione dello sviluppo delle capacità. Tale procedura di pianificazione integrata è stabilita ai sensi dei paragrafi 2, 3 e 4 del presente articolo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri e l'Agenzia adottano piani operativi per la gestione delle frontiere e i rimpatri. I piani operativi degli Stati membri relativi alle sezioni di frontiera con livelli di impatto alti e critici sono coordinati con gli Stati membri vicini e con l'Agenzia, al fine di attuare le misure transfrontaliere necessarie e fornire il sostegno dell'Agenzia. Per le attività dell'Agenzia, le procedure di pianificazione operativa per l'anno successivo sono fissate in un allegato del documento unico di programmazione di cui all'articolo 102. Per ciascuna specifica attività operativa, le procedure di pianificazione operativa derivano dai piani operativi di cui all'articolo 38 e all'articolo 74, paragrafo 3. I piani operativi o parti di essi possono essere opportunamente classificati a norma dell'articolo 92.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ciascuno Stato membro adotta un piano di emergenza per la gestione delle proprie frontiere e i rimpatri. In linea con le strategie nazionali per la gestione integrata delle frontiere, il piano di emergenza descrive tutte le misure e le risorse necessarie per un eventuale rafforzamento delle capacità, ivi compresa la logistica e il sostegno sia a livello nazionale che da parte dell'Agenzia.</p>\n<p class=\"oj-normal\">La parte dei piani di emergenza per cui occorre un sostegno supplementare della guardia di frontiera e costiera europea è elaborata congiuntamente dallo Stato membro interessato e dall'Agenzia in stretto coordinamento con gli Stati membri vicini.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri adottano piani nazionali di sviluppo delle capacità per la gestione delle frontiere e i rimpatri in linea con le loro strategie nazionali per la gestione integrata delle frontiere. Tali piani nazionali di sviluppo delle capacità descrivono l'evoluzione a medio e lungo termine delle capacità nazionali per la gestione delle frontiere e i rimpatri.</p>\n<p class=\"oj-normal\">I piani di sviluppo delle capacità nazionali riguardano gli sviluppi di ciascun elemento della gestione europea integrata delle frontiere, in particolare la politica di assunzione e di formazione delle guardie di frontiera e degli esperti in materia di rimpatrio, l'acquisto e la manutenzione delle attrezzature, le necessarie attività di ricerca e sviluppo, così come i corrispondenti requisiti e fonti di finanziamento.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I piani di emergenza e i piani nazionali di sviluppo delle capacità di cui ai paragrafi 3 e 4 si basano sugli scenari che sono tratti dall'analisi dei rischi. Tali scenari rispecchiano la possibile evoluzione della situazione alle frontiere esterne e nel settore della immigrazione illegale e le sfide individuate nel ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere. Tali scenari sono definiti nei piani di emergenza e nei piani nazionali di sviluppo delle capacità cui si riferiscono.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   La metodologia e la procedura per definire i piani di cui ai paragrafi 3 e 4 sono adottate dal consiglio di amministrazione, previa consultazione degli Stati membri, sulla base di una proposta del direttore esecutivo.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia elabora una sintesi dei piani nazionali di sviluppo delle capacità e una strategia pluriennale per l'acquisto delle attrezzature dell'Agenzia di cui all'articolo 63 e la pianificazione pluriennale dei profili del personale del corpo permanente.</p>\n<p class=\"oj-normal\">L'Agenzia condivide tale sintesi con gli Stati membri e la Commissione al fine di individuare eventuali sinergie e opportunità di cooperazione nei diversi settori contemplati dai piani nazionali di sviluppo delle capacità, compresi gli appalti congiunti. Sulla base delle sinergie individuate, l'Agenzia può invitare gli Stati membri a partecipare ad azioni di follow-up ai fini di tale cooperazione.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il consiglio di amministrazione si riunisce almeno una volta all'anno per discutere e approvare la tabella di marcia relativa alle capacità della guardia di frontiera e costiera europea. La tabella di marcia relativa alle capacità è proposta dal direttore esecutivo sulla base di una visione d'insieme dei piani nazionali di sviluppo delle capacità, tenendo conto, fra l'altro, dei risultati dell'analisi dei rischi e delle valutazioni delle vulnerabilità effettuate ai sensi degli articoli 29 e 32 e dei piani pluriennali propri dell'Agenzia. Una volta approvata dal consiglio di amministrazione, la tabella di marcia relativa alle capacità è allegata alla strategia tecnica e operativa di cui all'articolo 8, paragrafo 5.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Compiti dell'Agenzia europea della guardia di frontiera e costiera", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia svolge i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora i flussi migratori e svolge analisi dei rischi su tutti gli aspetti della gestione integrata delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora le esigenze operative degli Stati membri connesse all'esecuzione dei rimpatri, anche mediante la raccolta di dati operativi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">effettua una valutazione delle vulnerabilità, comprendente la verifica della capacità e della preparazione degli Stati membri a fronteggiare minacce e sfide alle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora la gestione delle frontiere esterne tramite i propri funzionari di collegamento negli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora il rispetto dei diritti fondamentali nell'ambito di tutte le sue attività alle frontiere esterne e delle operazioni di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostiene lo sviluppo e il funzionamento di Eurosur;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri in circostanze che richiedono una maggiore assistenza tecnica e operativa alle frontiere esterne coordinando e organizzando operazioni congiunte, tenendo conto del fatto che alcune situazioni possono comportare emergenze umanitarie e il soccorso in mare, ai sensi del diritto dell'Unione e del diritto internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri in circostanze che richiedono una maggiore assistenza tecnica e operativa alle frontiere esterne avviando interventi rapidi alle frontiere esterne degli Stati membri che fronteggiano sfide specifiche e sproporzionate, tenendo conto del fatto che alcune situazioni possono comportare emergenze umanitarie e il soccorso in mare, ai sensi del diritto dell'Unione e del diritto internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce assistenza tecnica e operativa agli Stati membri e ai paesi terzi, a norma del regolamento (UE) n. 656/2014 e del diritto internazionale, a sostegno delle operazioni di ricerca e soccorso per le persone in pericolo in mare che possono verificarsi nel corso di operazioni marittime di sorveglianza delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">invia il corpo permanente nell'ambito di squadre per la gestione delle frontiere, squadre di sostegno per la gestione della migrazione e squadre per il rimpatrio (collettivamente indicate come «squadre») durante operazioni congiunte, nonché in interventi rapidi alle frontiere, operazioni di rimpatrio e interventi di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce un parco attrezzature tecniche, compresa una riserva di attrezzatura di reazione rapida, da impiegare nelle operazioni congiunte, negli interventi rapidi alle frontiere e nell'ambito delle squadre di sostegno per la gestione della migrazione, nonché in operazioni di rimpatrio e interventi di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppa e gestisce, con il sostegno di un meccanismo interno di controllo della qualità, le proprie capacità umane e tecniche per contribuire al corpo permanente, comprese l'assunzione e la formazione dei membri del proprio personale che agiscono in qualità di membri di squadre, e al parco attrezzature tecniche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell'ambito delle squadre di sostegno per la gestione della migrazione nei punti di crisi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">invia personale operativo e attrezzatura tecnica per fornire assistenza nelle operazioni di selezione (<span class=\"oj-italic\">screening</span>), raccolta di informazioni (<span class=\"oj-italic\">debriefing</span>), identificazione e rilevamento delle impronte digitali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce una procedura di indirizzamento alle autorità (<span class=\"oj-italic\">referral</span>) e informazione iniziale per le persone che necessitano di protezione internazionale o intendono presentare domanda in tal senso, inclusa una procedura di identificazione dei gruppi vulnerabili, in cooperazione con l'EASO e le autorità nazionali competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce assistenza in tutte le fasi della procedura di rimpatrio, senza entrare nel merito delle decisioni di rimpatrio, che restano di esclusiva responsabilità degli Stati membri, concorre al coordinamento e all'organizzazione delle operazioni di rimpatrio e fornisce sostegno tecnico e operativo per adempiere all'obbligo di rimpatriare le persone soggette a espulsione, nonché sostegno tecnico e operativo in relazione alle operazioni e agli interventi di rimpatrio, anche in circostanze che richiedono maggiore assistenza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce una riserva di osservatori per i rimpatri forzati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">invia squadre per il rimpatrio durante gli interventi di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell'ambito dei rispettivi mandati delle agenzie interessate, collabora con Europol ed Eurojust e assiste gli Stati membri in circostanze che richiedono una maggiore assistenza tecnica e operativa alle frontiere esterne nella lotta alla criminalità transfrontaliera e al terrorismo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coopera con l'EASO, nell'ambito dei rispettivi mandati, in particolare per agevolare l'adozione di misure nei casi in cui cittadini di paesi terzi la cui domanda di protezione internazionale sia stata respinta con decisione definitiva siano oggetto di una procedura di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coopera con la FRA, nell'ambito dei rispettivi mandati, per garantire l'applicazione continua e uniforme dell'<span class=\"oj-italic\">acquis</span> dell'Unione in materia di diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coopera con l'Agenzia europea di controllo della pesca (EFCA) e l'Agenzia europea per la sicurezza marittima (EMSA), nell'ambito dei rispettivi mandati, al fine di aiutare le autorità nazionali a svolgere le funzioni di guardia costiera di cui all'articolo 69, tra cui salvare vite umane in mare, fornendo servizi, informazioni, attrezzatura e formazione, nonché coordinando operazioni multifunzionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coopera con i paesi terzi nei settori contemplati dal presente regolamento, anche mediante il possibile impiego operativo di squadre per la gestione delle frontiere nei paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">v)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri e i paesi terzi nel contesto della cooperazione tecnica e operativa tra loro negli ambiti disciplinati dal presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">w)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri e i paesi terzi nella formazione delle guardie di frontiera nazionali, di altro personale competente e degli esperti nazionali in materia di rimpatrio, anche attraverso la definizione di standard e programmi comuni di formazione, ivi compreso per quanto riguarda i diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">x)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">partecipa allo sviluppo e alla gestione di attività di ricerca e innovazione utili per il controllo delle frontiere esterne, tra cui l'uso di tecnologie avanzate di sorveglianza, ed elabora propri progetti pilota, ove necessario, per l'attuazione delle attività previste dal presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">y)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppa norme tecniche per lo scambio di informazioni;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">z)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostiene lo sviluppo di norme tecniche per l'attrezzatura nel settore del controllo di frontiera e del rimpatrio, anche per l'interconnessione di sistemi e reti, e sostiene, ove opportuno, lo sviluppo di norme minime comuni per la sorveglianza delle frontiere esterne, in linea con le rispettive competenze degli Stati membri e della Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">aa)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituisce e aggiorna la rete di comunicazione di cui all'articolo 14;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ab)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppa e fornisce, ai sensi del regolamento (UE) 2018/1725, sistemi informativi che consentano scambi rapidi e affidabili di informazioni sui rischi emergenti in materia di gestione delle frontiere esterne, immigrazione illegale e rimpatrio, in stretta cooperazione con la Commissione, gli organi, gli uffici e le agenzie dell'Unione e la rete europea sulle migrazioni istituita con decisione 2008/381/CE del Consiglio (<span class=\"oj-super oj-note-tag\">36</span>);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ac)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ove opportuno, presta la necessaria assistenza per sviluppare un ambiente comune di condivisione delle informazioni, compresa l'interoperabilità dei sistemi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ad)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">segue standard elevati per quanto riguarda la gestione delle frontiere, assicurando la trasparenza e il controllo pubblico, nel pieno rispetto del diritto applicabile, e garantendo il rispetto, la protezione e la promozione dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ae)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestisce e fornisce il sistema relativo ai documenti falsi e autentici online di cui all'articolo 79 e fornisce sostegno agli Stati membri nell'individuazione dei casi di frode documentale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">af)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adempie ai compiti e agli obblighi affidati all'Agenzia dal regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">37</span>) e assicura l'istituzione e il funzionamento dell'unità centrale ETIAS ai sensi dell'articolo 7 di tale regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ag)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assiste gli Stati membri nel facilitare le persone nell'attraversamento delle frontiere esterne.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia comunica sulle questioni che rientrano nel suo mandato. Essa fornisce al pubblico informazioni precise, dettagliate, tempestive ed esaustive sulle sue attività.</p>\n<p class=\"oj-normal\">Tale comunicazione non può pregiudicare i compiti di cui al paragrafo 1 del presente articolo e, in particolare, non può divulgare informazioni operative che, se rese pubbliche, comprometterebbero il raggiungimento dell'obiettivo delle operazioni. L'agenzia comunica fatto salvo l'articolo 92 e ai sensi dei pertinenti piani di comunicazione e divulgazione adottati dal consiglio di amministrazione e, ove opportuno, in stretta cooperazione con altri organi e organismi.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Dovere di leale collaborazione", "anchor": "art_11", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia, le autorità nazionali preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera e le autorità nazionali responsabili in materia di rimpatri, hanno il dovere di collaborare lealmente e l'obbligo di scambiarsi informazioni.</p>"]]}, "12": {"label": "Articolo 12", "heading": "Obbligo di scambio di informazioni", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per svolgere i compiti conferiti loro dal presente regolamento, l'Agenzia, le autorità nazionali preposte alla gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, e le autorità nazionali responsabili in materia di rimpatri condividono, a norma del presente regolamento e di altra pertinente normativa dell'Unione e nazionale riguardante lo scambio di informazioni, tutte le informazioni necessarie in modo tempestivo e accurato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia adotta le misure appropriate per agevolare lo scambio, con la Commissione e gli Stati membri, di informazioni utili all'assolvimento dei suoi compiti.</p>\n<p class=\"oj-normal\">In caso di informazioni utili all'assolvimento dei suoi compiti, l'Agenzia procede allo scambio di tali informazioni con altri organi, uffici e agenzie dell'Unione competenti al fine dell'analisi dei rischi, della raccolta di dati statistici, della valutazione della situazione nei paesi terzi, della formazione e del sostegno agli Stati membri in merito alla pianificazione di emergenza. A tal fine, le strutture e gli strumenti necessari sono sviluppati fra le istituzioni, gli organi e gli organismi dell'Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia adotta tutte le misure necessarie per semplificare lo scambio, con l'Irlanda e il Regno Unito, di informazioni utili all'assolvimento dei suoi compiti se esse sono inerenti alle attività cui tali paesi partecipano a norma dell'articolo 70 e dell'articolo 100, paragrafo 5.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Punti di contatto nazionale", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni Stato membro designa un punto di contatto nazionale per la comunicazione con l'Agenzia su tutte le questioni attinenti alle attività della stessa, fatto salvo il ruolo dei centri nazionali di coordinamento. Il punto di contatto nazionale è raggiungibile in qualsiasi momento e assicura la divulgazione tempestiva di tutte le informazioni dall'Agenzia a tutte le autorità pertinenti dello Stato membro interessato, in particolare ai membri del consiglio di amministrazione e del centro nazionale di coordinamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono designare fino a due membri da assegnare quali funzionari di collegamento presso l'Agenzia in rappresentanza del loro punto di contatto nazionale. I funzionari di collegamento agevolano la comunicazione tra il punto di contatto nazionale e l'Agenzia e possono, se necessario, partecipare alle riunioni pertinenti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia mette a disposizione, nella sua sede, i locali necessari e il supporto adeguato per l'espletamento dei compiti dei funzionari di collegamento. Tutte le altre spese connesse all'impiego dei funzionari di collegamento sono a carico dello Stato membro. Il consiglio di amministrazione specifica le norme e le condizioni dell'impiego, nonché le norme riguardanti il sostegno adeguato richiesto.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Rete di comunicazione", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce e aggiorna una rete di comunicazione, al fine di fornire strumenti di comunicazione e di analisi e consentire lo scambio di informazioni sensibili non classificate e di informazioni classificate, in modo sicuro e quasi in tempo reale, con e tra i centri nazionali di coordinamento.</p>\n<p class=\"oj-normal\">Qualsiasi sistema o applicazione che utilizza la rete di comunicazione rispetta il diritto dell'Unione in materia di protezione dei dati durante tutto il suo ciclo di vita.</p>\n<p class=\"oj-normal\">La rete di comunicazione è operativa 24 ore su 24 e sette giorni su sette e provvede ai seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambio bilaterale e multilaterale di informazioni quasi in tempo reale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">audioconferenze e videoconferenze;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestione, conservazione, trasmissione e trattamento sicuri di informazioni sensibili non classificate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestione, conservazione, trasmissione e trattamento sicuri di informazioni classificate UE fino al livello CONFIDENTIEL UE/EU CONFIDENTIAL o a livelli di classifica nazionali equivalenti, garantendo che le informazioni classificate siano gestite, archiviate, trasmesse e trattate in una sezione distinta e debitamente accreditata della rete di comunicazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia fornisce assistenza tecnica e garantisce che la rete di comunicazione sia disponibile in permanenza e possa sostenere il sistema di comunicazione e informazione gestito dall'Agenzia.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Sistemi e applicazioni per lo scambio di informazioni gestiti dall'Agenzia", "anchor": "art_15", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può adottare tutte le misure necessarie per agevolare lo scambio di informazioni utili all'assolvimento dei suoi compiti con il Parlamento europeo, il Consiglio, la Commissione, gli Stati membri e, se del caso, altre istituzioni dell'Unione e gli organi e gli organismi dell'Unione e le organizzazioni internazionali elencate all'articolo 68, paragrafo 1, e i paesi terzi come previsto all'articolo 71.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia sviluppa, attiva e fornisce un sistema informativo che permetta di scambiare informazioni classificate e informazioni sensibili non classificate con gli interlocutori di cui al paragrafo 1 del presente articolo, e di scambiare i dati personali di cui agli articoli da 86 a 91 ai sensi dell'articolo 92.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia impiega i sistemi informativi di cui al paragrafo 2 del presente articolo nella rete di comunicazione di cui all'articolo 14, ove opportuno.</p>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Norme tecniche per lo scambio di informazioni", "anchor": "art_16", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia, in collaborazione con gli Stati membri, sviluppa norme tecniche per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">interconnettere la rete di comunicazione di cui all'articolo 14 con le reti nazionali usate per stabilire i quadri situazionali nazionali di cui all'articolo 25 e gli altri sistemi informativi pertinenti al fine del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppare e istituire interfacce tra i pertinenti sistemi e applicazioni software per lo scambio di informazioni dell'Agenzia e degli Stati membri al fine del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">trasmettere i quadri situazionali e, ove opportuno, i quadri situazionali specifici di cui all'articolo 27 e garantire la comunicazione tra i pertinenti centri e unità delle autorità nazionali competenti e con le squadre inviate dall'Agenzia attraverso vari mezzi di comunicazione, quali le comunicazioni satellitari e reti radio;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferire la posizione dei mezzi propri utilizzando al meglio lo sviluppo tecnologico del sistema di radionavigazione via satellite istituito nell'ambito del programma Galileo ai sensi del regolamento (UE) n. 1285/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">38</span>).</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "17": {"label": "Articolo 17", "heading": "Garanzia di sicurezza delle informazioni", "anchor": "art_17", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri garantiscono tramite il rispettivo centro di coordinamento nazionale e sotto la vigilanza delle autorità nazionali competenti che le proprie autorità, agenzie e altri organi nazionali, nel momento in cui utilizzano la rete di comunicazione di cui all'articolo 14 e i sistemi di scambio di informazioni dell'Agenzia:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">abbiano un accesso adeguato e continuo ai pertinenti sistemi e reti dell'Agenzia o ai sistemi e reti connessi a essi;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rispettino le pertinenti norme tecniche di cui all'articolo 16;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">applichino regole e norme di sicurezza equivalenti a quelle applicate dall'Agenzia per il trattamento delle informazioni classificate;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambino, trattino e conservino le informazioni sensibili non classificate e le informazioni classificate ai sensi dell'articolo 92.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "18": {"label": "Articolo 18", "heading": "EUROSUR", "anchor": "art_18", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento istituisce Eurosur quale quadro integrato per lo scambio di informazioni e la cooperazione operativa all'interno della guardia di frontiera e costiera europea al fine di migliorare la conoscenza situazionale e aumentare la capacità di reazione ai fini della gestione delle frontiere, ivi compreso al fine di individuare, prevenire e combattere l'immigrazione illegale e la criminalità transfrontaliera e contribuire a garantire la protezione e la salvezza della vita dei migranti.</p>"]]}, "19": {"label": "Articolo 19", "heading": "Ambito di applicazione di Eurosur", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Eurosur è utilizzato per le verifiche di frontiera ai valichi di frontiera autorizzati e per la sorveglianza delle frontiere esterne terrestri, marittime e aeree, inclusi il monitoraggio, l'individuazione, l'identificazione, la localizzazione, la prevenzione e l'intercettazione degli attraversamenti non autorizzati delle frontiere al fine di individuare, prevenire e combattere l'immigrazione illegale e la criminalità transfrontaliera e contribuire a garantire la protezione e la salvezza della vita dei migranti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Eurosur non può essere utilizzato per eventuali misure giuridiche o amministrative adottate una volta che le autorità competenti di uno Stato membro abbiano intercettato attività criminali transfrontaliere o attraversamenti non autorizzati delle frontiere esterne.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Componenti di Eurosur", "anchor": "art_20", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri e l'Agenzia utilizzano Eurosur per lo scambio di informazioni e per la cooperazione nel settore del controllo di frontiera, tenendo conto dei meccanismi esistenti di scambio di informazioni e di cooperazione. Eurosur è costituito dalle seguenti componenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri nazionali di coordinamento di cui all'articolo 21;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadri situazionali nazionali, di cui all'articolo 25;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadro situazionale europeo di cui all'articolo 26, incluse le informazioni sulle sezioni di frontiera esterna con i corrispondenti livelli di impatto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quadri situazionali specifici di cui all'articolo 27;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">servizi Eurosur per la fusione dei dati, di cui all'articolo 28;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">pianificazione integrata di cui all'articolo 9.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I centri nazionali di coordinamento forniscono all'Agenzia, tramite la rete di comunicazione di cui all'articolo 14 e i sistemi pertinenti, le informazioni, tratte dai loro quadri situazionali nazionali e, ove opportuno, dai quadri situazionali specifici, che sono necessarie per istituire e aggiornare il quadro situazionale europeo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia conferisce ai centri nazionali di coordinamento, tramite la rete di comunicazione, accesso illimitato 24 ore su 24 e sette giorni su sette ai quadri situazionali specifici e al quadro situazionale europeo.</p>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Centri nazionali di coordinamento", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni Stato membro istituisce, attiva e gestisce un centro nazionale di coordinamento che provvede al coordinamento e allo scambio di informazioni tra tutte le autorità responsabili del controllo delle frontiere esterne a livello nazionale, nonché con gli altri centri nazionali di coordinamento e con l'Agenzia. Ogni Stato membro comunica l'istituzione del proprio centro nazionale di coordinamento alla Commissione, che ne informa immediatamente gli altri Stati membri e l'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatto salvo l'articolo 13 e nell'ambito della struttura di Eurosur, il centro nazionale di coordinamento costituisce l'unico punto di contatto per lo scambio di informazioni e la cooperazione con gli altri centri nazionali di coordinamento e con l'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I centri nazionali di coordinamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedono allo scambio tempestivo di informazioni e alla cooperazione tempestiva tra tutte le autorità nazionali responsabili del controllo delle frontiere esterne a livello nazionale, nonché con gli altri centri nazionali di coordinamento e con l'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedono allo scambio tempestivo di informazioni con le autorità responsabili delle attività di ricerca e soccorso, delle attività di contrasto, dell'asilo e dell'immigrazione, e gestisce la diffusione delle informazioni pertinenti a livello nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono alla gestione efficace ed efficiente delle risorse e del personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituiscono e aggiornano il quadro situazionale nazionale ai sensi dell'articolo 25;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostengono il coordinamento, la pianificazione e l'attuazione del controllo nazionale di frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinano i sistemi nazionali di controllo di frontiera, ai sensi del diritto nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono a misurare a scadenze regolari gli effetti del controllo nazionale di frontiera ai fini del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinano le misure operative con altri Stati membri e paesi terzi, fatte salve le competenze dell'Agenzia e degli altri Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambiano le informazioni pertinenti con i funzionari di collegamento del proprio Stato membro incaricati dell'immigrazione, ove designati, attraverso adeguate strutture istituite a livello nazionale, al fine di contribuire al quadro situazionale europeo e sostenere le operazioni di controllo di frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono, sotto la vigilanza delle autorità nazionali competenti, alla garanzia di sicurezza delle informazioni dei sistemi informativi nazionali e dei sistemi informativi dell'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri possono incaricare autorità regionali, locali, funzionali o di altro tipo, che siano in grado di adottare decisioni operative, di assicurare la conoscenza situazionale e la capacità di reazione nelle rispettive aree di competenza, nonché i compiti e le competenze elencate all'articolo 21, paragrafo 3, lettere c), e) e f).</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La decisione di uno Stato membro di ripartire i compiti ai sensi del paragrafo 4 non compromette la capacità del centro nazionale di coordinamento di cooperare e scambiare informazioni con altri centri nazionali di coordinamento e con l'Agenzia.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   In casi prestabiliti, determinati a livello nazionale, un centro nazionale di coordinamento può autorizzare un'autorità di cui al paragrafo 4 a comunicare e scambiare informazioni con le autorità regionali o il centro nazionale di coordinamento di un altro Stato membro o le autorità competenti di un paese terzo, a condizione che tale autorità autorizzata informi regolarmente il suo centro nazionale di coordinamento di tali comunicazioni e scambi di informazioni.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il centro nazionale di coordinamento è operativo 24 ore su 24 e sette giorni su sette.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Manuale Eurosur", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione in stretta cooperazione con l'Agenzia e ogni altro organo, ufficio o agenzia competente dell'Unione, adotta e mette a disposizione un manuale pratico per l'attuazione e la gestione di Eurosur («manuale Eurosur»). Il manuale Eurosur fornisce orientamenti tecnici e operativi, raccomandazioni e migliori prassi, anche in merito alla cooperazione con paesi terzi. La Commissione adotta il manuale Eurosur sotto forma di raccomandazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione può decidere, previa consultazione degli Stati membri e dell'Agenzia, di classificare parti del manuale Eurosur come RESTREINT UE/EU RESTRICTED secondo le norme stabilite nel regolamento interno della Commissione.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Monitoraggio di Eurosur", "anchor": "art_23", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia e gli Stati membri garantiscono che siano applicate procedure per monitorare il funzionamento tecnico e operativo di Eurosur in funzione degli obiettivi da conseguire, ossia adeguate conoscenza situazionale e capacità di reazione alle frontiere esterne.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia monitora continuamente la qualità dei servizi offerti dalla rete di comunicazione di cui all'articolo 14 e la qualità dei dati condivisi nell'ambito situazionale europeo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia trasmette le informazioni raccolte quale parte del monitoraggio di cui al paragrafo 2 ai centri nazionali di coordinamento e alle pertinenti strutture di comando e controllo utilizzate per le operazioni dell'Agenzia nell'ambito dei servizi Eurosur per la fusione dei dati. Tali informazioni sono classificate al livello RESTREINT UE/EU RESTRICTED.</p>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Quadri situazionali", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I quadri situazionali nazionali, il quadro situazionale europeo e i quadri situazionali specifici risultano dalla raccolta e valutazione, dal confronto, dall'analisi e interpretazione, dalla produzione, visualizzazione e divulgazione di informazioni.</p>\n<p class=\"oj-normal\">I quadri situazionali di cui al primo comma comprendono i seguenti livelli di informazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un livello «eventi», contenente gli eventi e gli episodi riguardanti attraversamenti di frontiera non autorizzati e la criminalità transfrontaliera e, ove disponibili, informazioni sui movimenti secondari non autorizzati, al fine di comprendere le tendenze migratorie, i volumi e le rotte di tali movimenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un livello «operazioni», contenente informazioni sulle operazioni, tra cui il piano di impiego, l'area delle operazioni e la posizione, l'ora, lo stato e il tipo di mezzi che partecipano secondo quanto previsto nel piano operativo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un livello «analisi», contenente informazioni analizzate che sono rilevanti ai fini del presente regolamento e, in particolare, sono rilevanti per l'attribuzione dei livelli di impatto alle sezioni di frontiera esterna, quali immagini e geodati, principali evoluzioni e indicatori, relazioni analitiche e altre informazioni di supporto pertinenti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I quadri situazionali di cui al paragrafo 1 consentono di identificare e localizzare eventi, operazioni e analisi corrispondenti riguardanti situazioni in cui sono a rischio vite umane.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione adotta un atto di esecuzione che fissa i dettagli dei livelli di informazione dei quadri situazionali e le norme per l'istituzione dei quadri situazionali specifici. L'atto di esecuzione indica il tipo di informazioni da fornire, i soggetti responsabili della raccolta, del trattamento, dell'archiviazione e della trasmissione di informazioni specifiche, i termini massimi per presentare relazioni, le norme per la sicurezza e la protezione dei dati e i relativi meccanismi di controllo della qualità. Tale atto di esecuzione è adottato secondo la procedura d'esame di cui all'articolo 122, paragrafo 2.</p>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Quadri situazionali nazionali", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni centro nazionale di coordinamento istituisce e aggiorna un quadro situazionale nazionale per fornire informazioni efficaci, esatte e tempestive a tutte le autorità responsabili del controllo delle frontiere esterne.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il quadro situazionale nazionale consta delle informazioni raccolte dalle seguenti fonti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sistema nazionale di sorveglianza di frontiera, ai sensi del diritto nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sensori stazionari e mobili gestiti da autorità nazionali responsabili della sorveglianza delle frontiere esterne;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">pattugliamenti per la sorveglianza di frontiera e altre missioni di monitoraggio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri di coordinamento locali, regionali e di altro tipo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre autorità e altri sistemi nazionali pertinenti, inclusi funzionari di collegamento incaricati dell'immigrazione, centri operativi e punti di contatto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">verifiche di frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri nazionali di coordinamento degli altri Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorità dei paesi terzi, in base agli accordi bilaterali o multilaterali e alle reti regionali di cui all'articolo 72;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sistemi di segnalazione delle navi, secondo le rispettive basi giuridiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre organizzazioni europee e internazionali competenti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre fonti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ogni centro nazionale di coordinamento attribuisce un unico livello di impatto indicativo, «basso», «medio», «alto» o «molto alto», a ogni episodio registrato nel livello «eventi» del quadro situazionale nazionale. Tutti gli episodi sono comunicati all'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ogni centro nazionale di coordinamento può decidere, su richiesta delle autorità nazionali competenti, di restringere l'accesso alle informazioni relative alla sicurezza nazionale, incluse quelle riguardanti mezzi militari in base al principio della necessità di sapere.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I centri nazionali di coordinamento degli Stati membri vicini possono condividere direttamente e quasi in tempo reale il quadro situazionale delle sezioni di frontiera esterna vicine, tra cui le posizioni, lo stato e il tipo di mezzi propri che operano nelle sezioni di frontiera esterna vicine.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Quadro situazionale europeo", "anchor": "art_26", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce e aggiorna un quadro situazionale europeo per fornire ai centri nazionali di coordinamento e alla Commissione informazioni e analisi efficaci, esatte e tempestive sulle frontiere esterne, sulla zona pre-frontaliera e sui movimenti secondari non autorizzati.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il quadro situazionale europeo consta delle informazioni raccolte dalle seguenti fonti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">centri nazionali di coordinamento e quadri situazionali nazionali, informazioni e relazioni ricevute dai funzionari di collegamento incaricati dell'immigrazione nella misura prevista dal presente articolo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'Agenzia, comprese le informazioni e le relazioni ricevute dai suoi funzionari di collegamento ai sensi degli articoli 31 e 77</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">delegazioni dell'Unione e missioni e operazioni nell'ambito della politica di sicurezza e di difesa comune (PSDC) di cui all'articolo 68, paragrafo 1, secondo comma, lettera j);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altri organi, uffici e agenzie dell'Unione e organizzazioni internazionali competenti di cui all'articolo 68, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorità dei paesi terzi, in base agli accordi bilaterali o multilaterali e alle reti regionali di cui all'articolo 72 e agli accordi di lavoro di cui all'articolo 73, paragrafo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre fonti.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il livello «eventi» del quadro situazionale europeo contiene informazioni su:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi e altri eventi contenuti nel livello «eventi» dei quadri situazionali nazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi e altri eventi contenuti nei quadri situazionali specifici di cui all'articolo 27;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">episodi nell'area operativa di un'operazione congiunta, o di un intervento rapido coordinato dall'Agenzia, o in un punto di crisi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il livello «operazioni» del quadro situazionale europeo contiene informazioni sulle operazioni congiunte e gli interventi rapidi coordinati dall'Agenzia e sui punti di crisi, e comprende il mandato della missione, l'ubicazione, la situazione, la durata, informazioni sugli Stati membri e su altri soggetti coinvolti, relazioni sulla situazione quotidiana e settimanale, dati statistici e fascicoli informativi per i media.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le informazioni sui mezzi propri del livello «operazioni» del quadro situazionale europeo possono essere classificate, ove opportuno, RESTREINT UE/EU RESTRICTED.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nell'ambito situazionale europeo l'Agenzia tiene conto dei livelli di impatto che erano stati attribuiti a episodi specifici nei quadri situazionali nazionali dai centri nazionali di coordinamento. Per ogni episodio nella zona pre-frontaliera l'Agenzia attribuisce un unico livello di impatto indicativo e ne informa i centri nazionali di coordinamento.</p>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Quadri situazionali specifici", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia e gli Stati membri possono istituire e aggiornare quadri situazionali specifici per sostenere attività operative specifiche alle frontiere esterne o per condividere informazioni con le istituzioni, gli organi, gli uffici e le agenzie dell'Unione e le organizzazioni internazionali di cui all'articolo 68, paragrafo 1, o con paesi terzi come previsto all'articolo 75.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I quadri situazionali specifici constano di un sottoinsieme di informazioni dei quadri situazionali nazionali e del quadro situazionale europeo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le norme dettagliate per istituire e condividere i quadri situazionali specifici sono fissate in un piano operativo per le attività operative interessate e negli accordi bilaterali o multilaterali quando il quadro situazionale specifico è istituito nell'ambito di una cooperazione bilaterale o multilaterale con paesi terzi. Qualsiasi scambio di informazioni ai sensi del presente paragrafo è effettuato conformemente al principio del consenso dell'originatore.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Servizi Eurosur per la fusione dei dati", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia coordina i servizi Eurosur per la fusione dei dati, al fine di fornire ai centri nazionali di coordinamento, alla Commissione e a sé medesima informazioni sulle frontiere esterne e sulla zona pre-frontaliera su base regolare e in modo affidabile ed economicamente efficiente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su domanda di un centro nazionale di coordinamento, l'Agenzia gli fornisce informazioni sulle frontiere esterne dello Stato membro a cui appartiene tale centro e sulla zona pre-frontaliera, che possono essere ottenute tramite:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio selettivo di porti e coste del paese terzo designato che, tramite analisi dei rischi e informazioni, risultino essere punti di imbarco o di transito di imbarcazioni o altri mezzi utilizzati per l'immigrazione illegale o la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">localizzazione in alto mare di imbarcazioni o altro mezzo e di aeromobili utilizzati, o che si sospetta siano utilizzati, per l'immigrazione illegale o la criminalità transfrontaliera, anche nel caso di persone in pericolo in mare, allo scopo di trasmettere tali informazioni alle pertinenti autorità competenti ai fini delle operazioni di ricerca e soccorso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio di aree designate nel settore marittimo al fine di individuare, identificare e localizzare imbarcazioni e altri mezzi utilizzati, o che si sospetta siano utilizzati, per l'immigrazione illegale o la criminalità transfrontaliera, anche nel caso di persone in pericolo in mare, allo scopo di trasmettere tali informazioni alle pertinenti autorità competenti ai fini delle operazioni di ricerca e soccorso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio di aree designate alle frontiere aeree al fine di individuare, identificare e localizzare aeromobili e altre forme di equipaggiamento utilizzati, o che si sospetta siano utilizzati, per l'immigrazione illegale o la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutazione ambientale di aree designate nel settore marittimo e alle frontiere esterne terrestri e aeree, allo scopo di ottimizzare le attività di monitoraggio e pattugliamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio selettivo di zone pre-frontaliere designate lungo le frontiere esterne che, tramite analisi dei rischi e informazioni, risultino essere potenziali aree di partenza o di transito dell'immigrazione illegale o della criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio dei flussi migratori verso l'Unione e al suo interno in termini di tendenze, volumi e rotte;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio dei media, intelligence da fonte aperta e analisi di attività su Internet, in linea con la direttiva (UE) 2016/680 o il regolamento (UE) 2016/679, a seconda dei casi, al fine di prevenire l'immigrazione illegale o la criminalità transfrontaliera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">analisi delle informazioni ottenute da sistemi d'informazione su larga scala per individuare cambiamenti nelle rotte e nei metodi utilizzati ai fini dell'immigrazione illegale e della criminalità transfrontaliera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia può respingere una richiesta presentata da un centro nazionale di coordinamento per motivi tecnici, finanziari od operativi. L'Agenzia notifica al centro nazionale di coordinamento, a tempo debito, i motivi di tale diniego.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia può utilizzare di propria iniziativa gli strumenti di sorveglianza di cui al paragrafo 2 per raccogliere informazioni sulla zona pre-frontaliera utili per il quadro situazionale europeo.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Analisi dei rischi", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia monitora i flussi migratori verso e all'interno dell'Unione, in termini di tendenze, di volumi e rotte, così come altre tendenze o possibili sfide alle frontiere esterne e per quanto riguarda il rimpatrio. A tale scopo, l'Agenzia, con decisione del consiglio di amministrazione su proposta del direttore esecutivo, elabora un modello comune di analisi integrata dei rischi, che è applicato dall'Agenzia stessa e dagli Stati membri. Il modello comune di analisi integrata dei rischi è definito e se necessario aggiornato in base all'esito della valutazione dell'attuazione del ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere di cui all'articolo 8, paragrafo 7.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia elabora analisi del rischio annuali, di carattere generale, e le sottopone al Parlamento europeo, al Consiglio e alla Commissione ai sensi delle norme di sicurezza disciplinate dall'articolo 92, nonché analisi del rischio mirate per attività operative. Ogni due anni l'Agenzia, in stretta consultazione con gli Stati membri, elabora e sottopone al Parlamento europeo, al Consiglio e alla Commissione un'analisi strategica dei rischi per la gestione europea integrata delle frontiere. Tali analisi strategiche del rischio sono prese in considerazione nella preparazione del ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere. L'Agenzia elabora tali analisi generali annuali dei rischi e analisi strategiche dei rischi sulla base delle informazioni ricevute, anche dagli Stati membri. I dati personali sono resi anonimi nei risultati di tali analisi dei rischi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le analisi dei rischi di cui al paragrafo 2 comprendono tutti gli aspetti pertinenti alla gestione europea integrata delle frontiere allo scopo di sviluppare un meccanismo di pre-allarme.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia pubblica informazioni complete sul modello comune di analisi integrata dei rischi.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri forniscono all'Agenzia tutte le informazioni necessarie sulla situazione, sulle tendenze e sulle possibili minacce alle frontiere esterne e nel settore del rimpatrio. Gli Stati membri trasmettono all'Agenzia, periodicamente o su sua richiesta, tutte le informazioni pertinenti quali dati statistici e operativi raccolti in relazione alla gestione europea integrata delle frontiere che sono incluse nell'elenco delle informazioni e dei dati obbligatori da scambiare con l'Agenzia, ai sensi dell'articolo 100, paragrafo 2, lettera e), nonché informazioni derivanti dal livello «analisi» del quadro situazionale nazionale come previsto all'articolo 25.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   I risultati dell'analisi dei rischi sono presentati al consiglio di amministrazione e condivisi con le autorità competenti degli Stati membri in modo tempestivo e accurato.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Gli Stati membri tengono conto dei risultati dell'analisi dei rischi nel pianificare le loro operazioni e attività alle frontiere esterne e le loro attività nel settore del rimpatrio.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia tiene conto dei risultati del modello comune di analisi integrata dei rischi nell'elaborare un programma comune di base per la formazione di cui all'articolo 62.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Determinazione delle sezioni di frontiera esterna", "anchor": "art_30", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento, ogni Stato membro suddivide le sue frontiere esterne in sezioni di frontiera esterne. Tali sezioni consistono di frontiere terrestri, marittime e, se del caso, uno Stato membro decide in tal senso, aeree. Ogni Stato membro notifica tali sezioni di frontiera esterne all'Agenzia.</p>"], [null, "<p class=\"oj-normal\">Gli Stati membri notificano ogni cambiamento delle sezioni di frontiera esterne tempestivamente all'Agenzia al fine di garantire la continuità dell'analisi dei rischi da parte dell'Agenzia.</p>"]]}, "31": {"label": "Articolo 31", "heading": "Funzionari di collegamento dell'Agenzia negli Stati membri", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia svolge un monitoraggio regolare della gestione delle frontiere esterne e dei rimpatri da parte di tutti gli Stati membri tramite i suoi funzionari di collegamento.</p>\n<p class=\"oj-normal\">L'Agenzia può stabilire che un funzionario di collegamento si occupi di massimo quattro Stati membri geograficamente limitrofi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo nomina esperti appartenenti al personale statutario da impiegare quali funzionari di collegamento. Sulla base dell'analisi dei rischi e in consultazione con gli Stati membri interessati, il direttore esecutivo formula una proposta sulla natura e le condizioni dell'impiego, lo Stato membro o la regione presso i quali può essere impiegato il funzionario di collegamento e gli eventuali compiti non contemplati dal paragrafo 3. La proposta del direttore esecutivo è soggetta ad approvazione del consiglio di amministrazione. Il direttore esecutivo comunica la nomina allo Stato membro interessato e stabilisce, insieme a tale Stato membro, la sede dell'impiego.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I funzionari di collegamento agiscono a nome dell'Agenzia e hanno il ruolo di favorire la cooperazione e il dialogo tra l'Agenzia e le autorità nazionali responsabili della gestione delle, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, nonché le autorità nazionali responsabili dei rimpatri. In particolare, i funzionari di collegamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fungono da interfaccia tra l'Agenzia e le autorità nazionali responsabili della gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, nonché le autorità nazionali responsabili dei rimpatri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">favoriscono la raccolta di informazioni richieste dall'Agenzia ai fini del monitoraggio della migrazione illegale e delle analisi dei rischi di cui all'articolo 29;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">favoriscono la raccolta di informazioni di cui all'articolo 32 e richieste dall'Agenzia per svolgere la valutazione delle vulnerabilità ed elaborano una relazione a tal fine;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitorano le misure adottate dagli Stati membri alle sezioni di frontiera esterne a cui è stato attribuito un livello di impatto alto o critico ai sensi dell'articolo 34;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono a promuovere l'applicazione dell'<span class=\"oj-italic\">acquis</span> dell'Unione relativo alla gestione delle frontiere esterne e al rimpatrio, anche con riferimento al rispetto dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperano con il responsabile dei diritti fondamentali, ove necessario, al fine di promuovere del rispetto dei diritti fondamentali nell'attività dell'Agenzia, ai sensi della lettera e);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ove possibile assistono gli Stati membri nella preparazione dei loro piani di emergenza relativi alla gestione delle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitano la comunicazione tra lo Stato membro interessato e l'Agenzia, condividono le informazioni rilevanti in possesso dell'Agenzia con lo Stato membro interessato, comprese le informazioni sulle operazioni in corso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferiscono regolarmente e direttamente al direttore esecutivo in merito alla situazione alle frontiere esterne e alla capacità dello Stato membro interessato di gestire efficacemente la situazione alle frontiere esterne; riferiscono inoltre in merito all'esecuzione delle operazioni di rimpatrio verso i pertinenti paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controllano le misure adottate dallo Stato membro riguardo a una situazione che richieda un'azione urgente alle frontiere esterne di cui all'articolo 42;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">controllano le misure adottate dallo Stato membro riguardo ai rimpatri e favoriscono la raccolta di informazioni richieste dall'Agenzia per svolgere le attività di cui all'articolo 48.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Qualora le informazioni riferite dal funzionario di collegamento ai sensi del paragrafo 3, lettera i), sollevino preoccupazioni riguardo a uno o più dei suddetti aspetti d'interesse per lo Stato membro in questione, quest'ultimo è informato senza indugio dal direttore esecutivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Ai fini del paragrafo 3, il funzionario di collegamento, ai sensi delle norme nazionali e dell'Unione in materia di sicurezza e protezione dei dati:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riceve informazioni dal centro nazionale di coordinamento interessato e dal pertinente quadro situazionale nazionale stabilito ai sensi dell'articolo 25;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tiene contatti regolari con le autorità nazionali responsabili della gestione delle frontiere, comprese le guardie costiere nella misura in cui svolgono compiti di controllo di frontiera, nonché le autorità nazionali responsabili dei rimpatri, informando al contempo il punto di contatto nazionale interessato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   La relazione del funzionario di collegamento di cui al presente articolo, paragrafo 3, lettera c), fa parte della valutazione delle vulnerabilità di cui all'articolo 32. La relazione è trasmessa allo Stato membro interessato.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Nell'assolvere ai loro compiti, i funzionari di collegamento ricevono istruzioni soltanto dall'Agenzia.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Valutazione delle vulnerabilità", "anchor": "art_32", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia definisce una metodologia comune per la valutazione delle vulnerabilità, con decisione del consiglio di amministrazione sulla base di una proposta del direttore esecutivo elaborata in stretta collaborazione con gli Stati membri e la Commissione. Tale metodologia specifica i criteri oggettivi in base ai quali l'Agenzia effettua la valutazione delle vulnerabilità, la frequenza di tali valutazioni, le modalità con cui effettuare valutazioni delle vulnerabilità successive e le modalità di un sistema efficace per monitorare l'attuazione delle raccomandazioni del direttore esecutivo di cui al paragrafo 7.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia monitora e valuta la disponibilità di attrezzature tecniche, di sistemi, di capacità, di risorse, di infrastrutture e di personale degli Stati membri adeguatamente qualificato e formato, necessari ai fini del controllo di frontiera ai sensi dell'articolo 3, paragrafo 1, lettera a). In tale contesto l'Agenzia valuta i piani nazionali di sviluppo delle capacità di cui all'articolo 9, paragrafo 4, in relazione alla capacità di svolgere il controllo di frontiera tenendo conto del fatto che alcune capacità nazionali potrebbero essere in parte utilizzate per fini diversi dal controllo di frontiera Per quanto riguarda la pianificazione futura, l'Agenzia effettua tale controllo e valutazione come misura preventiva sulla base di un'analisi dei rischi predisposta a norma dell'articolo 29, paragrafo 2. L'Agenzia effettua tali monitoraggio e valutazione almeno una volta all'anno, a meno che il direttore esecutivo non decida altrimenti sulla scorta delle valutazioni del rischio o di una precedente valutazione della vulnerabilità. In ogni caso, ciascuno Stato membro è soggetto al monitoraggio e alla valutazione almeno una volta ogni tre anni.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo l'articolo 9, gli Stati membri, su richiesta dell'Agenzia, forniscono informazioni circa l'attrezzatura tecnica, il personale e, nella misura del possibile, le risorse finanziarie disponibili a livello nazionale per svolgere il controllo di frontiera. Su richiesta dell'Agenzia gli Stati membri forniscono anche informazioni sui loro piani di emergenza per la gestione delle frontiere.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Scopo della valutazione delle vulnerabilità è permettere all'Agenzia: di valutare la capacità e la preparazione degli Stati membri ad affrontare le sfide presenti e future alle frontiere esterne, di identificare, specialmente per quegli Stati membri che devono fronteggiare sfide specifiche e sproporzionate, eventuali ripercussioni immediate alle frontiere esterne e conseguenze successive sul funzionamento dello spazio Schengen, di valutare la capacità di tali Stati membri di contribuire al corpo permanente e al parco attrezzature tecniche, compresa la riserva di reazione rapida, e di valutare la capacità dello Stato membro ospitante in relazione al sostegno fornito dalla guardia di frontiera e costiera europea in linea con l'articolo 9, paragrafo 3. Tale valutazione non pregiudica il meccanismo di valutazione Schengen.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nell'ambito della valutazione delle vulnerabilità, l'Agenzia valuta, in termini qualitativi e quantitativi, la capacità degli Stati membri di espletare tutti i compiti di gestione delle frontiere, tra cui la capacità di far fronte al potenziale arrivo di un elevato numero di persone sul proprio territorio.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   I risultati preliminari della valutazione delle vulnerabilità sono sottoposti agli Stati membri interessati. Questi ultimi possono formulare osservazioni su tale valutazione.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Ove necessario, il direttore esecutivo, in consultazione con lo Stato membro interessato, formula una raccomandazione che stabilisce le misure necessarie da adottarsi da parte dello Stato membro interessato e il termine entro il quale tali misure devono essere attuate. Il direttore esecutivo invita lo Stato membro interessato ad adottare le misure necessarie sulla base di un piano d'azione elaborato dallo Stato membro in consultazione con il direttore esecutivo.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Nell'elaborare le misure da raccomandare agli Stati membri interessati, il direttore esecutivo si basa sui risultati della valutazione delle vulnerabilità tenendo conto dell'analisi dei rischi svolta dall'Agenzia, delle osservazioni formulate dagli Stati membri interessati e dei risultati del meccanismo di valutazione Schengen.</p>\n<p class=\"oj-normal\">Le misure raccomandate hanno l'obiettivo di eliminare le vulnerabilità individuate nella valutazione in modo che gli Stati membri rafforzino la loro preparazione ad affrontare le sfide presenti e future alle frontiere esterne, potenziando o migliorando le loro capacità, l'attrezzatura tecnica, i sistemi, le risorse e i piani di emergenza. Il direttore esecutivo può mettere a disposizione degli Stati membri le competenze tecniche dell'Agenzia per sostenere l'attuazione delle misure raccomandate.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Il direttore esecutivo monitora l'attuazione delle misure raccomandate per mezzo delle relazioni periodiche presentate dagli Stati membri sulla base dei piani d'azione di cui al paragrafo 7.</p>\n<p class=\"oj-normal\">Qualora sussista il rischio che uno Stato membro non attui una misura raccomandata entro il termine stabilito di cui al paragrafo 7, il direttore esecutivo lo comunica immediatamente al membro del consiglio di amministrazione proveniente dallo Stato membro interessato e alla Commissione. In consultazione con il membro del consiglio di amministrazione proveniente dallo Stato membro interessato, il direttore esecutivo si informa presso le autorità competenti di tale Stato membro dei motivi del ritardo e offre il sostegno dell'Agenzia per facilitare l'attuazione della misura raccomandata.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Qualora uno Stato membro non attui le misure necessarie stabilite nella raccomandazione entro il termine stabilito in conformità del paragrafo 7 del presente articolo, il direttore esecutivo riferisce la questione al consiglio di amministrazione e ne informa la Commissione. Il consiglio di amministrazione, su proposta del direttore esecutivo, adotta una decisione che stabilisce le misure necessarie che lo Stato membro interessato deve adottare e il termine entro il quale tali misure devono essere attuate. La decisione del consiglio di amministrazione è vincolante per lo Stato membro. Se lo Stato membro non attua le misure entro il termine previsto in tale decisione, il consiglio di amministrazione ne informa il Consiglio e la Commissione, e ulteriori iniziative possono essere adottate ai sensi dell'articolo 42.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   A norma dell'articolo 92, la valutazione delle vulnerabilità, compresa una descrizione dettagliata dell'esito della valutazione delle vulnerabilità, delle misure adottate dagli Stati membri a seguito di tale valutazione e dello stato di attuazione di eventuali misure precedentemente oggetto di raccomandazioni, è trasmessa periodicamente e con cadenza almeno annuale al Parlamento europeo, al Consiglio e alla Commissione.</p>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Sinergie tra la valutazione delle vulnerabilità e il meccanismo di valutazione Schengen", "anchor": "art_33", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le sinergie tra la valutazione delle vulnerabilità e il meccanismo di valutazione Schengen sono massimizzate al fine di creare un miglior quadro situazionale del funzionamento dello spazio Schengen, evitando, per quanto possibile, la duplicazione degli sforzi da parte degli Stati membri e garantendo un utilizzo più coordinato degli strumenti finanziari pertinenti dell'Unione a sostegno della gestione delle frontiere esterne.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ai fini di cui al paragrafo 1, la Commissione e l'Agenzia stabiliscono le disposizioni necessarie per scambiarsi in modo regolare, sicuro e tempestivo tutte le informazioni relative ai risultati delle valutazioni delle vulnerabilità e ai risultati delle valutazioni effettuate nell'ambito del meccanismo di valutazione Schengen nel settore della gestione delle frontiere. Tali disposizioni di scambio delle informazioni riguardano le relazioni sulle valutazioni delle vulnerabilità e le relazioni sulle visite di valutazione Schengen, le successive raccomandazioni, i piani d'azione e ogni aggiornamento dell'attuazione dei piani d'azione comunicato dagli Stati membri.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ai fini del meccanismo di valutazione Schengen in relazione alla gestione delle frontiere esterne, la Commissione condivide i risultati delle valutazioni delle vulnerabilità con tutti i membri delle squadre di valutazione Schengen che partecipano alla valutazione dello Stato membro interessato. Tali informazioni sono considerate sensibili ai sensi del regolamento (UE) n. 1053/2013 e sono trattate di conseguenza.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le disposizioni di cui al paragrafo 2 riguardano i risultati delle valutazioni effettuate nell'ambito del meccanismo di valutazione Schengen nel settore del rimpatrio al fine di garantire che l'Agenzia abbia piena conoscenza delle carenze riscontrate e possa proporre misure appropriate per sostenere lo Stato membro interessato al riguardo.</p>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Assegnazione di livelli di impatto alle sezioni di frontiera esterna", "anchor": "art_34", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Sulla base delle proprie analisi dei rischi e della propria valutazione delle vulnerabilità e di concerto con lo Stato membro interessato, l'Agenzia assegna i seguenti livelli di impatto a ciascuna delle sezioni di frontiera esterna o li modifica:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello di impatto basso, qualora gli episodi connessi alla immigrazione illegale o alla criminalità transfrontaliera che si verificano nella pertinente sezione di frontiera abbiano un impatto irrilevante sulla sicurezza della frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello di impatto medio, qualora gli episodi connessi alla immigrazione illegale o alla criminalità transfrontaliera che si verificano nella pertinente sezione di frontiera abbiano un impatto moderato sulla sicurezza della frontiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">livello di impatto alto, qualora gli episodi connessi all'immigrazione illegale o alla criminalità transfrontaliera che si verificano nella pertinente sezione di frontiera abbiano un impatto significativo sulla sicurezza della frontiera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Al fine di affrontare prontamente le situazioni di crisi a una data sezione di frontiera esterna, nella quale, secondo l'analisi dei rischi dell'Agenzia, gli episodi verificatisi connessi all'immigrazione illegale o alla criminalità transfrontaliera hanno un impatto decisivo sulla sicurezza della frontiera tale da rischiare di compromettere il funzionamento dello spazio Schengen, l'Agenzia d'intesa con lo Stato membro interessato, attribuisce temporaneamente un livello di impatto «critico» a tale sezione di frontiera esterna.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In mancanza di accordo tra lo Stato membro interessato e l'Agenzia sull'attribuzione di un livello d'impatto a una sezione di frontiera esterna, il livello d'impatto precedentemente attribuito a tale sezione di frontiera rimane invariato.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il centro nazionale di coordinamento valuta costantemente, in stretta collaborazione con altre autorità nazionali competenti, se sia necessario modificare il livello di impatto di una sezione di frontiera esterna tenendo conto delle informazioni contenute nell'ambito situazionale nazionale e ne informa di conseguenza l'Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia indica i livelli di impatto assegnati alle sezioni di frontiera esterna nell'ambito situazionale europeo.</p>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Reazione corrispondente ai livelli di impatto", "anchor": "art_35", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri si assicurano che il controllo di frontiera svolto alle sezioni di frontiera esterna corrisponda ai livelli di impatto attribuiti, nei modi seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se a una sezione di frontiera esterna è attribuito un livello di impatto basso, le autorità nazionali responsabili del controllo delle frontiere esterne organizzano un controllo alle frontiere regolare sulla base delle analisi dei rischi e provvedono affinché in tale sezione di frontiera restino disponibili personale e risorse sufficienti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se a una sezione di frontiera esterna è attribuito un livello di impatto medio, le autorità nazionali responsabili del controllo delle frontiere esterne provvedono affinché siano adottate, per detta sezione di frontiera, misure di controllo alle frontiere adeguate oltre alle misure di cui alla lettera a) del presente paragrafo. L'adozione di tali misure di controllo alle frontiere è notificata al centro nazionale di coordinamento. Il centro nazionale di coordinamento coordina ogni sostegno dato ai sensi dell'articolo 21, paragrafo 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se a una sezione di frontiera esterna è attribuito un livello di impatto alto, lo Stato membro interessato provvede, mediante il centro nazionale di coordinamento, affinché le autorità nazionali che operano presso tale sezione di frontiera ricevano il sostegno necessario e siano adottate misure di controllo alle frontiere rafforzate oltre alle misure di cui alla lettera b) del presente paragrafo. Detto Stato membro può chiedere sostegno all'Agenzia alle condizioni previste dall'articolo 36 per l'avvio di operazioni congiunte o interventi rapidi alle frontiere;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">se a una sezione di frontiera esterna è attribuito un livello di impatto critico, l'Agenzia lo notifica alla Commissione. Il direttore esecutivo, in aggiunta alle misure di cui alla lettera c) del presente paragrafo, formula una raccomandazione ai sensi dell'articolo 41, paragrafo 1, tenendo conto del costante sostegno dell'Agenzia. Lo Stato membro interessato risponde alla raccomandazione ai sensi dell'articolo 41, paragrafo 2.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il centro nazionale di coordinamento informa regolarmente l'Agenzia delle misure adottate a livello nazionale a norma del paragrafo 1, lettere c) e d).</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Se a una sezione di frontiera esterna, adiacente a una sezione di frontiera di un altro Stato membro o di un paese terzo con cui esistono accordi, intese o reti regionali di cui agli articoli 72 e 73, è attribuito un livello di impatto medio, alto o critico, il centro nazionale di coordinamento contatta il centro nazionale di coordinamento dello Stato membro vicino o l'autorità competente del paese terzo vicino e si adopera per coordinare con l'Agenzia le necessarie misure transfrontaliere.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia valuta, insieme allo Stato membro interessato, l'attribuzione dei livelli di impatto e le misure corrispondenti adottate a livello nazionale e dell'Unione. Tale valutazione contribuisce alla valutazione delle vulnerabilità effettuata dall'Agenzia a norma dell'articolo 32.</p>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Azioni dell'Agenzia alle frontiere esterne", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Uno Stato membro può chiedere all'Agenzia assistenza nell'adempimento dei propri obblighi riguardo al controllo delle frontiere esterne. L'Agenzia attua anche misure ai sensi degli articoli 41 e 42.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia organizza la necessaria assistenza tecnica e operativa per lo Stato membro ospitante e può adottare, ai sensi del pertinente diritto dell'Unione e internazionale, compreso il principio di non respingimento, una o più delle seguenti misure:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinare operazioni congiunte per uno o più Stati membri e impiegare il corpo permanente e l'attrezzatura tecnica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzare interventi rapidi alle frontiere e impiegare il corpo permanente e l'attrezzatura tecnica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinare attività per uno o più Stati membri e paesi terzi alle frontiere esterne, comprese operazioni congiunte con paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiegare il corpo permanente nell'ambito delle squadre di sostegno per la gestione della migrazione, tra l'altro, nei punti di crisi al fine di fornire assistenza tecnica e operativa agli Stati membri, anche, se del caso, nelle attività di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nell'ambito delle operazioni di cui alle lettere a), b) e c) del presente paragrafo e a norma del regolamento (UE) n. 656/2014 e del diritto internazionale, fornire assistenza tecnica e operativa agli Stati membri e ai paesi terzi, a sostegno delle operazioni di ricerca e soccorso per le persone in pericolo in mare, che possono svolgersi nel corso di operazioni di sorveglianza delle frontiere in mare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riservare un trattamento prioritario ai servizi Eurosur per la fusione dei dati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia finanzia o cofinanzia le attività di cui al paragrafo 2 con il proprio bilancio, conformemente alle regole finanziarie applicabili all'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   In caso di sostanziale fabbisogno finanziario supplementare ascrivibile a una particolare situazione alle frontiere esterne, l'Agenzia ne informa tempestivamente il Parlamento europeo, il Consiglio e la Commissione.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Avvio di operazioni congiunte e interventi rapidi alle frontiere esterne", "anchor": "art_37", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Uno Stato membro può chiedere all'Agenzia di avviare operazioni congiunte per far fronte a sfide imminenti, comprese l'immigrazione illegale, minacce presenti o future alle frontiere esterne o la criminalità transfrontaliera, o di fornirgli maggiore assistenza tecnica e operativa, per l'adempimento dei suoi obblighi in materia di controllo delle frontiere esterne. Nell'ambito di tale richiesta, uno Stato membro può anche indicare i profili del personale operativo necessario per l'operazione congiunta in questione, compreso il personale che possiede poteri esecutivi, a seconda dei casi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su richiesta di uno Stato membro che si trovi a far fronte a sfide specifiche e sproporzionate, specie in caso di afflusso massiccio in determinati punti delle frontiere esterne di cittadini di paesi terzi che tentano di entrare nel territorio di tale Stato membro senza autorizzazione, l'Agenzia può effettuare un intervento rapido alle frontiere per un periodo limitato nel territorio di tale Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo valuta, approva e coordina le proposte degli Stati membri per operazioni congiunte o interventi rapidi alle frontiere. Le operazioni congiunte e gli interventi rapidi alle frontiere sono preceduti da un'analisi dei rischi completa, affidabile e aggiornata che consenta all'Agenzia di stabilire un ordine di priorità per le operazioni congiunte e gli interventi rapidi alle frontiere proposti, tenendo conto del livello di impatto attribuito alle sezioni di frontiera esterna ai sensi dell'articolo 34 e della disponibilità di risorse.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli obiettivi di un'operazione congiunta o di un intervento rapido alle frontiere possono essere conseguiti nell'ambito di un'operazione multifunzionale. Tali operazioni possono comprendere funzioni di guardia costiera e la prevenzione della criminalità transfrontaliera, concentrandosi sulla lotta al traffico di migranti o alla tratta di esseri umani e sulla gestione della migrazione, in particolare l'identificazione, la registrazione, la raccolta di informazioni (<span class=\"oj-italic\">debriefing</span>) e il rimpatrio.</p>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Piani operativi per le operazioni congiunte", "anchor": "art_38", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   In preparazione di un'operazione congiunta, il direttore esecutivo, in cooperazione con lo Stato membro ospitante, redige un elenco dell'attrezzatura tecnica, del personale e dei profili necessari, inclusi quelli che possiedono poteri esecutivi, se del caso, che devono essere autorizzati ai sensi dell'articolo 82, paragrafo 2. Tale elenco è redatto tenendo conto delle risorse di cui dispone lo Stato membro ospitante e della sua richiesta ai sensi dell'articolo 37. Sulla base di tali elementi, l'Agenzia definisce una serie di misure di rinforzo tecnico e operativo e di attività di sviluppo delle capacità, da includere nel piano operativo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo predispone un piano operativo per le operazioni congiunte alle frontiere esterne. Il direttore esecutivo e lo Stato membro ospitante, in stretta e tempestiva consultazione con gli Stati membri partecipanti, concordano il piano operativo che definisce nel dettaglio gli aspetti organizzativi e procedurali dell'operazione congiunta.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il piano operativo è vincolante per l'Agenzia, lo Stato membro ospitante e gli Stati membri partecipanti. Esso copre tutti gli aspetti considerati necessari per la realizzazione dell'operazione congiunta, fra cui i seguenti elementi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione della situazione con modus operandi e obiettivi dell'operazione, scopo operativo compreso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il lasso di tempo stimato dell'operazione congiunta necessario per il conseguimento dei suoi obiettivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'area geografica in cui si svolgerà l'operazione congiunta;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una descrizione dei compiti, inclusi quelli che richiedono poteri esecutivi, delle responsabilità, anche per quanto riguarda il rispetto dei diritti fondamentali e degli obblighi di protezione dei dati, e istruzioni specifiche per le squadre, anche in merito all'autorizzazione a consultare banche dati e portare armi d'ordinanza, munizioni ed equipaggiamento nello Stato membro ospitante;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la composizione delle squadre e l'impiego di altro personale pertinente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">disposizioni in ordine al comando e al controllo, compresi il nome e il grado delle guardie di frontiera dello Stato membro ospitante responsabili della cooperazione con i membri delle squadre e con l'Agenzia, in particolare il nome e il grado delle guardie di frontiera che hanno il comando durante l'operazione, e la posizione nella catena di comando dei membri delle squadre;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le attrezzature tecniche da utilizzare durante l'operazione congiunta, comprensive di requisiti specifici come le condizioni d'uso, l'equipaggio richiesto, il trasporto e altri aspetti logistici, e le disposizioni finanziarie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">disposizioni dettagliate riguardo alla comunicazione immediata di episodi al consiglio di amministrazione e alle competenti autorità nazionali da parte dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uno schema di relazioni e valutazioni contenente i parametri per la relazione di valutazione, anche per quanto riguarda la protezione dei diritti fondamentali, e il termine ultimo per presentare la relazione di valutazione finale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per le operazioni in mare, informazioni specifiche riguardanti la giurisdizione pertinente e il diritto applicabile nell'area geografica in cui si svolge l'operazione congiunta, compresi i riferimenti al diritto nazionale, internazionale e dell'Unione in materia di intercettazione, soccorso in mare e sbarco. A tale riguardo, il piano operativo è redatto ai sensi del regolamento (UE) n. 656/2014;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le modalità di cooperazione con i paesi terzi, gli altri organi, uffici e agenzie dell'Unione, o con le organizzazioni internazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istruzioni generali su come garantire la salvaguardia dei diritti fondamentali durante l'attività operativa dell'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">procedure grazie alle quali persone che necessitano di protezione internazionale, vittime della tratta di esseri umani, minori non accompagnati e persone in situazioni vulnerabili siano indirizzate alle autorità nazionali competenti per ricevere l'assistenza adeguata;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">procedure per la creazione di un meccanismo inteso a ricevere e trasmettere all'Agenzia denunce contro chiunque partecipi a un'attività operativa dell'Agenzia, ivi compresi guardie di frontiera o altro personale competente dello Stato membro ospitante e membri delle squadre, relative a presunte violazioni dei diritti fondamentali nel contesto della loro partecipazione a un'attività operativa dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">disposizioni logistiche, comprese informazioni sulle condizioni di lavoro e sull'ambiente nelle zone in cui è ha luogo l'operazione congiunta.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Eventuali modifiche o adattamenti del piano operativo necessitano del consenso del direttore esecutivo e dello Stato membro ospitante, previa consultazione degli Stati membri partecipanti. L'Agenzia trasmette immediatamente copia del piano operativo modificato o adattato agli Stati membri partecipanti.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il presente articolo si applica <span class=\"oj-italic\">mutatis mutandis</span> a tutte le operazioni dell'Agenzia.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Procedura di avvio di un intervento rapido alle frontiere", "anchor": "art_39", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La richiesta di avvio di un intervento rapido alle frontiere presentata da uno Stato membro comprende una descrizione della situazione, i possibili obiettivi e le esigenze previste nonché i profili necessari, inclusi quelli che possiedono poteri esecutivi, se del caso. Se necessario, il direttore esecutivo può inviare immediatamente esperti dell'Agenzia per valutare la situazione alle frontiere esterne dello Stato membro interessato.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo informa immediatamente il consiglio di amministrazione della richiesta di avvio di un intervento rapido alle frontiere presentata da uno Stato membro.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel decidere in merito alla richiesta presentata da uno Stato membro, il direttore esecutivo tiene conto dei risultati delle analisi dei rischi svolte dall'Agenzia e del livello «analisi» del quadro situazionale europeo, nonché dei risultati della valutazione delle vulnerabilità di cui all'articolo 32 e di ogni altra informazione pertinente fornita dallo Stato membro interessato o da un altro Stato membro.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo valuta immediatamente le possibilità di reimpiegare i membri delle squadre del corpo permanente, in particolare il personale statutario e il personale distaccato all'Agenzia dagli Stati membri, che sono disponibili e si trovano in altre aree operative. Il direttore esecutivo valuta inoltre le ulteriori esigenze di impiegare personale operativo ai sensi dell'articolo 57 e, una volta esauriti tali profili richiesti, di attivare la riserva di reazione rapida ai sensi dell'articolo 58.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo adotta una decisione sulla richiesta di avvio di un intervento rapido alle frontiere entro due giorni lavorativi dalla data di ricevimento della richiesta. Contemporaneamente notifica per iscritto la decisione allo Stato membro interessato e al consiglio di amministrazione. Nella decisione sono precisate le motivazioni principali della stessa.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nell'adottare la decisione di cui al paragrafo 5 del presente articolo, il direttore esecutivo informa gli Stati membri in merito alla possibilità di richiedere personale operativo aggiuntivo ai sensi dell'articolo 57 e, ove applicabile, all'articolo 58, indicando il numero congruo e i profili del personale che ogni Stato membro deve fornire.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Se decide di avviare un intervento rapido alle frontiere, il direttore esecutivo invia le squadre per la gestione delle frontiere disponibili formate a partire dal corpo permanente e l'attrezzatura attinta dal parco attrezzature tecniche ai sensi dell'articolo 64 e, se necessario, decide di fornire un rinforzo immediato mediante una o più squadre per la gestione delle frontiere ai sensi dell'articolo 57.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il direttore esecutivo, insieme allo Stato membro ospitante, predispone e concorda immediatamente, e comunque non oltre tre giorni lavorativi dalla data della decisione, un piano operativo ai sensi dell'articolo 38, paragrafo 2.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Non appena il piano operativo è stato concordato e trasmesso agli Stati membri, il direttore esecutivo invia immediatamente il personale operativo disponibile tramite reimpiego da altre aree operative o altre funzioni.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Parallelamente all'invio di forze di cui al paragrafo 9 e, se necessario, per garantire il rinforzo immediato delle squadre per la gestione delle frontiere reimpiegate da altre aree o funzioni, il direttore esecutivo richiede a ciascuno Stato membro il numero e i profili di personale aggiuntivo da impiegare in via aggiuntiva attinto dagli elenchi nazionali per gli impieghi a breve durata di cui all'articolo 57.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Qualora si verifichi una situazione in cui squadre per la gestione delle frontiere di cui ai paragrafi 7 e il personale di cui al paragrafo 10 sono insufficienti, il direttore esecutivo può attivare la riserva di reazione rapida chiedendo a ciascuno Stato membro il numero e i profili di personale aggiuntivo da impiegare ai sensi dell'articolo 58.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   Le informazioni di cui ai paragrafi 10 e 11 sono fornite per iscritto ai punti di contatto nazionali, con l'indicazione della data in cui deve avere luogo l'impiego del personale di ciascuna categoria. Ai punti di contatto nazionali viene trasmessa anche una copia del piano operativo.</p>\n</div>"], [13, "<div>\n<p class=\"oj-normal\">13.   Gli Stati membri provvedono affinché il numero e i profili del personale siano immediatamente messi a disposizione dell'Agenzia onde garantire un impiego completo ai sensi dell'articolo 57 e, se del caso, dell'articolo 58.</p>\n</div>"], [14, "<div>\n<p class=\"oj-normal\">14.   Le prime squadre per la gestione delle frontiere sono reimpiegate da altre aree e altre funzioni entro cinque giorni lavorativi dalla data di approvazione del piano operativo da parte del direttore esecutivo e dello Stato membro ospitante. L'impiego aggiuntivo di squadre per la gestione delle frontiere avviene, se necessario, entro 12 giorni lavorativi dalla data in cui è stato concordato il piano operativo.</p>\n</div>"], [15, "<div>\n<p class=\"oj-normal\">15.   Qualora l'intervento rapido alle frontiere debba aver luogo, il direttore esecutivo, in consultazione con il consiglio di amministrazione, valuta immediatamente le priorità in relazione alle operazioni congiunte dell'Agenzia in corso e pianificate presso altre frontiere esterne, al fine di prevedere un'eventuale riallocazione delle risorse a favore di zone frontaliere esterne in cui è maggiormente necessario un impiego rafforzato.</p>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Squadre di sostegno per la gestione della migrazione", "anchor": "art_40", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Uno Stato membro che si trovi a fronteggiare sfide migratorie sproporzionate in particolari punti di crisi alle sue frontiere esterne, caratterizzate dall'arrivo di ampi flussi migratori misti, può chiedere un rinforzo tecnico e operativo da parte delle squadre di sostegno per la gestione della migrazione composte da esperti dei pertinenti organi, uffici e agenzie dell'Unione, che sono tenuti a operare nel rispetto del proprio mandato.</p>\n<p class=\"oj-normal\">Tale Stato membro presenta una richiesta di rinforzo e una valutazione delle proprie esigenze alla Commissione. La Commissione, sulla base di tale valutazione delle esigenze, trasmette, a seconda del caso, la richiesta all'Agenzia, all'EASO, a Europol o ad altri organi, uffici e agenzie competenti dell'Unione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli organi, uffici e agenzie competenti dell'Unione esaminano, ai sensi dei rispettivi mandati, la richiesta di rinforzo dello Stato membro e la valutazione delle sue esigenze per definire un insieme completo di misure di rinforzo comprendente varie attività coordinate dagli organi, uffici e agenzie competenti dell'Unione, che deve essere approvato dallo Stato membro interessato. Tale processo avviene sotto il coordinamento della Commissione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione, in cooperazione con lo Stato membro ospitante e gli organi, uffici e agenzie competenti dell'Unione, ai sensi dei rispettivi mandati, stabilisce le modalità di cooperazione presso il punto di crisi ed è responsabile del coordinamento delle attività delle squadre di sostegno per la gestione della migrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il rinforzo tecnico e operativo fornito dal corpo permanente nell'ambito delle squadre di sostegno per la gestione della migrazione, nel pieno rispetto dei diritti fondamentali, può comprendere la fornitura di:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nel pieno rispetto dei diritti fondamentali, assistenza nella selezione (screening) dei cittadini di paesi terzi che arrivano alle frontiere esterne, comprese l'identificazione e la registrazione di tali cittadini e la raccolta di informazioni dai medesimi (<span class=\"oj-italic\">debriefing</span>), nonché, se richiesto dallo Stato membro, il rilevamento delle loro impronte digitali e la comunicazione di informazioni circa lo scopo di tali procedure;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni preliminari alle persone che desiderano richiedere protezione internazionale e l'indirizzamento di tali persone presso le autorità nazionali competenti dello Stato membro interessato o gli esperti inviati dall'EASO</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assistenza tecnica e operativa nel settore del rimpatrio, ai sensi dell'articolo 48, comprese la preparazione e l'organizzazione di operazioni di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le attrezzature tecniche necessarie.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le squadre di sostegno per la gestione della migrazione comprendono, ove necessario, personale specializzato in materia di protezione dei minori, tratta di esseri umani, protezione contro le persecuzioni di genere o diritti fondamentali.</p>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Azioni proposte alle frontiere esterne", "anchor": "art_41", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Sulla base dei risultati della valutazione delle vulnerabilità o quando a una o più sezioni di frontiera esterna è attribuito un livello di impatto critico e tenuto conto degli elementi pertinenti dei piani di emergenza dello Stato membro, dell'analisi dei rischi effettuata dall'Agenzia e del livello «analisi» del quadro situazionale europeo, il direttore esecutivo raccomanda allo Stato membro interessato di richiedere all'Agenzia di avviare, effettuare o adeguare operazioni congiunte o interventi rapidi alle frontiere o qualsiasi altra azione dell'Agenzia prevista all'articolo 36.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Lo Stato membro interessato risponde alla raccomandazione del direttore esecutivo di cui al paragrafo 1 entro sei giorni lavorativi. In caso di risposta negativa alla raccomandazione, lo Stato membro fornisce anche le motivazioni della risposta. Il direttore esecutivo comunica senza indugio al consiglio di amministrazione e alla Commissione le azioni raccomandate e le motivazioni della risposta negativa, affinché sia valutata l'eventuale necessità di un'azione urgente a norma dell'articolo 42.</p>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Situazioni che richiedono un'azione urgente alle frontiere esterne", "anchor": "art_42", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Qualora il controllo delle frontiere esterne sia reso inefficace in misura tale da rischiare di compromettere il funzionamento dello spazio Schengen poiché:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uno Stato membro non attua le misure necessarie ai sensi di una decisione del consiglio di amministrazione di cui all'articolo 32, paragrafo 10; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">uno Stato membro che si trova a fronteggiare sfide specifiche e sproporzionate alle frontiere esterne non ha chiesto un sostegno sufficiente all'Agenzia mediante le misure di cui all'articolo 37, 39, o 40, o non sta adottando le misure necessarie per attuare le azioni previste da tali articoli o dall'articolo 41;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">il Consiglio, sulla base di una proposta della Commissione, può adottare senza indugio una decisione, mediante atto di esecuzione, in cui definisce le misure che dovrebbero attenuare tali rischi e che devono essere attuate dall'Agenzia e impone allo Stato membro interessato di cooperare con l'Agenzia nell'attuazione di tali misure. La Commissione consulta l'Agenzia prima di formulare la sua proposta.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Se si verifica una situazione che richiede un'azione urgente, il Parlamento europeo è informato tempestivamente della situazione e di tutte le successive misure e decisioni adottate in risposta.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Al fine di attenuare il rischio di compromettere lo spazio Schengen, la decisione del Consiglio di cui al paragrafo 1 dispone che l'Agenzia adotti una o più delle seguenti misure:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzare e coordinare interventi rapidi alle frontiere e impiegare il corpo permanente, comprese squadre della riserva di reazione rapida;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiegare il corpo permanente nell'ambito delle squadre di sostegno per la gestione della migrazione, in particolare nei punti di crisi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">coordinare attività per uno o più Stati membri e paesi terzi alle frontiere esterne, comprese operazioni congiunte con paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impiegare attrezzatura tecnica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzare interventi di rimpatrio.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo, entro due giorni lavorativi dalla data di adozione della decisione del Consiglio di cui al paragrafo 1:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce le azioni da adottare per l'esecuzione pratica delle misure individuate in tale decisione, compresi l'attrezzatura tecnica e il numero e i profili del personale operativo necessari per conseguire gli obiettivi di tale decisione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">redige un progetto di piano operativo e lo presenta agli Stati membri interessati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo e lo Stato membro interessato concordano il piano operativo di cui al paragrafo 4, lettera b) entro tre giorni lavorativi dalla data di presentazione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'Agenzia invia tempestivamente, e comunque entro cinque giorni lavorativi dalla definizione del piano operativo, il personale operativo necessario attinto dal corpo permanente per l'esecuzione pratica delle misure individuate nella decisione del Consiglio di cui al paragrafo 1. L'impiego aggiuntivo di squadre avviene, se necessario, in una seconda fase e in ogni caso entro 12 giorni lavorativi dalla definizione del piano operativo.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia e gli Stati membri inviano tempestivamente, e comunque entro dieci giorni lavorativi dalla definizione del piano operativo, l'attrezzatura tecnica necessaria e il personale competente alla destinazione di impiego per l'esecuzione pratica delle misure individuate nella decisione del Consiglio di cui al paragrafo 1.</p>\n<p class=\"oj-normal\">L'impiego aggiuntivo di attrezzatura tecnica avviene, se necessario, in una seconda fase ai sensi delle pertinenti disposizioni dell'articolo 64.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Lo Stato membro interessato si conforma alla decisione del Consiglio di cui al paragrafo 1. A tale scopo coopera immediatamente con l'Agenzia e intraprende le azioni necessarie, in particolare adempiendo agli obblighi di cui agli articoli 43, 82 e 83, per agevolare l'attuazione di tale decisione e l'esecuzione pratica delle misure stabilite nella decisione stessa e nel piano operativo concordato con il direttore esecutivo.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Ai sensi dell'articolo 57 e, se del caso, dell'articolo 39, gli Stati membri mettono a disposizione il personale operativo determinato dal direttore esecutivo a norma del paragrafo 4 del presente articolo.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   La Commissione vigila sull'attuazione delle misure individuate nella decisione del Consiglio di cui al paragrafo 1 e delle azioni da essa adottate a tal fine. Qualora lo Stato membro interessato non si conformi alla decisione del Consiglio di cui al paragrafo 1 del presente articolo entro 30 giorni e non cooperi con l'Agenzia ai sensi del paragrafo 8 del presente articolo, la Commissione può attivare la procedura di cui all'articolo 29 del regolamento (UE) 2016/399.</p>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Istruzioni alle squadre", "anchor": "art_43", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Durante l'impiego delle squadre per la gestione delle frontiere, delle squadre per il rimpatrio e delle squadre di sostegno per la gestione della migrazione, lo Stato membro ospitante – o, in caso di cooperazione con un paese terzo ai sensi dell'accordo sullo status, il paese terzo interessato – impartisce istruzioni alle squadre conformemente al piano operativo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia, tramite il suo funzionario di coordinamento, può comunicare allo Stato membro ospitante il suo parere sulle istruzioni impartite alle squadre. In tal caso, lo Stato membro ospitante tiene conto di tale parere e lo segue nella misura del possibile.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualora le istruzioni impartite alle squadre non siano conformi al piano operativo, il funzionario di coordinamento ne informa immediatamente il direttore esecutivo, che può, se del caso, intervenire ai sensi dell'articolo 46, paragrafo 3.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze, i membri delle squadre rispettano pienamente i diritti fondamentali, compreso l'accesso alle procedure di asilo, e la dignità umana e prestano particolare attenzione alle persone vulnerabili. Qualsiasi misura che essi adottino nello svolgimento dei loro compiti e nell'esercizio delle loro competenze deve essere proporzionata agli obiettivi perseguiti dalla misura stessa. Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze essi non discriminano le persone in base a fattori quali il sesso, la razza, il colore, l'origine etnica o sociale, le caratteristiche genetiche, la lingua, la religione o le convinzioni personali, le opinioni politiche o di altro tipo, l'appartenenza a una minoranza nazionale, la proprietà, la nascita, la disabilità, l'età o l'orientamento sessuale, in linea con l'articolo 21 della Carta.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   I membri delle squadre che non sono personale statutario restano soggetti alle misure disciplinari dei rispettivi Stati membri di appartenenza. Lo Stato membro di appartenenza predispone adeguate misure disciplinari o di altra natura ai sensi del proprio diritto interno relativamente alle violazioni dei diritti fondamentali o degli obblighi in materia di protezione internazionale nel corso di una qualsiasi attività operativa dell'Agenzia.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il personale statutario impiegato come membri delle squadre è soggetto alle misure disciplinari stabilite dallo statuto dei funzionari e dal regime applicabile agli altri agenti dell'Unione nonché alle misure disciplinari previste dal meccanismo di vigilanza di cui all'articolo 55, paragrafo 5, lettera a).</p>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Funzionario di coordinamento", "anchor": "art_44", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia garantisce l'attuazione operativa di tutti gli aspetti organizzativi delle operazioni congiunte, dei progetti pilota e degli interventi rapidi alle frontiere, compresa la presenza di membri del suo personale statuario.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatto salvo l'articolo 60, il direttore esecutivo nomina uno o più esperti facenti parte del personale statutario da impiegare in qualità di funzionari di coordinamento per ogni operazione congiunta o intervento rapido alle frontiere. Il direttore esecutivo comunica la nomina allo Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il funzionario di coordinamento agisce a nome e per conto dell'Agenzia per tutti gli aspetti relativi all'impiego delle squadre. Il ruolo del funzionario di coordinamento è favorire la cooperazione e il coordinamento tra gli Stati membri ospitanti e partecipanti. Almeno un osservatore dei diritti fondamentali fornisce assistenza e consulenza al funzionario di coordinamento. In particolare, il funzionario di coordinamento:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">funge da interfaccia tra l'Agenzia, lo Stato membro ospitante e i membri delle squadre, fornendo assistenza, per conto dell'Agenzia, su tutte le questioni connesse alle condizioni del loro impiego;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitora la corretta attuazione del piano operativo, anche per quanto riguarda la tutela dei diritti fondamentali, in collaborazione con gli osservatori dei diritti fondamentali, e riferisce al direttore esecutivo in merito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">agisce a nome e per conto dell'Agenzia per tutti gli aspetti relativi all'impiego delle squadre e riferisce all'Agenzia su tutti tali aspetti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferisce al direttore esecutivo qualora le istruzioni impartite alle sue squadre dallo Stato membro ospitante non siano conformi al piano operativo, in particolare sotto il profilo dei diritti umani, e, ove opportuno, propone al direttore esecutivo di prendere in considerazione l'adozione di una decisione ai sensi dell'articolo 46.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nel contesto delle operazioni congiunte o degli interventi rapidi alle frontiere, il direttore esecutivo può autorizzare il funzionario di coordinamento a contribuire alla soluzione di eventuali disaccordi sull'esecuzione del piano operativo e sull'impiego delle squadre.</p>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Costi", "anchor": "art_45", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia copre pienamente i seguenti costi sostenuti dagli Stati membri nel mettere i membri del loro personale a disposizione ai fini dell'impiego a breve durata come membri delle squadre del corpo permanente negli Stati membri e nei paesi terzi ai sensi dell'articolo 57 oppure negli Stati membri attraverso la riserva di reazione rapida ai sensi dell'articolo 58:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le spese di viaggio dallo Stato membro di appartenenza allo Stato membro ospitante e dallo Stato membro ospitante allo Stato membro di appartenenza e all'interno dello Stato membro ospitante ai fini della missione o del reimpiego all'interno di tale Stato membro ospitante o di un altro Stato membro ospitante e ai fini della missione o del reimpiego all'interno di un paese terzo o in un altro paese terzo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi di vaccinazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi relativi ad assicurazioni specifiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i costi di assistenza sanitaria, inclusa quella psicologica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la diaria, spese di alloggio comprese.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Sulla base di una proposta del direttore esecutivo, il consiglio di amministrazione adotta e aggiorna, ove necessario, le regole specifiche per il rimborso dei costi sostenuti dal personale impiegato a breve termine ai sensi degli articoli 57 e 58. Per garantire il rispetto del quadro giuridico applicabile, il direttore esecutivo formula tale proposta dopo aver ricevuto il parere favorevole della Commissione. Le regole specifiche si basano per quanto possibile su opzioni semplificate in materia di costi ai sensi dell'articolo 125, paragrafo 1, lettere c), d) ed e) del regolamento (UE, Euratom) 2018/1046. Se del caso, il consiglio di amministrazione garantisce la coerenza con le regole applicabili alle spese di missione del personale statutario.</p>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Decisioni di sospensione, cessazione o mancato avvio delle attività", "anchor": "art_46", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo cessa qualsiasi attività dell'Agenzia se non ricorrono più le condizioni per il loro svolgimento. Il direttore esecutivo informa lo Stato membro interessato prima di tale cessazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri partecipanti a un'attività operativa dell'Agenzia possono chiedere al direttore esecutivo di cessare tale attività operativa. Il direttore esecutivo informa il consiglio di amministrazione di tale richiesta.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo, dopo avere informato lo Stato membro interessato, può revocare il finanziamento di un'attività, oppure sospendere o cessare tale attività se lo Stato membro ospitante non rispetta il piano operativo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo, dopo aver consultato il responsabile dei diritti fondamentali e informato lo Stato membro interessato, revoca il finanziamento di qualsiasi attività dell'Agenzia, oppure sospende o cessa, interamente o parzialmente, qualsiasi attività dell'Agenzia se ritiene che vi siano violazioni dei diritti fondamentali o degli obblighi in materia di protezione internazionale di natura grave o destinate a persistere correlate all'attività in questione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Previa consultazione del responsabile dei diritti fondamentali, il direttore esecutivo decide di non avviare alcuna attività dell'Agenzia per cui sussisterebbero, sin dal suo inizio, gravi motivi per sospenderla o cessarla perché potrebbe dare luogo a violazioni dei diritti fondamentali o degli obblighi in materia di protezione internazionale di natura grave. Il direttore esecutivo informa di tale decisione gli Stati membri interessati.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le decisioni di cui ai paragrafi 4 e 5 sono adottate sulla base di fondati motivi. Nell'adottare tali decisioni, il direttore esecutivo tiene conto delle informazioni pertinenti, per esempio il numero e il merito delle denunce registrate che non siano state risolte da un'autorità nazionale competente, delle relazioni relative a gravi incidenti nonché delle relazioni dei funzionari di coordinamento e di organizzazioni internazionali e istituzioni, organi, uffici e agenzie dell'Unione pertinenti nei settori contemplati dal presente regolamento. Il direttore esecutivo informa il consiglio di amministrazione di tali decisioni e ne fornisce le motivazioni.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Qualora decida di sospendere o cessare l'impiego, da parte dell'Agenzia, di una squadra di sostegno per la gestione della migrazione, il direttore esecutivo informa di tale decisione gli altri organi e organismi competenti che operano nell'area di crisi.</p>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Valutazione delle attività", "anchor": "art_47", "frags": [[null, "<p class=\"oj-normal\">Il direttore esecutivo valuta i risultati di tutte le attività operative dell'Agenzia. Il direttore esecutivo trasmette al consiglio di amministrazione relazioni di valutazione dettagliate entro sessanta giorni dal termine di tali attività, unitamente alle osservazioni del responsabile dei diritti fondamentali. Il direttore esecutivo effettua un'analisi completa di tali risultati allo scopo di migliorare la qualità, la coerenza e l'efficacia delle attività future, inserisce tale analisi nella relazione annuale di attività dell'Agenzia. Il direttore esecutivo garantisce che l'Agenzia tenga conto di tali risultati nell'ambito delle attività operative future.</p>"]]}, "48": {"label": "Articolo 48", "heading": "Rimpatrio", "anchor": "art_48", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Senza entrare nel merito delle decisioni di rimpatrio, che restano di responsabilità esclusiva degli Stati membri, l'Agenzia, nel rispetto dei diritti fondamentali, dei principi generali del diritto dell'Unione e del diritto internazionale, tra cui la protezione internazionale, il rispetto del principio di non respingimento e i diritti dei minori, assolve ai seguenti compiti per quanto riguarda il rimpatrio:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce assistenza tecnica e operativa agli Stati membri in relazione al rimpatrio, tra l'altro nei seguenti ambiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">raccolta delle informazioni necessarie per l'emissione delle decisioni di rimpatrio, identificazione dei cittadini di paesi terzi oggetto delle procedure di rimpatrio e altre attività degli Stati membri precedenti al rimpatrio, legate al rimpatrio e successive all'arrivo e al rimpatrio, al fine di instaurare un sistema integrato di gestione dei rimpatri tra le autorità competenti degli Stati membri, con la partecipazione delle autorità competenti dei paesi terzi e di altre pertinenti parti interessate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">\n<span class=\"oj-italic\">acquis</span>izione dei documenti di viaggio, anche tramite la cooperazione consolare, senza divulgare informazioni sul fatto che è stata presentata una domanda di protezione internazionale o qualsiasi altra informazione non necessaria ai fini del rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">iii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzazione e coordinamento delle operazioni di rimpatrio e fornitura di assistenza per i rimpatri volontari, in cooperazione con gli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">iv)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per quanto concerne i rimpatri volontari assistiti dagli Stati membri, fornitura di assistenza ai rimpatriandi nelle fasi precedenti al rimpatrio, legate al rimpatrio nonché successive all'arrivo e al rimpatrio, tenendo conto delle esigenze delle persone vulnerabili;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce assistenza tecnica e operativa agli Stati membri che incontrano difficoltà legate ai loro sistemi di rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppa, in consultazione con il responsabile dei diritti fondamentali, un modello di riferimento non vincolante per i sistemi informatici nazionali di gestione dei casi di rimpatrio che descriva la struttura di tali sistemi, e fornisce assistenza tecnica e operativa agli Stati membri per lo sviluppo di siffatti sistemi compatibili con il modello;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisce e sviluppa ulteriormente una piattaforma per la gestione integrata dei rimpatri e un'infrastruttura di comunicazione che consenta di collegare i sistemi di gestione dei rimpatri degli Stati membri con la piattaforma ai fini dello scambio di dati e informazioni, compresa la trasmissione automatica di dati statistici, e fornisce assistenza tecnica e operativa agli Stati membri per la connessione all'infrastruttura di comunicazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizza, promuove e coordina attività che consentano lo scambio di informazioni e l'individuazione e la condivisione delle migliori prassi in materia di rimpatrio tra gli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">finanzia o cofinanzia con il proprio bilancio, ai sensi delle regole finanziarie applicabili all'Agenzia, le operazioni, gli interventi e le attività di cui al presente capo, compresi i rimborsi dei costi sostenuti per il necessario adeguamento dei sistemi informatici nazionali di gestione dei casi di rimpatrio per garantire una comunicazione sicura con la piattaforma per la gestione integrata dei rimpatri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'assistenza tecnica e operativa di cui al paragrafo 1, lettera b), comprende attività intese ad aiutare gli Stati membri a espletare le procedure di rimpatrio svolte dalle autorità nazionali competenti, fornendo in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">servizi d'interpretariato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni pratiche, incluse le analisi di tali informazioni, e raccomandazioni dell'Agenzia sui paesi terzi di rimpatrio, utili ai fini dell'applicazione del presente regolamento, in cooperazione, se del caso, con altri organi, uffici e agenzie dell'Unione, in particolare l'EASO;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">consulenza per l'attuazione e la gestione delle procedure di rimpatrio ai sensi della direttiva 2008/115/CE;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">consulenza e assistenza per l'attuazione delle misure adottate dagli Stati membri ai sensi della direttiva 2008/115/CE e del diritto internazionale necessarie per garantire la disponibilità dei rimpatriandi ai fini del rimpatrio e per evitare che i rimpatriandi si rendano irreperibili, nonché consulenza e assistenza in relazione alle alternative al trattenimento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">attrezzature, risorse e competenze per l'attuazione delle decisioni di rimpatrio e l'identificazione dei cittadini di paesi terzi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia mira a sviluppare sinergie e a collegare le reti e i programmi finanziati dall'Unione in materia di rimpatrio, in stretta cooperazione con la Commissione e con il sostegno delle pertinenti parti interessate, compresa la rete europea sulle migrazioni.</p>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Sistemi di scambio di informazioni e gestione dei rimpatri", "anchor": "art_49", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia fornisce e sviluppa ulteriormente una piattaforma per la gestione integrata dei rimpatri, ai sensi dell'articolo 48, paragrafo 1, lettera d), per il trattamento delle informazioni, inclusi i dati personali che sono trasmessi dai sistemi nazionali di gestione dei rimpatri degli Stati membri e che sono necessari all'Agenzia per fornire assistenza tecnica e operativa. I dati personali devono includere unicamente dati biografici o elenchi di passeggeri. I dati personali sono trasmessi solo se sono necessari per consentire all'Agenzia di fornire assistenza nel coordinamento o nell'organizzazione delle operazioni di rimpatrio nei paesi terzi, indipendentemente dal mezzo di trasporto. Tali dati personali sono trasmessi alla piattaforma solo una volta che è stata adottata la decisione di avviare un'operazione di rimpatrio e sono cancellati non appena l'operazione ha termine.</p>\n<p class=\"oj-normal\">I dati biografici sono comunicati alla piattaforma solo se non possono essere consultati dai membri delle squadre ai sensi dell'articolo 17, paragrafo 3, del regolamento (UE) 2018/1860 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">39</span>).</p>\n<p class=\"oj-normal\">L'Agenzia può inoltre utilizzare la piattaforma ai fini della trasmissione sicura di dati biografici o biometrici, compresi tutti i tipi di documenti che possono essere considerati prova o prova <span class=\"oj-italic\">prima facie</span> della cittadinanza dei cittadini di paesi terzi oggetto di decisioni di rimpatrio, se la trasmissione di tali dati è necessaria per consentire all'Agenzia, su richiesta dello Stato membro, di fornire assistenza nella conferma dell'identità e della nazionalità dei cittadini di paesi terzi in singoli casi. Tali dati non sono conservati sulla piattaforma e sono cancellati immediatamente dopo la conferma di ricezione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Inoltre l'Agenzia sviluppa, attiva e fornisce sistemi informativi e applicazioni software per lo scambio di informazioni all'interno della guardia di frontiera e costiera europea ai fini del rimpatrio e per lo scambio di dati personali.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I dati personali sono trattati ai sensi degli articoli 86, 87, 88 e 91, a seconda dei casi.</p>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Operazioni di rimpatrio", "anchor": "art_50", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Senza entrare nel merito delle decisioni di rimpatrio, che restano di esclusiva responsabilità degli Stati membri, l'Agenzia fornisce agli Stati membri assistenza tecnica e operativa e assicura il coordinamento o l'organizzazione delle operazioni di rimpatrio, anche mediante il noleggio di aeromobili ai fini di tali operazioni e l'organizzazione di rimpatri su voli di linea o con altri mezzi di trasporto. L'Agenzia può, di propria iniziativa, con l'accordo dello Stato membro interessato, coordinare o organizzare operazioni di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri forniscono, mediante la piattaforma di cui all'articolo 49, paragrafo 1, i dati operativi sui rimpatri che sono necessari all'Agenzia per valutare le esigenze in materia di rimpatrio, e informano l'Agenzia della loro pianificazione indicativa del numero di rimpatriandi e dei paesi terzi di rimpatrio relativamente alle pertinenti operazioni di rimpatrio nazionali, e delle loro necessità di assistenza o coordinamento da parte dell'Agenzia. L'Agenzia predispone e tiene aggiornato un piano operativo dinamico inteso a fornire agli Stati membri che ne facciano richiesta l'assistenza e il rinforzo operativi necessari, anche in termini di attrezzatura tecnica. L'Agenzia può, di propria iniziativa, con l'accordo dello Stato membro interessato, o su richiesta di uno Stato membro, inserire nel piano operativo dinamico le date e le destinazioni delle operazioni di rimpatrio che ritiene necessarie, sulla base di una valutazione delle esigenze. Il consiglio di amministrazione decide, su proposta del direttore esecutivo, il modus operandi del piano operativo dinamico. Lo Stato membro interessato conferma all'Agenzia che tutti i rimpatriandi interessati da un'operazione di rimpatrio organizzata o coordinata dall'Agenzia sono destinatari di una decisione esecutiva di rimpatrio.</p>\n<p class=\"oj-normal\">Qualora siano impiegati membri di squadre, essi devono consultare il Sistema Informativo Schengen, prima del rimpatrio di qualsiasi persona soggetta a espulsione, per verificare se la decisione di rimpatrio di tale soggetto sia stata sospesa o se la sua esecuzione sia stata rinviata.</p>\n<p class=\"oj-normal\">Il piano operativo dinamico comprende gli elementi necessari per effettuare l'operazione di rimpatrio, tra cui quelli relativi al rispetto dei diritti fondamentali, e fa riferimento, tra l'altro, ai pertinenti codici di condotta, come pure alle procedure di monitoraggio, alla rendicontazione e al meccanismo per le denunce.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia può fornire assistenza tecnica e operativa agli Stati membri e può altresì, di propria iniziativa e con l'accordo dello Stato membro interessato, o su richiesta degli Stati membri partecipanti, assicurare il coordinamento o l'organizzazione delle operazioni di rimpatrio per le quali i mezzi di trasporto e le scorte per i rimpatri sono forniti da un paese terzo di rimpatrio («operazioni di rimpatrio mediante prelevamento»). Gli Stati membri partecipanti e l'Agenzia provvedono affinché il rispetto dei diritti fondamentali, il principio di non respingimento, l'uso proporzionato dei mezzi coercitivi e la dignità del rimpatriando siano garantiti durante l'intera operazione di rimpatrio. Almeno un rappresentante di uno Stato membro e un osservatore per i rimpatri forzati facente parte del gruppo istituito ai sensi dell'articolo 51 o del sistema di monitoraggio dello Stato membro partecipante sono presenti durante l'intera operazione di rimpatrio fino all'arrivo nel paese terzo di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo stabilisce senza indugio un piano di rimpatrio per le operazioni di rimpatrio mediante prelevamento. Il direttore esecutivo e ogni Stato membro partecipante concordano il piano di rimpatrio che definisce nel dettaglio gli aspetti organizzativi e procedurali dell'operazione di rimpatrio mediante prelevamento, tenendo conto delle implicazioni per i diritti fondamentali e dei rischi che tali operazioni comportano. Eventuali modifiche o adattamenti di tale piano sono subordinati al consenso delle parti di cui al paragrafo 3 e al presente paragrafo.</p>\n<p class=\"oj-normal\">Il piano di rimpatrio per le operazioni di rimpatrio mediante prelevamento è vincolante per l'Agenzia e per ogni Stato membro partecipante. Esso copre tutte le misure necessarie per la realizzazione delle operazioni di rimpatrio mediante prelevamento.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Ciascuna operazione di rimpatrio organizzata o coordinata dall'Agenzia è monitorata ai sensi dell'articolo 8, paragrafo 6, della direttiva 2008/115/CE. Il monitoraggio delle operazioni di rimpatrio forzato è svolto dall'osservatore per i rimpatri forzati sulla base di criteri oggettivi e trasparenti e riguarda l'intera operazione, dalla fase precedente la partenza fino alla consegna del rimpatriando nel paese terzo di rimpatrio. L'osservatore per i rimpatri forzati presenta una relazione su ogni operazione di rimpatrio forzato al direttore esecutivo, al responsabile dei diritti fondamentali e alle autorità nazionali competenti di tutti gli Stati membri coinvolti nell'operazione. Se del caso, è assicurato un seguito adeguato da parte, rispettivamente, del direttore esecutivo e delle autorità nazionali competenti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Qualora nutra preoccupazioni circa il rispetto dei diritti fondamentali in qualsiasi fase di un'operazione di rimpatrio, l'Agenzia le comunica agli Stati membri partecipanti e alla Commissione.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il direttore esecutivo valuta i risultati delle operazioni di rimpatrio e trasmette ogni sei mesi al Parlamento europeo, al Consiglio, alla Commissione e al consiglio di amministrazione una relazione di valutazione dettagliata su tutte le operazioni di rimpatrio effettuate nel semestre precedente, unitamente alle osservazioni del responsabile dei diritti fondamentali. Il direttore esecutivo effettua un'analisi completa e comparativa di tali risultati allo scopo di migliorare la qualità, la coerenza e l'efficacia delle future operazioni di rimpatrio. Il direttore esecutivo inserisce tale analisi nella relazione annuale di attività dell'Agenzia.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia finanzia o cofinanzia le operazioni di rimpatrio mediante il proprio bilancio, ai sensi delle regole finanziarie applicabili all'Agenzia, dando priorità a quelle condotte da più di uno Stato membro, o a partire dai punti di crisi.</p>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Riserva di osservatori per i rimpatri forzati", "anchor": "art_51", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, dopo aver preso in debita considerazione il parere del responsabile dei diritti fondamentali, costituisce una riserva di osservatori per i rimpatri forzati provenienti dagli organi competenti degli Stati membri, che svolgono attività di monitoraggio del rimpatrio forzato ai sensi dell'articolo 8, paragrafo 6, della direttiva 2008/115/CE e che sono stati formati ai sensi dell'articolo 62 del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione, su proposta del direttore esecutivo, determina il profilo e il numero degli osservatori per i rimpatri forzati da mettere a disposizione della riserva. La stessa procedura si applica a eventuali successive modifiche del profilo e del numero complessivo.</p>\n<p class=\"oj-normal\">Gli Stati membri sono responsabili del contributo alla riserva designando gli osservatori per i rimpatri forzati corrispondenti al profilo stabilito, fatta salva l'indipendenza di tali osservatori, ove prevista a norma del diritto nazionale. Anche l'Agenzia contribuisce alla riserva con gli osservatori dei diritti fondamentali di cui all'articolo 110. La riserva include osservatori per i rimpatri forzati dotati di competenze specifiche in materia di protezione dei minori.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il contributo degli Stati membri, relativamente ai loro osservatori per i rimpatri forzati, a operazioni e interventi di rimpatrio previsti per l'anno successivo è programmato sulla base di negoziati e accordi bilaterali annuali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi, gli Stati membri mettono a disposizione dell'Agenzia gli osservatori per i rimpatri forzati per il loro impiego su richiesta della stessa, salvo che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Tale richiesta è inoltrata almeno 21 giorni lavorativi prima della missione prevista o cinque giorni lavorativi prima nel caso di un intervento rapido di rimpatrio.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia mette a disposizione degli Stati membri partecipanti, su richiesta, gli osservatori per i rimpatri forzati affinché monitorino, per loro conto, il corretto svolgimento delle operazioni di rimpatrio e degli interventi di rimpatrio per la loro intera durata. Essa mette a disposizione osservatori per i rimpatri forzati dotati di competenze specifiche in materia di protezione dei minori per qualsiasi operazione di rimpatrio che coinvolga minori.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli osservatori per i rimpatri forzati restano soggetti alle misure disciplinari dei rispettivi Stati membri di appartenenza nel corso di un'operazione o di un intervento di rimpatrio. Il personale statutario impiegato come osservatore per i rimpatri forzati è soggetto alle misure disciplinari previste dallo statuto dei funzionari e dal regime applicabile agli altri agenti dell'Unione.</p>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Squadre per il rimpatrio", "anchor": "art_52", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può inviare, di propria iniziativa e con l'accordo dello Stato membro interessato o su richiesta di tale Stato membro, squadre per il rimpatrio. L'Agenzia può inviare tali squadre durante un intervento di rimpatrio, nell'ambito delle squadre di sostegno per la gestione della migrazione o nella misura necessaria per fornire assistenza tecnica e operativa supplementare nel settore del rimpatrio. Ove necessario, le squadre per il rimpatrio possono comprendere anche agenti con competenze specifiche nella protezione dei minori.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'articolo 40, paragrafi da 2 a 5, e gli articoli 43, 44 e 45 si applicano, <span class=\"oj-italic\">mutatis mutandis</span>, alle squadre per il rimpatrio.</p>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Interventi di rimpatrio", "anchor": "art_53", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Nei casi in cui uno Stato membro debba affrontare oneri nell'attuazione dell'obbligo di rimpatrio di rimpatriandi, l'Agenzia fornisce, di propria iniziativa e con l'accordo dello Stato membro interessato, o su richiesta di tale Stato membro, l'adeguata assistenza tecnica e operativa sotto forma di intervento di rimpatrio. Tale intervento può consistere nell'invio nello Stato membro ospitante di squadre per il rimpatrio che forniscono assistenza nell'attuazione delle procedure di rimpatrio e nell'organizzazione di operazioni di rimpatrio dallo Stato membro ospitante.</p>\n<p class=\"oj-normal\">L'articolo 50 si applica anche alle operazioni di rimpatrio organizzate o coordinate dall'Agenzia nell'ambito di interventi di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei casi in cui uno Stato membro sia soggetto a sfide specifiche e sproporzionate nell'attuazione del suo obbligo di rimpatrio di persone soggette a espulsione, l'Agenzia fornisce, di propria iniziativa con l'accordo dello Stato membro interessato, o su richiesta di tale Stato membro, l'adeguata assistenza tecnica e operativa sotto forma di intervento rapido di rimpatrio. Un intervento rapido di rimpatrio può consistere nell'invio rapido nello Stato membro ospitante di squadre per il rimpatrio che forniscono assistenza nell'attuazione delle procedure di rimpatrio e nell'organizzazione di operazioni di rimpatrio dallo Stato membro ospitante.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel contesto di un intervento di rimpatrio il direttore esecutivo stabilisce tempestivamente un piano operativo, di concerto con lo Stato membro ospitante e con gli Stati membri partecipanti. Si applicano le disposizioni dell'articolo 38 <span class=\"oj-italic\">mutatis mutandis</span>.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo adotta una decisione sul piano operativo quanto prima e, nel caso di cui al paragrafo 2, entro cinque giorni lavorativi. La decisione è immediatamente notificata per iscritto agli Stati membri interessati e al Consiglio di amministrazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia finanzia o cofinanzia gli interventi di rimpatrio dal proprio bilancio, ai sensi delle regole finanziarie applicabili all'Agenzia.</p>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Corpo permanente della guardia di frontiera e costiera europea", "anchor": "art_54", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia comprende un corpo permanente della guardia di frontiera e costiera europea con la capacità stabilita nell'allegato I. Il corpo permanente è formato dalle quattro seguenti categorie di personale operativo ai sensi del piano annuale delle disponibilità di cui all'allegato I:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">categoria 1: personale statutario impiegato come membri delle squadre nelle aree operative ai sensi dell'articolo 55, e personale responsabile del funzionamento dell'unità centrale ETIAS;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">categoria 2: personale distaccato a lungo termine presso l'Agenzia dagli Stati membri e facente parte integrante del corpo permanente ai sensi dell'articolo 56;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">categoria 3: personale degli Stati membri pronto per essere messo a disposizione dell'Agenzia per un impiego di breve durata quale parte integrante del corpo permanente ai sensi dell'articolo 57; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">categoria 4: riserva di reazione rapida composta da personale degli Stati membri pronto per essere impiegato, ai sensi dell'articolo 58 ai fini di interventi rapidi alle frontiere ai sensi dell'articolo 39.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia impiega i membri del corpo permanente in qualità di membri delle squadre per la gestione delle frontiere, delle squadre di sostegno per la gestione della migrazione e delle squadre per il rimpatrio nelle operazioni congiunte, negli interventi rapidi alle frontiere o in qualsiasi altra attività operativa pertinente negli Stati membri o nei paesi terzi. Tali attività possono essere svolte solo previa autorizzazione dello Stato membro o del paese terzo interessato. L'effettiva consistenza numerica del personale del corpo permanente dipende dalle esigenze delle esigenze operative.</p>\n<p class=\"oj-normal\">L'impiego del corpo permanente è complementare agli sforzi intrapresi dagli Stati membri.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nel fornire sostegno agli Stati membri, i membri del corpo permanente impiegati come membri delle squadre devono avere la capacità di svolgere compiti di controllo di frontiera o di rimpatrio, compresi i compiti che richiedono i poteri esecutivi previsti dal diritto nazionale pertinente o, nel caso del personale statutario, i compiti che richiedono i poteri esecutivi di cui all'articolo 55, paragrafo 7.</p>\n<p class=\"oj-normal\">I membri del corpo permanente soddisfano i requisiti in materia di formazione specialistica e professionalità di cui all'articolo 16, paragrafo 1, terzo comma, del regolamento (UE) 2016/399 o ad altri strumenti pertinenti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sulla base di una proposta del direttore esecutivo e tenuto conto dell'analisi dei rischi effettuata dall'Agenzia, dei risultati della valutazione delle vulnerabilità e del ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere, e sulla base del numero e dei profili del personale di cui l'Agenzia dispone grazie al suo personale statutario e ai distacchi in corso, il consiglio di amministrazione adotta una decisione entro il 31 marzo di ogni anno:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che definisce i profili e i requisiti per il personale operativo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che stabilisce, sulla base delle esigenze operative previste per l'anno successivo, il numero dei membri del personale per ogni profilo specifico delle categorie 1, 2 e 3 del personale che dovranno formare le squadre l'anno successivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che stabilisce ulteriormente i contributi stabiliti negli allegati II e III fissando, per ogni Stato membro, il numero e i profili specifici dei membri del personale da distaccare presso l'Agenzia ai sensi dell'articolo 56 e da designare ai sensi dell'articolo 57 l'anno successivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che specifica ulteriormente i contributi stabiliti nell'allegato IV fissando, per ogni Stato membro, il numero e i profili specifici dei membri del personale da mettere a disposizione l'anno successivo nell'ambito della riserva di reazione rapida in caso di interventi rapidi alle frontiere ai sensi degli articoli 39 e 58;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">che stabilisce una pianificazione pluriennale indicativa dei profili per gli anni successivi per facilitare la pianificazione a lungo termine dei contributi degli Stati membri e dell'assunzione del personale statutario.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il personale addetto alle attrezzature tecniche messo a disposizione ai sensi dell'articolo 64 è preso in considerazione quale parte dei contributi forniti dagli Stati membri per gli impieghi di breve durata, ai sensi dell'articolo 57, per l'anno successivo. In vista dell'adozione della pertinente decisione del consiglio di amministrazione di cui al paragrafo 4 del presente articolo, lo Stato membro interessato comunica all'Agenzia l'intenzione di utilizzare le attrezzature tecniche, con il personale corrispondente, entro la fine di gennaio di ogni anno.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Ai fini dell'articolo 73, l'Agenzia sviluppa e provvede alle strutture di comando e controllo per l'effettivo impiego del corpo permanente nel territorio di paesi terzi.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia può assumere un numero sufficiente di membri del personale statutario, che può coprire il 4 % del numero totale dei membri del corpo permanente quale indicato nell'allegato I per svolgere funzioni di sostegno o monitoraggio per l'istituzione del corpo permanente, la pianificazione e la gestione delle sue operazioni e l'<span class=\"oj-italic\">acquis</span>to delle attrezzature proprie dell'Agenzia.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I membri del personale di cui al paragrafo 7 e del personale responsabile del funzionamento dell'unità centrale ETIAS non sono impiegati in quanto membri delle squadre, ma sono comunque conteggiati come personale di categoria 1 ai fini dell'allegato I.</p>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Personale statutario all'interno del corpo permanente", "anchor": "art_55", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia contribuisce al corpo permanente con membri del proprio personale statutario (categoria 1) da inviare nelle aree operative in qualità di membri delle squadre dotati delle competenze e dei compiti di cui all'articolo 82, compreso quello di gestire le attrezzature proprie dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   All'atto dell'assunzione del personale, l'Agenzia garantisce la selezione dei soli candidati che dimostrino un livello elevato di professionalità, rispettino rigorosi valori etici e dispongano di competenze linguistiche adeguate.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ai sensi dell'articolo 62, paragrafo 2, dopo l'assunzione i membri del personale statutario che saranno impiegati nelle squadre seguono la necessaria formazione di guardia di frontiera o attinente ai rimpatri, anche in materia di diritti fondamentali, in funzione dei profili del personale stabiliti dal consiglio di amministrazione ai sensi dell'articolo 54, paragrafo 4, e tenendo conto dei titoli e dell'esperienza professionale precedentemente <span class=\"oj-italic\">acquis</span>iti nei settori pertinenti.</p>\n<p class=\"oj-normal\">La formazione di cui al primo comma si svolge nell'ambito di appositi programmi di formazione sviluppati dall'Agenzia e, sulla base di accordi con Stati membri prescelti, attuati in istituti specializzati di istruzione e formazione di tali Stati membri, tra cui le scuole partner dell'Agenzia situate negli Stati membri. Per tutti i singoli membri del personale, in seguito all'assunzione, sono stabiliti percorsi di formazione per garantire che posseggano sempre le qualifiche professionali necessarie per adempiere ai compiti di guardia di frontiera o attinenti ai rimpatri. Tali percorsi sono aggiornati periodicamente. Il costo della formazione è interamente coperto dall'Agenzia.</p>\n<p class=\"oj-normal\">Il personale statutario che svolge la funzione di personale tecnico addetto alle attrezzature proprie dell'Agenzia non necessita di formazione completa connessa a guardia di frontiera o rimpatri.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia assicura che, durante tutto il loro impiego, i membri del proprio personale statutario assolvano alle loro funzioni di membri delle squadre secondo gli standard più elevati e nel pieno rispetto dei diritti fondamentali.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sulla base di una proposta del direttore esecutivo, il consiglio di amministrazione provvede a:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituire un adeguato meccanismo di vigilanza per monitorare l'applicazione delle disposizioni sull'uso della forza da parte del personale statutario, comprese le norme in materia di rendicontazione e le misure specifiche, per esempio di carattere disciplinare, relative all'uso della forza durante l'impiego;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilire norme in base alle quali il direttore esecutivo possa autorizzare personale statutario a portare e utilizzare armi ai sensi dell'articolo 82 e all'allegato V, anche in relazione alla cooperazione obbligatoria con le autorità nazionali competenti, in particolare dello Stato membro di cittadinanza, dello Stato membro di residenza e dello Stato membro in cui si è tenuta la formazione iniziale. Tali norme disciplinano altresì il modo in cui il direttore esecutivo garantisce che le condizioni per il rilascio di tali autorizzazioni continuino a essere soddisfatte dal personale statutario, in particolare per quanto riguarda l'uso delle armi, inclusa la realizzazione di prove di tiro periodiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilire norme specifiche per agevolare la custodia di armi, munizioni e altre attrezzature in strutture sicure, nonché il loro trasporto verso le zone operative.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Per quanto concerne le norme di cui al presente paragrafo, primo comma, lettera a), la Commissione esprime un parere sulla loro conformità allo statuto dei funzionari e al regime applicabile agli altri agenti dell'Unione, a norma dell'articolo 110, paragrafo 2, dello statuto dei funzionari. Il responsabile dei diritti fondamentali è consultato in merito alla proposta del direttore esecutivo concernente tali norme.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il personale dell'Agenzia che non è qualificato per svolgere funzioni di guardia di frontiera o attinenti al rimpatrio sono impiegati nelle operazioni congiunte solo per compiti di coordinamento, monitoraggio dei diritti fondamentali e altri compiti connessi. Esso non fa parte delle squadre.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il personale statutario da impiegare nelle squadre è abilitato a svolgere, ai sensi dell'articolo 82, i seguenti compiti per i quali sono necessari poteri esecutivi, in conformità dei profili di personale e della pertinente formazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">verifica dell'identità e della cittadinanza delle persone, compresa la consultazione delle pertinenti banche dati nazionali e dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorizzazione all'ingresso, se le condizioni stabilite all'articolo 6 del regolamento (UE) 2016/399 sono soddisfatte;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">respingimento ai sensi dell'articolo 14 del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">apposizione di timbri sui documenti di viaggio ai sensi dell'articolo 11 del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rilascio o rifiuto di visti alla frontiera ai sensi dell'articolo 35 del regolamento (CE) n. 810/2009 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">40</span>) e inserimento dei corrispondenti dati nel Sistema di Informazione dei visti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sorveglianza di frontiera, compreso il pattugliamento tra valichi di frontiera, allo scopo di impedire l'attraversamento non autorizzato della frontiera, di lottare contro la criminalità transfrontaliera e di adottare misure contro le persone entrate illegalmente, ivi compresi l'intercettazione o il fermo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">registrazione nell'Eurodac delle impronte digitali delle persone fermate in relazione all'attraversamento irregolare di una frontiera esterna, ai sensi del capo III del regolamento(UE) n. 603/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">41</span>);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contatti con i paesi terzi ai fini dell'identificazione e dell'<span class=\"oj-italic\">acquis</span>izione di documenti di viaggio per i rimpatriandi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scorta di cittadini di paesi terzi cui si applicano procedure di rimpatrio forzato.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Partecipazione degli Stati membri al corpo permanente mediante distacchi a lungo termine", "anchor": "art_56", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri contribuiscono al corpo permanente distaccando presso l'Agenzia membri del personale operativo in qualità di membri delle squadre (categoria 2). La durata dei singoli distacchi è di 24 mesi. Con il consenso dello Stato membro di appartenenza e dell'Agenzia, i singoli distacchi possono essere prorogati una sola volta per altri 12 o 24 mesi. Al fine di facilitare l'attuazione del sistema di sostegno finanziario di cui all'articolo 61, di norma il distacco comincia all'inizio dell'anno civile.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   A ciascuno Stato membro spetta garantire il contributo continuo in termini di membri del personale operativo distaccati in qualità di membri delle squadre ai sensi dell'allegato II. Il pagamento dei costi sostenuti dal personale impiegato a norma del presente articolo è effettuato ai sensi delle norme adottate ai sensi dell'articolo 95, paragrafo 6.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I membri del personale operativo distaccati presso l'Agenzia hanno i compiti e le competenze dei membri delle squadre ai sensi dell'articolo 82. Lo Stato membro che ha distaccato tali membri del personale operativo è considerato il loro Stato membro di appartenenza. Durante il distacco, la sede e la durata del distacco dei membri delle squadre distaccati sono decise dal direttore esecutivo secondo le esigenze operative. L'Agenzia assicura la formazione continua del personale operativo durante il periodo di distacco.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Entro il 30 giugno di ogni anno ciascuno Stato membro indica i candidati al distacco tra il personale operativo in base al numero e ai profili specifici decisi dal consiglio di amministrazione per l'anno successivo come indicato all'articolo 54, paragrafo 4. L'Agenzia verifica che il personale operativo proposto dagli Stati membri corrisponda ai profili del personale stabiliti e possieda le competenze linguistiche necessarie. Entro il 15 settembre di ogni anno l'Agenzia accetta i candidati proposti o, qualora il candidato in questione non corrisponda al profilo richiesto, non abbia sufficienti competenze linguistiche o durante precedenti impieghi abbia tenuto una condotta scorretta o abbia violato le norme applicabili, lo respinge e richiede allo Stato membro di proporre altri candidati per il distacco.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Qualora, per causa di forza maggiore, un membro del personale operativo non possa essere distaccato o non sia più in grado di proseguire il distacco, lo Stato membro interessato garantisce la sostituzione del membro del personale con un altro membro del personale operativo che abbia il profilo richiesto.</p>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Partecipazione degli Stati membri al corpo permanente mediante impieghi di breve durata", "anchor": "art_57", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Oltre ai distacchi di cui all'articolo 56, entro il 30 giugno di ogni anno gli Stati membri contribuiscono al corpo permanente designando guardie di frontiera e altro personale competente da inserire nell'elenco nazionale preliminare del personale operativo disponibile per impieghi di breve durata (categoria 3) conformemente ai contributi indicati nell'allegato III e al numero e ai profili specifici del personale decisi dal consiglio di amministrazione per l'anno successivo a norma dell'articolo 54, paragrafo 4. Gli elenchi nazionali preliminari del personale operativo designato sono comunicati all'Agenzia. La composizione definitiva dell'elenco annuale è confermata dall'Agenzia dopo la conclusione dei negoziati bilaterali annuali, entro il 1<span class=\"oj-super\">o</span> dicembre dello stesso anno.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   A ciascuno Stato membro spetta garantire che il personale designato come operativo sia disponibile su richiesta dell'Agenzia ai sensi degli accordi definiti nel presente articolo. Ogni membro del personale è disponibile per un periodo massimo di quattro mesi nell'arco di un anno civile. Tuttavia, gli Stati membri possono decidere di impiegare un singolo membro del personale oltre il periodo di quattro mesi. Tale proroga è considerata un contributo distinto dello Stato membro in questione per lo stesso profilo o per un altro profilo richiesto se il membro del personale possiede le competenze necessarie. Il pagamento dei costi sostenuti dal personale impiegato a norma del presente articolo è effettuato ai sensi delle norme adottate ai sensi dell'articolo 45, paragrafo 2.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il personale operativo impiegato a norma del presente articolo ha i compiti e le competenze dei membri delle squadre ai sensi dell'articolo 82.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia può verificare che il personale operativo designato dagli Stati membri per impieghi di breve durata corrisponda ai profili del personale stabiliti e possieda le competenze linguistiche necessarie. L'Agenzia rifiuta un membro del personale operativo designato se questi non ha sufficienti competenze linguistiche o durante precedenti impieghi ha tenuto una condotta scorretta o ha violato le norme applicabili. L'Agenzia rifiuta altresì un membro personale operativo designato in caso di non conformità al profilo richiesto, a meno che tale membro del personale operativo soddisfi i requisiti di un altro profilo assegnato allo stesso Stato membro. In caso di rifiuto di un membro del personale da parte dell'Agenzia, lo Stato membro interessato ne assicura la sostituzione con un altro membro del personale operativo corrispondente al profilo richiesto.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Entro il 31 luglio di ogni anno l'Agenzia richiede il contributo degli Stati membri in termini di membri del personale operativo per l'impiego nelle proprie specifiche operazioni congiunte per l'anno successivo, nell'ambito del numero e dei profili richiesti. La durata dei singoli impieghi è decisa nei negoziati e accordi bilaterali annuali tra l'Agenzia e gli Stati membri.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   In esito ai negoziati bilaterali annuali, gli Stati membri mettono il personale figurante negli elenchi nazionali di cui al paragrafo 1 a disposizione per impieghi specifici in base al numero e ai profili specificati nella richiesta dell'Agenzia.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Qualora, per causa di forza maggiore, un membro del personale operativo non possa essere impiegato conformemente agli accordi, lo Stato membro interessato provvede a sostituirlo con altro membro incluso nella lista che abbia il profilo richiesto.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Qualora l'esigenza di rinforzo per un'operazione congiunta in corso aumenti o sorga l'esigenza di avviare un intervento rapido alle frontiere o una nuova operazione congiunta non specificata nel pertinente programma di lavoro annuale né nei corrispondenti risultati delle negoziazioni bilaterali annuali, l'impiego ha luogo nel rispetto delle capacità indicate nell'allegato III. Il direttore esecutivo informa senza indugio gli Stati membri delle esigenze aggiuntive indicando il numero congruo e i profili di personale operativo che ogni Stato membro deve fornire. Una volta che il direttore esecutivo e lo Stato membro ospitante abbiano concordato gli emendamenti del piano operativo o, se del caso, un nuovo piano operativo, il direttore esecutivo presenta la richiesta formale per il numero e i profili di personale operativo. Gli Stati membri inviano i rispettivi membri delle squadre entro 20 giorni lavorativi dalla richiesta formale, fatto salvo l'articolo 39.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Qualora dall'analisi dei rischi o, se disponibile, da una valutazione delle vulnerabilità emerga che uno Stato membro si trova a far fronte a una situazione che inciderebbe in misura sostanziale sull'adempimento dei compiti nazionali, tale Stato membro fornisce contributi in termini di personale operativo conformemente alle richieste dell'Agenzia di cui al paragrafo 5 o al paragrafo 8 del presente articolo. Tuttavia, tali contributi non superano complessivamente la metà delle capacità dello Stato membro stabilite per l'anno in questione nell'allegato III. Qualora uno Stato membro faccia valere una tale situazione eccezionale, esso fornisce per iscritto all'Agenzia motivazioni e informazioni dettagliate sulla situazione, il cui contenuto sarà incluso nella relazione di cui all'articolo 65.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   La durata dell'impiego per un'operazione specifica è stabilita dallo Stato membro di appartenenza ma in ogni caso non è inferiore a 30 giorni, tranne se l'operazione di cui fa parte l'impiego ha una durata inferiore a 30 giorni.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Il personale tecnico considerato ai fini dei contributi degli Stati membri ai sensi dell'articolo 54, paragrafo 5, è unicamente impiegato ai sensi degli accordi risultanti dai negoziati bilaterali annuali per le attrezzature tecniche corrispondenti di cui all'articolo 64, paragrafo 9.</p>\n<p class=\"oj-normal\">In deroga al paragrafo 1 del presente articolo, gli Stati membri includono nei loro elenchi annuali il personale tecnico di cui al presente paragrafo, primo comma, soltanto dopo la conclusione dei negoziati bilaterali annuali. Gli Stati membri possono adeguare l'elenco annuale pertinente in caso di modifiche riguardanti il personale tecnico durante l'anno in questione. Gli Stati membri comunicano tali modifiche all'Agenzia.</p>\n<p class=\"oj-normal\">La verifica di cui al paragrafo 4 del presente articolo non riguarda le competenze di utilizzo dell'attrezzatura tecnica.</p>\n<p class=\"oj-normal\">Il personale tecnico avente esclusivamente funzioni tecniche figura negli elenchi annuali nazionali soltanto per funzione svolta.</p>\n<p class=\"oj-normal\">La durata dell'impiego del personale tecnico è determinata ai sensi dell'articolo 64.</p>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Partecipazione degli Stati membri al corpo permanente mediante la riserva di reazione rapida", "anchor": "art_58", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri contribuiscono mediante personale operativo al corpo permanente per mezzo di una riserva di reazione rapida (categoria 4) da attivare per interventi rapidi alle frontiere ai sensi dell'articolo 37, paragrafo 2, e dell'articolo 39, purché il personale operativo nelle categorie 1, 2 e 3 sia già stato pienamente impiegato per l'intervento rapido alle frontiere in questione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni Stato membro è responsabile di garantire la disponibilità del personale operativo nella consistenza numerica e nei profili corrispondenti stabiliti dal consiglio di amministrazione per l'anno successivo, come previsto all'articolo 54, paragrafo 4, su richiesta dell'Agenzia nel rispetto dei limiti indicati nell'allegato IV e secondo le modalità definite nel presente articolo. Ogni membro del personale operativo è disponibile per un periodo massimo di quattro mesi nell'arco di un anno civile.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'impiego specifico nell'ambito degli interventi rapidi alle frontiere dalla riserva di reazione rapida ha luogo ai sensi dell'articolo 39, paragrafi 11 e 13.</p>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Revisione del corpo permanente", "anchor": "art_59", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 31 dicembre 2023 la Commissione, basandosi in particolare sulle relazioni di cui all'articolo 62, paragrafo 10, e all'articolo 5, presenta al Parlamento europeo e al Consiglio una revisione del numero complessivo del personale e della composizione del corpo permanente, valutando anche l'entità dei contributi dei singoli Stati membri al corpo permanente, nonché delle competenze e della professionalità del corpo permanente e della formazione che riceve. Nella revisione si valuta altresì la necessità di mantenere la riserva di reazione rapida nell'ambito del corpo permanente.</p>\n<p class=\"oj-normal\">Nella revisione sono descritte e considerate le esigenze operative esistenti e potenziali per il corpo permanente in relazione alle capacità di risposta rapida, nonché le circostanze significative che incidono sulle capacità degli Stati membri di contribuire al corpo permanente e l'evoluzione del personale statutario per quanto riguarda la contribuzione dell'Agenzia al corpo permanente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 29 febbraio 2024, la Commissione presenta, ove necessario, le opportune proposte di modifica degli allegati I, II, III e IV. Qualora non presenti una proposta, la Commissione ne spiega i motivi.</p>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Uffici antenna", "anchor": "art_60", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Previo accordo con lo Stato membro ospitante o previa inclusione esplicita di tale possibilità nell'accordo sullo status concluso con il paese terzo ospitante, l'Agenzia può istituire uffici antenna nel territorio di tale Stato membro o paese terzo per agevolare e migliorare il coordinamento delle attività operative, anche nel settore del rimpatrio, organizzate dall'Agenzia in tale Stato membro o nella regione vicina, o in tale paese terzo, e per assicurare la gestione efficace delle proprie risorse umane e tecniche. Gli uffici antenna sono istituiti in funzione delle esigenze operative per il periodo necessario all'Agenzia per svolgere attività operative significative nello Stato membro in questione, nella regione vicina o nel paese terzo interessato. Se necessario, tale periodo può essere prorogato.</p>\n<p class=\"oj-normal\">Prima dell'istituzione di un ufficio antenna sono valutate e calcolate attentamente tutte le conseguenze di bilancio, e i relativi importi sono iscritti preventivamente in bilancio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia e lo Stato membro ospitante o il paese terzo ospitante in cui è istituito l'ufficio antenna prendono gli accordi necessari per offrire all'ufficio antenna le migliori condizioni possibili per adempiere ai suoi compiti. La sede di lavoro del personale impiegato negli uffici antenna è stabilita ai sensi dell'articolo 95, paragrafo 2.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Se del caso, gli uffici antenna:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono sostegno operativo e logistico, e garantiscono il coordinamento delle attività dell'Agenzia nelle aree operative interessate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono sostegno operativo allo Stato membro o al paese terzo nelle aree operative interessate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitorano le attività delle squadre e riferiscono periodicamente alla sede centrale dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">cooperano con lo Stato membro ospitante o il paese terzo ospitante su tutte le questioni connesse all'attuazione pratica delle attività operative organizzate dall'Agenzia in tale Stato membro o in tale paese terzo, comprese eventuali ulteriori questioni sorte durante tali attività;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono sostegno al funzionario di coordinamento di cui all'articolo 44 ai fini della cooperazione con gli Stati membri partecipanti su tutte le questioni connesse al loro contributo alle attività operative organizzate dall'Agenzia, e, se necessario, assicurano il collegamento con la sede centrale dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono sostegno al funzionario di coordinamento, nonché agli osservatori dei diritti fondamentali incaricati di monitorare un'attività operativa, al fine di agevolare, se necessario, il coordinamento e la comunicazione tra le squadre dell'Agenzia e le autorità pertinenti dello Stato membro ospitante o del paese terzo ospitante nonché lo svolgimento di qualsiasi compito pertinente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzano il sostegno logistico per l'impiego dei membri delle squadre e l'impiego e l'uso delle attrezzature tecniche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono ogni altro sostegno logistico necessario nell'area operativa di cui un dato ufficio antenna è responsabile per facilitare il buon svolgimento delle attività operative organizzate dall'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">forniscono sostegno al funzionario di collegamento dell'Agenzia, fatti salvi i suoi compiti e le sue funzioni di cui all'articolo 31, al fine di individuare eventuali problemi attuali o futuri per la gestione delle frontiere nell'area di cui un dato ufficio antenna è responsabile, per attuare l'<span class=\"oj-italic\">acquis</span> in materia di rimpatrio, e riferiscono periodicamente alla sede centrale dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantiscono la gestione efficace delle attrezzature proprie dell'Agenzia nelle aree in cui essa svolge le sue attività, tra cui l'eventuale immatricolazione e manutenzione a lungo termine delle attrezzature e qualsiasi sostegno logistico necessario.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ogni ufficio antenna è gestito da un rappresentante dell'Agenzia nominato dal direttore esecutivo come capo dell'ufficio antenna. La persona nominata capo dell'ufficio antenna sovrintende ai lavori dell'ufficio e funge da punto di contatto unico con la sede centrale dell'Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio di amministrazione, su proposta del direttore esecutivo, decide circa l'istituzione, la composizione, la durata e l'eventuale proroga della durata del funzionamento di un ufficio antenna, tenuto conto del parere della Commissione e dell'accordo dello Stato membro ospitante o dello Stato terzo ospitante.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Lo Stato membro ospitante fornisce assistenza all'Agenzia per garantirne la capacità operativa.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il direttore esecutivo riferisce con cadenza trimestrale al consiglio di amministrazione in merito alle attività degli uffici antenna. Le attività degli uffici antenna sono descritte in una sezione distinta della relazione annuale di attività.</p>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Sostegno finanziario per lo sviluppo del corpo permanente", "anchor": "art_61", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Allo scopo di sostenere lo sviluppo delle risorse umane per garantire il proprio contributo al corpo permanente di cui agli allegati II, III e IV, gli Stati membri hanno diritto di ricevere su base annua fondi sotto forma di finanziamenti non collegati ai costi, a norma dell'articolo 125, paragrafo 1, lettera a), del regolamento (UE, Euratom) 2018/1046, erogabili una volta terminato l'esercizio interessato e nel rispetto delle condizioni di cui ai paragrafi 3 e 4 del presente articolo. I finanziamenti sono basati su un importo di riferimento ai sensi del paragrafo 2 del presente articolo e, se del caso, sono pari:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">al 100 % dell'importo di riferimento moltiplicato per il numero di membri del personale operativo indicati per l'anno N+2 per il distacco ai sensi dell'allegato II;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">al 37 % dell'importo di riferimento moltiplicato per il numero di membri del personale operativo effettivamente impiegati ai sensi dell'articolo 57 entro i limiti stabiliti dall'allegato III e ai sensi dell'articolo 58 entro i limiti stabiliti dall'allegato IV, se del caso;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un pagamento una tantum pari al 50 % dell'importo di riferimento moltiplicato per il numero di membri del personale operativo assunti dall'Agenzia come personale statutario. Tale pagamento si applica al personale proveniente dai servizi nazionali che non ha svolto più di 15 anni di servizio attivo al momento dell'assunzione da parte dell'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'importo di riferimento è equivalente allo stipendio base annuale di un agente contrattuale, gruppo di funzioni III, grado 8, scatto 1, di cui all'articolo 93 del regime applicabile agli altri agenti dell'Unione e soggetto a un coefficiente di correzione applicabile nello Stato membro interessato.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il pagamento annuale dell'importo di cui al paragrafo 1, lettera a), del presente articolo avviene a condizione che gli Stati membri aumentino conseguentemente gli effettivi complessivi delle loro rispettive guardie di frontiera nazionali attraverso l'assunzione di nuovo personale nel periodo interessato. Le informazioni rilevanti ai fini della rendicontazione sono fornite all'Agenzia nell'ambito dei negoziati bilaterali annuali e verificate tramite la valutazione delle vulnerabilità l'anno successivo. Il pagamento annuale dell'importo di cui al paragrafo 1, lettera b), del presente articolo avviene per intero in relazione al numero di membri del personale effettivamente impiegati per un periodo consecutivo o non consecutivo di quattro mesi ai sensi dell'articolo 57 entro i limiti stabiliti dall'allegato III e dell'articolo 58 entro i limiti stabiliti dall'allegato IV. Per gli impieghi effettivi di cui al paragrafo 1, lettera b), del presente articolo, i pagamenti sono calcolati proporzionalmente a un periodo di riferimento di quattro mesi.</p>\n<p class=\"oj-normal\">L'Agenzia concede un pagamento anticipato legato ai pagamenti annuali degli importi di cui al paragrafo 1, lettere a) e b), del presente articolo in conformità dell'atto di esecuzione di cui al paragrafo 4 del presente articolo, a seguito della presentazione di una richiesta specifica e motivata da parte dello Stato membro contribuente.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione adotta un atto di esecuzione che stabilisce norme dettagliate sul pagamento annuale e sul controllo delle condizioni applicabili di cui al paragrafo 3 del presente articolo. Tali norme comprendono meccanismi per i pagamenti anticipati ove siano soddisfatte le condizioni di cui al paragrafo 3 del presente articolo, e le modalità dei calcoli proporzionali, incluso nei casi in cui l'impiego del personale tecnico eccederebbe in via eccezionale i contributi nazionali massimi previsti nell'allegato III. Tale atto di esecuzione è adottato secondo la procedura di esame di cui all'articolo 122, paragrafo 2.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Nell'attuare il sostegno finanziario a norma del presente articolo, l'Agenzia e gli Stati membri garantiscono il rispetto dei principi di cofinanziamento e divieto del doppio finanziamento.</p>\n</div>"]]}, "62": {"label": "Articolo 62", "heading": "Formazione", "anchor": "art_62", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, tenendo conto della tabella di marcia relativa alle capacità di cui all'articolo 9, paragrafo 8, ove disponibile, e in cooperazione con i competenti organi di formazione degli Stati membri e, se del caso, l'EASO, la FRA, l'Agenzia dell'Unione europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia (euLISA) e l'Agenzia dell'Unione europea per la formazione delle autorità di contrasto (CEPOL), sviluppa specifici strumenti formativi, incluse formazioni specifiche in materia di protezione dei minori e di altre persone vulnerabili. I contenuti delle formazioni tengono conto dei risultati delle ricerche pertinenti e delle migliori prassi. L'Agenzia fornisce alle guardie di frontiera, agli esperti in materia di rimpatrio, alle scorte per i rimpatri e ad altri membri del personale che fanno parte del corpo permanente, nonché agli osservatori per i rimpatri forzati e agli osservatori dei diritti fondamentali formazioni specialistiche in relazione ai loro compiti e alle loro competenze. L'Agenzia svolge esercitazioni periodiche con dette guardie di frontiera e altri membri delle squadre secondo il calendario della formazione specialistica stabilito nel programma di lavoro annuale dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia garantisce che, oltre alla formazione di cui all'articolo 55, paragrafo 3, prima del suo impiego iniziale nelle attività operative organizzate dall'Agenzia, tutti i membri del personale statutario che saranno impiegati quali membri delle squadre abbiano ricevuto un'adeguata formazione sul pertinente diritto dell'Unione e internazionale, compresi i diritti fondamentali, l'accesso alla protezione internazionale, gli orientamenti intesi a consentire l'identificazione delle persone che chiedono protezione e a indirizzarle verso le procedure appropriate, gli orientamenti volti ad affrontare le particolari esigenze dei minori, compresi i minori non accompagnati, le vittime della tratta di esseri umani, le persone bisognose di assistenza medica urgente e altre persone particolarmente vulnerabili, e, nel caso in cui sia prevista la loro partecipazione a operazioni marittime, la ricerca e il soccorso.</p>\n<p class=\"oj-normal\">Tale formazione riguarda anche l'uso della forza ai sensi dell'allegato V.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ai fini del paragrafo 2, l'Agenzia, sulla base di accordi con Stati membri prescelti, attua i necessari programmi di formazione negli istituti specializzati di istruzione e formazione di tali Stati membri, comprese le scuole partner dell'Agenzia negli Stati membri. L'Agenzia garantisce che la formazione segua il programma comune di base, sia armonizzata e promuova la comprensione reciproca nonché una cultura comune sulla base dei valori sanciti dai trattati. Il costo della formazione è interamente coperto dall'Agenzia.</p>\n<p class=\"oj-normal\">Dopo aver ottenuto l'approvazione del consiglio di amministrazione, l'Agenzia può istituire un proprio centro di formazione per agevolare ulteriormente l'inclusione di una cultura europea comune nella formazione offerta.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia adotta le iniziative necessarie per assicurare che, prima di partecipare alle attività organizzate dall'Agenzia, tutti i membri del personale degli Stati membri che fanno parte delle squadre del corpo permanente abbiano ricevuto la formazione di cui al paragrafo 2, primo comma.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia adotta le iniziative necessarie al fine di assicurare la formazione del personale che assolve a compiti attinenti ai rimpatri e che farà parte del corpo permanente o della riserva di cui all'articolo 51. L'Agenzia assicura che, prima di partecipare alle attività operative organizzate dall'Agenzia, il personale statutario e tutti i membri del personale che partecipano alle operazioni di rimpatrio o agli interventi di rimpatrio abbiano ricevuto una formazione sul pertinente diritto dell'Unione e internazionale, compresi i diritti fondamentali, l'accesso alla protezione internazionale e l'indirizzamento delle persone vulnerabili.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'Agenzia crea e sviluppa un programma comune di base per la formazione delle guardie di frontiera e offre formazione a livello europeo per gli istruttori delle guardie di frontiera degli Stati membri, anche in materia di diritti fondamentali, accesso alla protezione internazionale e pertinente diritto del mare, così come un programma comune per la formazione del personale che assolve a compiti attinenti al rimpatrio. Il programma comune di base mira a promuovere gli standard più elevati e le migliori prassi nell'attuazione del diritto dell'Unione in materia di gestione delle frontiere e di rimpatri. L'Agenzia redige il programma comune di base previa consultazione del forum consultivo di cui all'articolo 108 («forum consultivo») e del responsabile dei diritti fondamentali. Gli Stati membri integrano tale programma comune di base nei corsi di formazione organizzati per le rispettive guardie di frontiera nazionali e il personale che partecipa a compiti attinenti ai rimpatri.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia offre inoltre al personale dei servizi competenti degli Stati membri e, se del caso, di paesi terzi, corsi e seminari di formazione supplementari su temi riguardanti il controllo delle frontiere esterne e il rimpatrio dei cittadini di paesi terzi.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia può organizzare attività di formazione in cooperazione con gli Stati membri e i paesi terzi nel loro territorio.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L'Agenzia istituisce un programma di scambi inteso a consentire alle guardie di frontiera che partecipano alle sue squadre e al personale che prende parte alle squadre di intervento per i rimpatri di <span class=\"oj-italic\">acquis</span>ire conoscenze o competenze specifiche grazie alle esperienze e alle buone prassi applicate all'estero, lavorando con le guardie di frontiera e il personale coinvolto in compiti attinenti ai rimpatri in uno Stato membro diverso dal proprio.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   L'Agenzia istituisce e sviluppa ulteriormente un meccanismo di controllo della qualità interno per garantire un elevato livello di formazione, competenza e professionalità del personale statutario, in particolare del personale statutario che partecipa alle attività operative dell'Agenzia. Sulla base dell'attuazione del meccanismo di controllo della qualità, l'Agenzia elabora una relazione di valutazione annuale che è allegata alla relazione annuale delle attività.</p>\n</div>"]]}, "63": {"label": "Articolo 63", "heading": "acquisto o noleggio di attrezzatura tecnica", "anchor": "art_63", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può <span class=\"oj-italic\">acquis</span>tare, autonomamente o in comproprietà con uno Stato membro, o noleggiare, attrezzatura tecnica da mettere a disposizione durante operazioni congiunte, progetti pilota, interventi rapidi alle frontiere, attività nel settore del rimpatrio, compresi operazioni di rimpatrio e interventi di rimpatrio, impiego di squadre di sostegno per la gestione della migrazione o progetti di assistenza tecnica, conformemente alle regole finanziarie applicabili all'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su proposta del direttore esecutivo, il consiglio di amministrazione adotta una strategia pluriennale globale sul modo in cui occorre sviluppare le capacità tecniche dell'Agenzia, tenuto conto del ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere, comprese la tabella di marcia relativa alle capacità di cui all'articolo 9, paragrafo 8, se disponibile, e le risorse di bilancio rese disponibili a tale scopo nell'ambito del quadro finanziario pluriennale. Per garantire il rispetto dei quadri applicabili sul piano giuridico, finanziario e politico, il direttore esecutivo formula tale proposta solo dopo aver ricevuto il parere favorevole della Commissione.</p>\n<p class=\"oj-normal\">La strategia pluriennale è accompagnata da un piano d'attuazione dettagliato che specifica i tempi per l'<span class=\"oj-italic\">acquis</span>to o il noleggio, la pianificazione degli appalti e l'attenuazione dei rischi. Se il consiglio di amministrazione, nell'adottare la strategia e il piano, decide di discostarsi dal parere della Commissione, fornisce alla Commissione una giustificazione al riguardo. Dopo l'adozione della strategia pluriennale, il piano d'attuazione diventa parte della programmazione pluriennale contenuta nel documento unico di programmazione di cui all'articolo 100, paragrafo 2, lettera k).</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia può <span class=\"oj-italic\">acquis</span>tare attrezzature tecniche su decisione del direttore esecutivo in consultazione con il consiglio di amministrazione conformemente alle norme applicabili in materia d'appalti. L'<span class=\"oj-italic\">acquis</span>to o il noleggio di attrezzature comportanti costi ingenti a carico dell'Agenzia sono preceduti da un'attenta analisi costi-benefici e del fabbisogno. Ogni spesa relativa a tale <span class=\"oj-italic\">acquis</span>to o noleggio è iscritta nel bilancio dell'Agenzia adottato dal consiglio di amministrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ove l'Agenzia <span class=\"oj-italic\">acquis</span>ti o noleggi attrezzature tecniche di grande rilievo, come aerei, veicoli di servizio o navi, si applicano le seguenti condizioni:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in caso di <span class=\"oj-italic\">acquis</span>to da parte dell'Agenzia o di comproprietà, l'Agenzia concorda con uno Stato membro che esso provveda all'immatricolazione dell'attrezzatura quale adibita a un servizio pubblico ai sensi del diritto applicabile di tale Stato membro, comprese le prerogative e le immunità previste dal diritto internazionale per tale attrezzatura tecnica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in caso di noleggio, l'attrezzatura è immatricolata in uno Stato membro.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sulla base di un modello di accordo redatto dall'Agenzia e approvato dal consiglio di amministrazione, lo Stato membro di immatricolazione e l'Agenzia stabiliscono di comune accordo le modalità che garantiscono l'interoperabilità dell'attrezzatura. In caso di risorse in comproprietà, le modalità includono anche i periodi di piena disponibilità delle risorse per l'Agenzia e determinano le condizioni d'uso di tali risorse, comprese le disposizioni specifiche sull'invio rapido durante gli interventi rapidi alle frontiere, e il finanziamento di tali risorse.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Qualora l'Agenzia non disponga del personale statutario qualificato richiesto, lo Stato membro di immatricolazione o il fornitore dell'attrezzatura tecnica mette a disposizione gli esperti e il personale tecnico necessari per un uso dell'attrezzatura tecnica nel rispetto delle norme e in sicurezza, conformemente al modello di accordo di cui al paragrafo 5 del presente articolo e basando la programmazione sui negoziati bilaterali annuali e sugli accordi di cui all'articolo 64, paragrafo 9. In tal caso, l'attrezzatura tecnica di proprietà esclusiva dell'Agenzia è messa a disposizione dell'Agenzia su richiesta della stessa, e lo Stato membro di registrazione non può invocare la situazione eccezionale di cui all'articolo 64, paragrafo 9.</p>\n<p class=\"oj-normal\">Quando chiede a uno Stato membro di fornire attrezzatura tecnica e personale, l'Agenzia tiene conto delle particolari sfide operative che lo Stato membro affronta al momento della richiesta.</p>\n</div>"]]}, "64": {"label": "Articolo 64", "heading": "Parco attrezzature tecniche", "anchor": "art_64", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia crea e conserva registri centralizzati del parco attrezzature tecniche comprendente l'attrezzatura di proprietà degli Stati membri o dell'Agenzia e l'attrezzatura in comproprietà degli Stati membri e dell'Agenzia utilizzate per le sue attività operative.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'attrezzatura di proprietà esclusiva dell'Agenzia è pienamente disponibile ai fini dell'impiego in qualunque momento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'attrezzatura detenuta in comproprietà dall'Agenzia per una quota superiore al 50 % è anch'essa disponibile ai fini dell'impiego conformemente a un accordo tra uno Stato membro e l'Agenzia, concluso a norma dell'articolo 63, paragrafo 5.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia assicura la compatibilità e l'interoperabilità dell'attrezzatura elencata nel parco attrezzature tecniche.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Ai fini del paragrafo 4 l'Agenzia, in stretta cooperazione con gli Stati membri e la Commissione, definisce gli standard tecnici per l'attrezzatura che dev'essere impiegata nelle attività dell'Agenzia, se necessario. L'attrezzatura <span class=\"oj-italic\">acquis</span>tata dall'Agenzia, in proprietà esclusiva o in comproprietà, e l'attrezzatura di proprietà degli Stati membri elencata nel parco attrezzature tecniche rispetta i suddetti standard.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Su proposta del direttore esecutivo, tenuto conto dell'analisi dei rischi effettuata dall'Agenzia e dei risultati delle valutazioni delle vulnerabilità, il consiglio di amministrazione decide, entro il 31 marzo di ogni anno, il numero minimo di attrezzature tecniche richieste in vista del fabbisogno dell'Agenzia dell'anno successivo, in particolare per quanto riguarda l'esecuzione di operazioni congiunte, l'impiego di squadre di sostegno per la gestione della migrazione, gli interventi rapidi alle frontiere, le attività nel settore del rimpatrio, inclusi le operazioni di rimpatrio e gli interventi di rimpatrio. Le attrezzature proprie dell'Agenzia sono incluse nel numero minimo di attrezzature tecniche. Tale decisione stabilisce le norme relative all'impiego delle attrezzature tecniche nelle attività operative.</p>\n<p class=\"oj-normal\">Se il numero minimo di attrezzature tecniche dovesse rivelarsi insufficiente per eseguire il piano operativo concordato per tali operazioni, l'Agenzia rivede tale numero minimo in funzione di esigenze giustificate e di un accordo con gli Stati membri.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il parco attrezzature tecniche è composto da un numero minimo di attrezzature identificate come necessarie all'Agenzia per tipo di attrezzatura tecnica. Le unità rientranti nel parco attrezzature tecniche sono utilizzate nell'ambito di operazioni congiunte, impiego di squadre di sostegno per la gestione della migrazione, progetti pilota, interventi rapidi alle frontiere, operazioni di rimpatrio o interventi di rimpatrio.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il parco attrezzature tecniche comprende una riserva di attrezzatura di reazione rapida che contiene un numero limitato di attrezzature necessarie per eventuali interventi rapidi alle frontiere. I contributi degli Stati membri alla riserva di attrezzatura di reazione rapida sono programmati conformemente ai negoziati e agli accordi annuali bilaterali di cui al paragrafo 9 del presente articolo. Relativamente all'attrezzatura indicata nell'elenco delle attrezzature di tale riserva, gli Stati membri non possono invocare la situazione eccezionale di cui al paragrafo 9 del presente articolo.</p>\n<p class=\"oj-normal\">Le attrezzature indicate in tale elenco, insieme ai necessari esperti e al personale tecnico, sono inviate a destinazione dallo Stato membro interessato, ai fini dell'impiego, quanto prima possibile e comunque entro 10 giorni dalla data in cui viene stabilito di comune accordo il piano operativo.</p>\n<p class=\"oj-normal\">L'Agenzia contribuisce a tale riserva con l'attrezzatura a sua disposizione di cui all'articolo 63, paragrafo 1.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Gli Stati membri contribuiscono al parco attrezzature tecniche. Questo loro contributo e l'impiego delle attrezzature tecniche per operazioni specifiche sono pianificati sulla base di negoziati e accordi annuali bilaterali tra l'Agenzia e gli Stati membri. Conformemente a tali accordi e nella misura in cui l'attrezzatura rientra nel numero minimo di attrezzature tecniche fornite per un anno determinato, gli Stati membri, su richiesta dell'Agenzia, rendono disponibile ai fini dell'impiego l'attrezzatura tecnica, a meno che si trovino a far fronte a una situazione eccezionale che incide in misura sostanziale sull'adempimento dei compiti nazionali. Qualora uno Stato membro invochi una tale situazione eccezionale, esso fornisce per iscritto all'Agenzia motivazioni e informazioni dettagliate sulla situazione, il cui contenuto sarà incluso nella relazione di cui all'articolo 65, paragrafo 1. La richiesta dell'Agenzia è inoltrata almeno 45 giorni prima dell'impiego previsto per l'attrezzatura tecnica di grande rilievo e 30 giorni prima dell'impiego previsto per l'altra attrezzatura. L'apporto al parco attrezzatura tecnica è soggetto a revisione annua.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Su proposta del direttore esecutivo, il consiglio di amministrazione decide su base annua le regole riguardanti l'attrezzatura tecnica, compreso il numero minimo complessivo richiesto per tipo di attrezzatura tecnica e le modalità di impiego e di rimborso dei costi, così come il numero limitato di attrezzature tecniche per la riserva di attrezzatura di reazione rapida. Per motivi di bilancio, la decisione è adottata dal consiglio di amministrazione entro il 31 marzo di ogni anno.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Se ha luogo un'operazione di intervento rapido alle frontiere, l'articolo 39, paragrafo 15, si applica di conseguenza.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   Ove necessità impreviste di attrezzatura tecnica per un'operazione congiunta o un intervento rapido alle frontiere emergano dopo la fissazione del numero minimo di attrezzature tecniche, e tali necessità non possano essere soddisfatte ricorrendo al parco attrezzature tecniche o alla riserva di attrezzatura di reazione rapida, gli Stati membri, laddove possibile, mettono a disposizione dell'Agenzia ai fini dell'impiego, su richiesta di quest'ultima e su una base ad hoc, l'attrezzatura tecnica necessaria.</p>\n</div>"], [13, "<div>\n<p class=\"oj-normal\">13.   Il direttore esecutivo riferisce periodicamente al consiglio di amministrazione circa la composizione e l'impiego dell'attrezzatura che fa parte del parco attrezzatura tecnica. Ove non sia raggiunto il numero minimo di attrezzature tecniche richieste per il parco, il direttore esecutivo ne informa immediatamente il consiglio di amministrazione. Il consiglio di amministrazione decide con urgenza l'ordine di priorità nell'impiego dell'attrezzatura tecnica e adotta opportune misure per correggere le carenze. Il consiglio di amministrazione comunica alla Commissione le carenze e le misure che ha adottato. La Commissione ne informa successivamente il Parlamento europeo e il Consiglio, esprimendo altresì la propria valutazione.</p>\n</div>"], [14, "<div>\n<p class=\"oj-normal\">14.   Gli Stati membri registrano nel parco attrezzatura tecnica tutti i mezzi di trasporto e l'attrezzatura operativa <span class=\"oj-italic\">acquis</span>tati nell'ambito delle azioni specifiche del Fondo sicurezza interna, ai sensi dell'articolo 7, paragrafo 1, del regolamento (UE) n. 515/2014 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">42</span>) o, se del caso, nell'ambito di qualsiasi altro futuro finanziamento specifico dell'Unione messo a disposizione degli Stati membri con il chiaro obiettivo di incrementare la capacità operativa dell'Agenzia. Tale attrezzatura tecnica rientra nel numero minimo di attrezzature tecniche fornite per un determinato anno.</p>\n<p class=\"oj-normal\">Su richiesta fatta dall'Agenzia nell'ambito dei negoziati bilaterali annuali, gli Stati membri mettono a disposizione dell'Agenzia ai fini dell'impiego l'attrezzatura tecnica cofinanziata nell'ambito delle azioni specifiche del Fondo sicurezza interna o nell'ambito di qualsiasi altro futuro finanziamento specifico dell'Unione di cui al primo comma del presente paragrafo. Ciascuna attrezzatura è messa a disposizione per un periodo massimo di quattro mesi conformemente a quanto previsto nell'ambito dei negoziati bilaterali annuali. Gli Stati membri possono decidere di impiegare la rispettiva attrezzatura oltre il periodo di quattro mesi. Nel caso di un'attività operativa di cui all'articolo 39 o 42 del presente regolamento, gli Stati membri non possono far valere la situazione eccezionale di cui al paragrafo 9 del presente articolo.</p>\n</div>"], [15, "<div>\n<p class=\"oj-normal\">15.   L'Agenzia gestisce il registro del parco attrezzatura tecnica come segue:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">classificazione per tipo di attrezzatura e per tipo di operazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">classificazione per proprietario (Stato membro, Agenzia, altro);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">numero complessivo delle attrezzature necessarie;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">requisiti relativi all'equipaggio, se applicabile;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre informazioni quali dati di immatricolazione, condizioni di trasporto e manutenzione, regimi nazionali di esportazione applicabili, istruzioni tecniche o altre informazioni necessarie per un uso appropriato dell'attrezzatura;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">menzione indicante se l'attrezzatura è stata finanziata con fondi dell'Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [16, "<div>\n<p class=\"oj-normal\">16.   L'Agenzia finanzia al 100 % l'impiego dell'attrezzatura tecnica rientrante nel numero minimo di attrezzature tecniche fornite da un determinato Stato membro per un anno determinato. L'impiego di attrezzatura tecnica che non rientra in tale numero minimo è cofinanziato dall'Agenzia fino a un massimo del 100 % delle spese ammissibili, tenendo conto delle particolari circostanze degli Stati membri che inviano detta attrezzatura tecnica.</p>\n</div>"]]}, "65": {"label": "Articolo 65", "heading": "Relazioni sulle capacità dell'Agenzia", "anchor": "art_65", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Su proposta del direttore esecutivo, il consiglio di amministrazione adotta e presenta al Parlamento europeo, al Consiglio e alla Commissione una relazione annuale sull'attuazione degli articoli 51, 55, 56, 57, 58, 63 e 64 («relazione annuale sull'attuazione»).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La relazione annuale sull'attuazione contiene in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il numero di membri del personale che ciascuno Stato membro ha destinato al corpo permanente, anche attraverso la riserva di reazione rapida, e alla riserva di osservatori per i rimpatri forzati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il numero di membri del personale statutario che l'Agenzia ha destinato al corpo permanente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il numero di membri del personale del corpo permanente effettivamente impiegati da ciascuno Stato membro e dall'Agenzia, per profilo, nell'anno precedente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il numero di attrezzature tecniche che ciascuno Stato membro e l'Agenzia hanno destinato al parco attrezzature tecniche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il numero di attrezzature tecniche del parco attrezzature tecniche che ciascuno Stato membro e l'Agenzia hanno impiegato nell'anno precedente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le destinazioni a favore della riserva di attrezzatura di reazione rapida e il suo impiego;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo sviluppo delle capacità umane e tecniche proprie dell'Agenzia.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La relazione annuale sull'attuazione elenca gli Stati membri che hanno invocato la situazione eccezionale di cui all'articolo 57, paragrafo 9, e all'articolo 64, paragrafo 9, nel corso dell'anno precedente e include le motivazioni e le informazioni fornite dallo Stato membro interessato.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Per garantire la trasparenza, il direttore esecutivo informa il consiglio di amministrazione con cadenza trimestrale sugli elementi elencati al paragrafo 2 in relazione all'anno in corso.</p>\n</div>"]]}, "66": {"label": "Articolo 66", "heading": "Ricerca e innovazione", "anchor": "art_66", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia provvede proattivamente a monitorare le attività di ricerca e di innovazione pertinenti per la gestione europea integrata delle frontiere, compreso l'utilizzo di avanzate tecnologie di controllo di frontiera, e a contribuirvi, tenendo conto della tabella di marcia relativa alle capacità di cui all'articolo 9, paragrafo 8. L'Agenzia provvede a divulgare i risultati di tali ricerche al Parlamento europeo, agli Stati membri e alla Commissione ai sensi dell'articolo 92. Tali risultati possono essere utilizzati nel modo opportuno in operazioni congiunte, interventi rapidi alle frontiere, operazioni di rimpatrio e interventi di rimpatrio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia, tenendo conto della tabella di marcia relativa alle capacità di cui all'articolo 9, paragrafo 8, assiste gli Stati membri e la Commissione nell'identificazione dei principali temi di ricerca. L'Agenzia assiste gli Stati membri e la Commissione nell'elaborazione e nell'attuazione dei pertinenti programmi quadro dell'Unione per le attività di ricerca e innovazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia attua le parti del programma quadro per la ricerca e l'innovazione che riguardano la sicurezza delle frontiere. A tal fine, e qualora la Commissione le abbia delegato i pertinenti poteri, l'Agenzia svolge i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestione di alcune fasi di attuazione del programma e di alcune fasi della vita di progetti specifici sulla base dei pertinenti programmi di lavoro adottati dalla Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adozione degli atti di esecuzione del bilancio delle entrate e delle spese ed esecuzione di tutte le operazioni necessarie alla gestione del programma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostegno all'attuazione del programma.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Agenzia può pianificare e attuare progetti pilota concernenti le materie oggetto del presente regolamento.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia rende pubbliche le informazioni sui suoi progetti di ricerca, compresi i progetti di dimostrazione, i partner della cooperazione partecipanti e il bilancio dei progetti.</p>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Unità centrale ETIAS", "anchor": "art_67", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia assicura l'istituzione e il funzionamento dell'unità centrale ETIAS di cui all'articolo 7 del regolamento (UE) 2018/1240.</p>"]]}, "68": {"label": "Articolo 68", "heading": "Cooperazione dell'Agenzia con le istituzioni, gli organi, gli uffici e le agenzie dell'Unione e con le organizzazioni internazionali", "anchor": "art_68", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia coopera con le istituzioni, gli organi, gli uffici e le agenzie dell'Unione e può cooperare con le organizzazioni internazionali, nell'ambito dei rispettivi quadri giuridici, e utilizza le informazioni, le risorse e i sistemi esistenti disponibili nell'ambito di Eurosur.</p>\n<p class=\"oj-normal\">A norma del primo comma, l'Agenzia coopera in particolare con:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la Commissione e il Servizio europeo per l'azione esterna (SEAE);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Europol;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'EASO,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">FRA;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Eurojust;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il Centro satellitare dell'Unione europea;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">EFCA ed EMSA;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">eu-LISA;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'Agenzia dell'Unione europea per la sicurezza aerea (AESA) e il gestore della rete europea di gestione del traffico aereo (EATMN);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le missioni e operazioni PESD, in funzione dei loro mandati al fine di garantire quanto segue:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la promozione delle norme in materia di gestione europea integrata delle frontiere,</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">conoscenza situazionale e analisi dei rischi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">L'Agenzia può altresì cooperare con le seguenti organizzazioni internazionali pertinenti all'assolvimento dei suoi compiti, nell'ambito dei rispettivi quadri giuridici:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le Nazioni Unite tramite i pertinenti uffici, agenzie, organizzazioni e altri soggetti, in particolare l'Alto Commissariato delle Nazioni Unite per i rifugiati, l'Alto commissariato per i diritti umani, l'Organizzazione internazionale per le migrazioni, l'Ufficio delle Nazioni Unite contro la droga e il crimine e l'Organizzazione dell'aviazione civile internazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'Organizzazione internazionale della polizia criminale (Interpol);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'Organizzazione per la sicurezza e la cooperazione in Europa;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il Consiglio d'Europa e il commissario per i diritti dell'uomo del Consiglio d'Europa;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il Centro di analisi e operazioni contro il narcotraffico marittimo (MAOC-N).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La cooperazione di cui al paragrafo 1 si svolge nell'ambito di accordi di lavoro conclusi con gli organi di cui al paragrafo 1. Tali accordi sono soggetti all'approvazione preliminare della Commissione. L'Agenzia informa il Parlamento europeo e il Consiglio in merito a tali accordi.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Per quanto riguarda il trattamento delle informazioni classificate, gli accordi di lavoro di cui al paragrafo 2 prevedono che l'organo, l'ufficio o l'agenzia dell'Unione o l'organizzazione internazionale interessati rispettino regole e norme di sicurezza equivalenti a quelle applicate dall'Agenzia. Prima della conclusione dell'accordo è effettuata una visita di valutazione e la Commissione è informata dell'esito di tale visita.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Sebbene al di fuori dell'ambito di applicazione del presente regolamento, l'Agenzia coopera altresì con la Commissione e, laddove pertinente, con gli Stati membri e con il SEAE in attività relative al settore doganale, compresa la gestione del rischio, qualora tali attività si sostengano a vicenda. Tale cooperazione lascia impregiudicate le competenze esistenti della Commissione, dell'alto rappresentante dell'Unione per gli affari esteri e la politica di sicurezza e degli Stati membri.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le istituzioni, gli organi, gli uffici e le agenzie dell'Unione e le organizzazioni internazionali di cui al paragrafo 1 usano le informazioni ricevute dall'Agenzia esclusivamente entro i limiti delle loro competenze e fintanto che rispettino i diritti fondamentali, compresi gli obblighi di protezione dei dati.</p>\n<p class=\"oj-normal\">Qualsiasi trasmissione di dati personali trattati dall'Agenzia ad altre istituzioni, organi, uffici e agenzie dell'Unione di cui all'articolo 87, paragrafo 1, lettere c) e d), è soggetta ad accordi operativi specifici riguardanti lo scambio di dati personali.</p>\n<p class=\"oj-normal\">Gli accordi operativi di cui al secondo comma includono una disposizione volta a garantire che i dati personali trasmessi dall'Agenzia alle istituzioni, organi e organismi dell'Unione possano essere trattati per un'altra finalità soltanto previa autorizzazione dell'Agenzia e se tale finalità è compatibile con lo scopo iniziale per il quale i dati sono stati raccolti e trasmessi dall'Agenzia. Tali istituzioni, organi e organismi dell'Unione conservano registrazioni scritte di una valutazione della compatibilità caso per caso.</p>\n<p class=\"oj-normal\">Qualsiasi trasferimento di dati personali da parte dell'Agenzia alle organizzazioni internazionali di cui all'articolo 87, paragrafo 1, lettera c), rispetta le disposizioni in materia di protezione dei dati di cui al capo IV, sezione 2.</p>\n<p class=\"oj-normal\">In particolare, l'Agenzia provvede affinché qualsiasi accordo di lavoro concluso con organizzazioni internazionali riguardo allo scambio di dati personali ai sensi dell'articolo 87, paragrafo 1, lettera c), sia conforme al capo V del regolamento (UE) 2018/1725 e sia soggetto all'autorizzazione del Garante europeo della protezione dei dati, ove ciò sia previsto da tale regolamento.</p>\n<p class=\"oj-normal\">L'Agenzia provvede affinché i dati personali trasferiti a organizzazioni internazionali siano trattati esclusivamente ai fini per i quali sono stati trasferiti.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Lo scambio di informazioni tra l'Agenzia e le istituzioni, gli organi e gli organismi dell'Unione e le organizzazioni internazionali di cui al paragrafo 2 avviene tramite la rete di comunicazione di cui all'articolo 14 o attraverso altri sistemi di scambio di informazioni accreditati che rispondano ai criteri di disponibilità, riservatezza e integrità.</p>\n</div>"]]}, "69": {"label": "Articolo 69", "heading": "Cooperazione europea in materia di funzioni di guardia costiera", "anchor": "art_69", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fermo restando Eurosur, l'Agenzia, in cooperazione con l'EFCA e l'EMSA, sostiene le autorità nazionali che svolgono funzioni di guardia costiera a livello nazionale e dell'Unione e, ove opportuno, a livello internazionale:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">condividendo, integrando e analizzando le informazioni disponibili nei sistemi di segnalazione delle navi e altri sistemi di informazione ospitati da tali agenzie o accessibili alle stesse, in conformità delle rispettive basi giuridiche e fatta salva la titolarità dei dati da parte degli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornendo servizi di sorveglianza e di comunicazione mediante tecnologie avanzate, comprese infrastrutture terrestri e spaziali e sensori montati su qualsiasi tipo di piattaforma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">potenziando le capacità mediante l'elaborazione di orientamenti e raccomandazioni e instaurando migliori prassi, nonché fornendo formazione e scambio di personale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">migliorando lo scambio di informazioni e la cooperazione in materia di funzioni di guardia costiera, anche analizzando le sfide operative e i rischi emergenti nel settore marittimo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">condividendo le capacità mediante la pianificazione e realizzando operazioni multifunzionali mediante la condivisione di risorse e altre capacità, nella misura in cui tali attività siano coordinate da dette agenzie e siano approvate dalle autorità competenti degli Stati membri interessati.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le modalità dettagliate della cooperazione per quanto riguarda le funzioni di guardia costiera tra l'Agenzia, l'EFCA e l'EMSA sono stabilite in un accordo di lavoro, conformemente ai loro rispettivi mandati e alle regole finanziarie applicabili a tali agenzie. Tale accordo è approvato dal consiglio di amministrazione dell'Agenzia e dai consigli di amministrazione dell'EFCA e dell'EMSA. L'Agenzia, l'EFCA e l'EMSA usano le informazioni ricevute nell'ambito della loro cooperazione esclusivamente entro i limiti del rispettivo quadro giuridico e nel rispetto dei diritti fondamentali, compresi gli obblighi in materia di protezione dei dati.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione, in stretta cooperazione con gli Stati membri, con l'Agenzia, con l'EFCA e con l'EMSA, mette a disposizione un manuale pratico sulla cooperazione europea nelle funzioni di guardia costiera. Tale manuale contiene orientamenti, raccomandazioni e migliori prassi per lo scambio di informazioni. La Commissione adotta il manuale sotto forma di raccomandazione.</p>\n</div>"]]}, "70": {"label": "Articolo 70", "heading": "Cooperazione con l'Irlanda e il Regno Unito", "anchor": "art_70", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia agevola la cooperazione operativa tra gli Stati membri e l'Irlanda e il Regno Unito in attività specifiche.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ai fini di Eurosur, lo scambio di informazioni e la cooperazione con l'Irlanda e il Regno Unito possono avvenire sulla base di accordi bilaterali o multilaterali tra l'Irlanda o il Regno Unito rispettivamente e uno o più Stati membri vicini, o attraverso reti regionali basate su tali accordi. I centri nazionali di coordinamento rappresentano i punti di contatto per lo scambio di informazioni con le omologhe autorità dell'Irlanda e del Regno Unito nell'ambito di Eurosur.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli accordi di cui al paragrafo 2 sono limitati ai seguenti scambi di informazioni tra un centro nazionale di coordinamento e la corrispondente autorità dell'Irlanda o del Regno Unito:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni contenute nell'ambito situazionale nazionale di uno Stato membro nella misura in cui sono trasmesse all'Agenzia ai fini del quadro situazionale europeo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni raccolte dall'Irlanda o dal Regno Unito che siano utili ai fini dell'ambito situazionale europeo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informazioni di cui all'articolo 25, paragrafo 5.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le informazioni fornite nel contesto di Eurosur dall'Agenzia o da uno Stato membro che non sia parte di un accordo di cui al paragrafo 2 non devono essere condivise con l'Irlanda o il Regno Unito senza la previa approvazione dell'Agenzia o di tale Stato membro. Il rifiuto di condividere tali informazioni con l'Irlanda o il Regno Unito vincola gli Stati membri e l'Agenzia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sono vietate la trasmissione ulteriore o altra comunicazione di informazioni scambiate ai sensi del presente articolo a paesi terzi o a parti terze.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli accordi di cui al paragrafo 2 comprendono disposizioni sui costi finanziari derivanti dalla partecipazione dell'Irlanda o del Regno Unito all'attuazione degli accordi stessi.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il sostegno che l'Agenzia offre ai sensi dell'articolo 10, paragrafo 1, lettere n), o) e p), comprende l'organizzazione di operazioni di rimpatrio di Stati membri a cui partecipino anche l'Irlanda o il Regno Unito.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'applicazione del presente regolamento alle frontiere di Gibilterra è sospesa fino alla data di conclusione di un accordo sulla portata delle disposizioni in materia di attraversamento delle frontiere esterne da parte delle persone.</p>\n</div>"]]}, "71": {"label": "Articolo 71", "heading": "Cooperazione con i paesi terzi", "anchor": "art_71", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri e l'Agenzia cooperano con i paesi terzi ai fini della gestione europea integrata delle frontiere e della politica in materia di migrazione a norma dell'articolo 3, paragrafo 1, lettera g).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Sulla base delle priorità politiche definite ai sensi dell'articolo 8, paragrafo 4, l'Agenzia fornisce assistenza tecnica e operativa ai paesi terzi nell'ambito della politica dell'Unione in materia di azione esterna, anche per quanto riguarda la protezione dei diritti fondamentali e dei dati personali e il principio di non respingimento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia e gli Stati membri osservano il diritto dell'Unione, tra cui norme e standard che fanno parte dell'<span class=\"oj-italic\">acquis</span> dell'Unione, anche quando la cooperazione con i paesi terzi avviene nel territorio di tali paesi terzi</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'instaurazione di una cooperazione con i paesi terzi mira a promuovere le norme in materia di gestione europea integrata delle frontiere.</p>\n</div>"]]}, "72": {"label": "Articolo 72", "heading": "Cooperazione degli Stati membri con i paesi terzi", "anchor": "art_72", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri possono cooperare a livello operativo con uno o più paesi terzi nelle materie disciplinate dal presente regolamento. Tale cooperazione può comprendere lo scambio di informazioni e può avvenire sulla base di accordi bilaterali o multilaterali o altre modalità, o attraverso reti regionali istituite in base a detti accordi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel concludere gli accordi bilaterali e multilaterali di cui al paragrafo 1 del presente articolo, gli Stati membri possono includere disposizioni relative allo scambio di informazioni e alla cooperazione ai fini di Eurosur ai sensi dell'articolo 75 e all'articolo 89.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli accordi bilaterali e multilaterali e altre modalità di cui al paragrafo 1 sono conformi al diritto dell'Unione e internazionale in materia di diritti fondamentali e protezione internazionale, inclusa la Carta, la convenzione europea per la salvaguardia dei diritti dell'uomo e delle libertà fondamentali e la convenzione del 1951 relativa allo status dei rifugiati e il relativo protocollo del 1967, e, in particolare, il principio di non respingimento. Nell'attuare tali accordi e modalità, gli Stati membri valutano con cadenza periodica la situazione generale nel paese terzo e ne tengono conto, anche alla luce dell'articolo 8.</p>\n</div>"]]}, "73": {"label": "Articolo 73", "heading": "Cooperazione fra l'Agenzia e i paesi terzi", "anchor": "art_73", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può, nella misura necessaria per l'espletamento dei suoi compiti, cooperare con le autorità di paesi terzi competenti per questioni contemplate nel presente regolamento. L'Agenzia rispetta il diritto dell'Unione, comprese le norme e gli standard che fanno parte dell'<span class=\"oj-italic\">acquis</span> dell'Unione, anche quando la cooperazione con i paesi terzi ha luogo sul territorio di tali paesi terzi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel cooperare con le autorità di paesi terzi di cui al paragrafo 1 del presente articolo, l'Agenzia agisce nell'ambito della politica dell'Unione in materia di azione esterna, anche con riferimento alla protezione dei diritti fondamentali e dei dati personali, al principio di non respingimento, al divieto di trattenimento arbitrario e al divieto di tortura e di trattamenti o pene inumani o degradanti, con il supporto delle delegazioni dell'Unione, se del caso, delle missioni e operazioni PSDC, e di concerto con esse, ai sensi dell'articolo 68, paragrafo 1, secondo comma, lettera j).</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In circostanze che richiedono l'invio di squadre per la gestione delle frontiere attinte dal corpo permanente in un paese terzo in cui i membri delle squadre eserciteranno poteri esecutivi, l'Unione conclude con il paese terzo interessato, ai sensi dell'articolo 218 del trattato sul funzionamento dell'Unione europea (TFUE), un accordo sullo status elaborato sulla base del modello di accordo sullo status di cui all'articolo 76, paragrafo 1. Tale accordo sullo status riguarda tutti gli aspetti necessari all'esecuzione delle attività. Esso stabilisce in particolare l'ambito dell'operazione, disposizioni in materia di responsabilità civile e penale e i compiti e le competenze dei membri delle squadre, le misure relative all'istituzione di un ufficio antenna e le misure concrete relative al rispetto dei diritti fondamentali. L'accordo sullo status garantisce il pieno rispetto dei diritti fondamentali nel corso di tali operazioni e prevede un meccanismo di denuncia. Il Garante europeo della protezione dei dati è consultato in merito alle disposizioni dell'accordo sullo status relative ai trasferimenti di dati qualora esse differiscano sostanzialmente dal modello di accordo sullo status.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ove disponibili, l'Agenzia agisce inoltre nell'ambito di accordi di lavoro conclusi con le autorità dei paesi terzi di cui al paragrafo 1 del presente articolo, conformemente al diritto e alle politiche dell'Unione, ai sensi dell'articolo 76, paragrafo 4.</p>\n<p class=\"oj-normal\">Gli accordi operativi di cui al primo comma del presente paragrafo precisano la portata, la natura e la finalità della cooperazione, sono connessi alla gestione della cooperazione operativa. Tali accordi operativi possono includere disposizioni riguardanti lo scambio di informazioni sensibili non classificate e la cooperazione nell'ambito di Eurosur ai sensi dell'articolo 74, paragrafo 3.</p>\n<p class=\"oj-normal\">L'Agenzia provvede affinché i paesi terzi a cui sono trasferite tali informazioni le trattino esclusivamente ai fini per i quali sono stati trasferite. Gli accordi operativi sullo scambio di informazioni classificate sono conclusi a norma dell'articolo 76, paragrafo 4, del presente regolamento. L'Agenzia chiede l'autorizzazione preventiva del Garante europeo della protezione dei dati, nella misura in cui tali accordi di lavoro prevedano il trasferimento dei dati personali e ove previsto dal regolamento (UE) 2018/1725.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia contribuisce all'attuazione della politica esterna dell'Unione in materia di rimpatrio e di riammissione nell'ambito della politica dell'Unione in materia di azione esterna e per quanto riguarda i settori contemplati dal presente regolamento.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   L'Agenzia può ricevere un finanziamento dell'Unione ai sensi delle disposizioni dei pertinenti strumenti che sostengono i paesi terzi e delle attività a essi connesse. L'Agenzia può varare e finanziare progetti di assistenza tecnica nei paesi terzi per le materie oggetto del presente regolamento e conformemente alle regole finanziarie a essa applicabili. Tali progetti sono inclusi nel documento unico di programmazione di cui all'articolo 102.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   L'Agenzia informa il Parlamento europeo, il Consiglio e la Commissione in merito alle attività espletate ai sensi del presente articolo e, in particolare, alle attività connesse all'assistenza tecnica e operativa nel settore della gestione delle frontiere e dei rimpatri nei paesi terzi e all'impiego di funzionari di collegamento, e fornisce loro informazioni dettagliate sul rispetto dei diritti fondamentali. L'Agenzia rende pubblici gli accordi, gli accordi di lavoro, i progetti pilota e i progetti di assistenza tecnica con i paesi terzi a norma dell'articolo 114, paragrafo 2.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   L'Agenzia include nelle sue relazioni annuali una valutazione della cooperazione con i paesi terzi.</p>\n</div>"]]}, "74": {"label": "Articolo 74", "heading": "Assistenza tecnica e operativa fornita dall'Agenzia ai paesi terzi", "anchor": "art_74", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può coordinare la cooperazione operativa tra gli Stati membri e i paesi terzi e fornire assistenza tecnica e operativa ai paesi terzi nell'ambito della gestione europea integrata delle frontiere.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia può effettuare interventi relativi alla gestione europea integrata delle frontiere nel territorio di un paese terzo previo accordo di tale paese terzo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le operazioni nel territorio di un paese terzo sono incluse nel programma di lavoro annuale adottato dal consiglio di amministrazione ai sensi dell'articolo 102 e sono effettuate sulla base di un piano operativo concordato fra l'Agenzia e il paese terzo interessato e in consultazione con gli Stati membri partecipanti. Nel caso in cui uno o più Stato membri siano situati in prossimità del paese terzo o siano confinanti con l'area operativa del paese terzo, il piano operativo e le relative modifiche sono soggetti all'accordo di tale Stato membro o di tali Stati membri. Gli articoli 38, 43, 46, 47 e da 54 a 57 si applicano, <span class=\"oj-italic\">mutatis mutandis</span>, a impieghi nei paesi terzi.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo garantisce la sicurezza del personale impiegato nei paesi terzi.</p>\n<p class=\"oj-normal\">Ai fini del primo comma, gli Stati membri informano il direttore esecutivo di qualsiasi preoccupazione relativa alla sicurezza dei loro cittadini, nel caso in cui siano impiegati sul territorio di determinati paesi terzi.</p>\n<p class=\"oj-normal\">Ove non sia possibile garantire la sicurezza di un membro del personale impiegato in un paese terzo, il direttore esecutivo adotta le opportune misure mediante la sospensione o la cessazione dei corrispondenti aspetti dell'assistenza tecnica e operativa fornita dall'Agenzia a tale paese terzo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fatto salvo l'invio di membri del corpo permanente ai sensi degli articoli da 54 a 58, gli Stati membri partecipano alle operazioni nel territorio di un paese terzo su base volontaria.</p>\n<p class=\"oj-normal\">Oltre al meccanismo pertinente di cui all'articolo 57, paragrafo 9, e al paragrafo 4 del presente articolo, qualora la sicurezza del personale partecipante non possa essere garantita in modo soddisfacente per lo Stato membro interessato, tale Stato membro può non contribuire all'operazione nel paese terzo in questione. Qualora uno Stato membro faccia valere una tale situazione eccezionale, esso fornisce per iscritto all'Agenzia, nel corso dei negoziati bilaterali annuali o almeno 21 giorni prima dell'invio, motivazioni e informazioni dettagliate sulla situazione, il cui contenuto dev'essere incluso nella relazione di cui all'articolo 65. L'impiego di personale distaccato a norma dell'articolo 56 è soggetto al consenso dello Stato membro di appartenenza, comunicato previa notifica da parte dell'Agenzia e almeno 21 giorni prima dell'invio.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   I piani operativi di cui al paragrafo 3 possono includere disposizioni relative allo scambio di informazioni e alla cooperazione ai fini di Eurosur ai sensi degli articoli 75 e 89.</p>\n</div>"]]}, "75": {"label": "Articolo 75", "heading": "Scambio di informazioni con i paesi terzi nell'ambito di Eurosur", "anchor": "art_75", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I centri nazionali di coordinamento, e, se del caso, l'Agenzia rappresentano i punti di contatto per lo scambio di informazioni e la cooperazione con i paesi terzi ai fini di Eurosur.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le disposizioni relative allo scambio di informazioni e alla cooperazione ai fini di Eurosur contenute negli accordi bilaterali o multilaterali di cui all'articolo 72, paragrafo 2, affrontano:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli ambiti situazionali specifici condivisi con i paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i dati provenienti dai paesi terzi che possono essere condivisi nell'ambito situazionale europeo e le procedure per la condivisione di tali dati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le procedure e le condizioni per la fornitura dei servizi Eurosur per la fusione dei dati alle autorità dei paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le norme dettagliate riguardo alla cooperazione e allo scambio di informazioni con gli osservatori di paesi terzi ai fini di Eurosur.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le informazioni fornite nel contesto di Eurosur dall'Agenzia o da uno Stato membro che non sia parte di un accordo di cui all'articolo 72, paragrafo 1, non devono essere condivise con un paese terzo nell'ambito di tale accordo senza la previa approvazione dell'Agenzia o di tale Stato membro. Il rifiuto di condividere tali informazioni con il paese terzo interessato vincola gli Stati membri e l'Agenzia</p>\n</div>"]]}, "76": {"label": "Articolo 76", "heading": "Ruolo della Commissione nella cooperazione con i paesi terzi", "anchor": "art_76", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione, previa consultazione degli Stati membri, dell'Agenzia, di FRA e del Garante europeo della protezione dei dati, redige un modello di accordo sullo status in relazione alle attività condotte sul territorio di paesi terzi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione, in cooperazione con gli Stati membri e l'Agenzia, elabora le disposizioni tipo per lo scambio di informazioni nell'ambito di Eurosur ai sensi degli articoli 70, paragrafo 2, e 72, paragrafo 2.</p>\n<p class=\"oj-normal\">La Commissione, previa consultazione dell'Agenzia e di altri organi, uffici o agenzie dell'Unione pertinenti, tra cui la FRA e il Garante europeo della protezione dei dati, elabora un modello per gli accordi di lavoro di cui all'articolo 73, paragrafo 4. Tale modello include disposizioni relative ai diritti fondamentali e alle garanzie in materia di protezione dei dati che vertono su misure pratiche.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Prima che sia concluso un nuovo accordo bilaterale o multilaterale di cui all'articolo 72, paragrafo 1, gli Stati membri interessati notificano alla Commissione il progetto di disposizioni relative alla gestione delle frontiere e ai rimpatri.</p>\n<p class=\"oj-normal\">Gli Stati membri interessati notificano le disposizioni di tali accordi, esistenti o nuovi, bilaterali o multilaterali, relative alla gestione delle frontiere e ai rimpatri alla Commissione che ne informa il Consiglio e l'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Prima che siano approvati dal consiglio di amministrazione gli accordi operativi tra l'Agenzia e le autorità competenti di paesi terzi sono notificati dall'Agenzia alla Commissione, che dà l'autorizzazione preventiva. Prima della conclusione di un accordo di lavoro, l'Agenzia informa il Parlamento europeo, fornendo informazioni dettagliate riguardo alle parti dell'accordo di lavoro e al contenuto previsto.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia notifica alla Commissione i piani operativi di cui all'articolo 74, paragrafo 3. Qualunque decisione di inviare funzionari di collegamento in paesi terzi ai sensi dell'articolo 77 è soggetta al previo parere della Commissione. Il Parlamento europeo è tenuto informato tempestivamente e in modo esaustivo su tali attività.</p>\n</div>"]]}, "77": {"label": "Articolo 77", "heading": "Funzionari di collegamento nei paesi terzi", "anchor": "art_77", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può inviare nei paesi terzi esperti appartenenti al proprio personale statutario e altri esperti in qualità di funzionari di collegamento, i quali beneficiano della massima protezione nell'esercizio delle loro funzioni. Essi appartengono alle reti di cooperazione locale o regionale dei funzionari di collegamento incaricati dell'immigrazione e degli esperti della sicurezza dell'Unione e degli Stati membri, compresa la rete istituita a norma del regolamento (UE) 2019/1240. Con decisione del consiglio di amministrazione l'Agenzia può stabilire i profili specifici per i funzionari di collegamento, in funzione delle esigenze operative riguardo al paese terzo in questione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nell'ambito della politica dell'Unione in materia di azione esterna, è data priorità all'invio di funzionari di collegamento nei paesi terzi che sono, in base a un'analisi dei rischi, paesi di origine o di transito per l'immigrazione illegale. L'Agenzia può ricevere funzionari di collegamento distaccati da tali paesi terzi secondo un criterio di reciprocità. Il consiglio di amministrazione adotta, su base annuale, l'elenco delle priorità su proposta del direttore esecutivo. L'invio dei funzionari di collegamento è approvato dal consiglio di amministrazione previo parere della Commissione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Rientra tra i compiti dei funzionari di collegamento dell'Agenzia instaurare e mantenere contatti con le autorità competenti dei paesi terzi presso i quali sono distaccati, per contribuire alla prevenzione e alla lotta contro l'immigrazione illegale e al rimpatrio di rimpatriandi, anche fornendo assistenza tecnica per l'identificazione dei cittadini di paesi terzi e l'<span class=\"oj-italic\">acquis</span>izione dei documenti di viaggio. Tali compiti sono svolti nel rispetto del diritto dell'Unione e rispettano i diritti fondamentali. I funzionari di collegamento dell'Agenzia si coordinano strettamente con le delegazioni dell'Unione, con gli Stati membri a norma del regolamento (UE) 2019/1240 e, se del caso, con le missioni e operazioni PSDC di cui all'articolo 68, paragrafo 1, secondo comma, lettera j). Ove possibile, gli uffici loro assegnati si trovano negli stessi locali delle delegazioni dell'Unione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nei paesi terzi in cui non invia funzionari di collegamento per i rimpatri, l'Agenzia può sostenere uno Stato membro ai fini dell'invio di un funzionario di collegamento per i rimpatri, il quale presta supporto sia agli Stati membri che alle attività dell'Agenzia, ai sensi dell'articolo 48.</p>\n</div>"]]}, "78": {"label": "Articolo 78", "heading": "Osservatori partecipanti alle attività dell'Agenzia", "anchor": "art_78", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può, con l'accordo degli Stati membri interessati, invitare osservatori dalle istituzioni, organi, uffici e agenzie dell'Unione o da organizzazioni internazionali e missioni e operazioni PSDC a norma dell'articolo 68, paragrafo 1, secondo comma, lettera j), a partecipare alle sue attività, in particolare alle operazioni congiunte e ai progetti pilota, alle analisi dei rischi e alla formazione, nella misura in cui la loro presenza sia conforme agli obiettivi di tali attività, possa contribuire allo sviluppo della cooperazione e allo scambio di buone prassi e non influisca sulla sicurezza complessiva delle attività. La partecipazione di tali osservatori alle analisi dei rischi e alla formazione può avvenire solo con l'accordo degli Stati membri interessati. Per quanto riguarda le operazioni congiunte e i progetti pilota, la partecipazione di osservatori è subordinata all'accordo dello Stato membro ospitante. Norme dettagliate sulla partecipazione degli osservatori sono incluse nel piano operativo. Gli osservatori ricevono dall'Agenzia una formazione appropriata prima della loro partecipazione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia può altresì, con l'accordo degli Stati membri interessati, invitare osservatori di paesi terzi a partecipare alle sue attività alle frontiere esterne, alle operazioni di rimpatrio, agli interventi di rimpatrio e alla formazione di cui all'articolo 62, nella misura in cui la loro presenza sia conforme agli obiettivi di tali attività, possa contribuire allo sviluppo della cooperazione e allo scambio di buone prassi e non influisca sulla sicurezza complessiva di tali attività né sulla sicurezza dei cittadini di paesi terzi. Norme dettagliate sulla partecipazione degli osservatori sono incluse nel piano operativo. Gli osservatori ricevono dall'Agenzia una formazione appropriata prima della loro partecipazione. Essi sono tenuti a osservare il codice di condotta dell'Agenzia mentre partecipano alle sue attività.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia assicura che la presenza di osservatori non comporti alcun rischio connesso al rispetto dei diritti fondamentali.</p>\n</div>"]]}, "79": {"label": "Articolo 79", "heading": "", "anchor": "art_79", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia rileva e gestisce il sistema relativo ai documenti falsi e autentici online (FADO), istituito ai sensi dell'azione comune 98/700/GAI.</p>"]]}, "80": {"label": "Articolo 80", "heading": "Protezione dei diritti fondamentali e strategia in materia di diritti fondamentali", "anchor": "art_80", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La guardia di frontiera e costiera europea garantisce la tutela dei diritti fondamentali nell'esecuzione dei suoi compiti a norma del presente regolamento, ai sensi del pertinente diritto dell'Unione, in particolare la Carta e il diritto internazionale pertinente, compresi la convenzione del 1951 relativa allo status di rifugiati e il suo protocollo del 1967, la convenzione sui diritti del fanciullo e gli obblighi inerenti all'accesso alla protezione internazionale, in particolare il principio di non respingimento.</p>\n<p class=\"oj-normal\">A tal fine, l'Agenzia, con il contributo del responsabile dei diritti fondamentali e fatta salva la sua approvazione, elabora, attua e sviluppa ulteriormente una strategia e un piano d'azione in materia di diritti fondamentali, che preveda un meccanismo efficace per monitorare il rispetto dei diritti fondamentali in tutte le sue attività.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nell'esecuzione dei suoi compiti, la guardia di frontiera e costiera europea provvede affinché nessuno, in violazione del principio di non respingimento, sia obbligato a sbarcare, obbligato a entrare o condotto in un paese o altrimenti consegnato o riconsegnato alle autorità di un paese nel quale esista, tra le altre cose, un rischio serio di essere sottoposto alla pena di morte, alla tortura, alla persecuzione o ad altre pene o trattamenti inumani o degradanti o in cui la vita o la libertà dell'interessato sarebbero minacciate a causa della sua razza, della sua religione, della sua cittadinanza, del suo orientamento sessuale, della sua appartenenza a un particolare gruppo sociale o delle sue opinioni politiche, o nel quale sussista un rischio di espulsione, di allontanamento, di estradizione o di rimpatrio verso un altro paese in violazione del principio di non respingimento.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nell'esecuzione dei suoi compiti, la guardia di frontiera e costiera europea prende in considerazione le particolari esigenze dei minori, dei minori non accompagnati, delle persone con disabilità, delle vittime della tratta di esseri umani, delle persone bisognose di assistenza medica, delle persone bisognose di protezione internazionale, delle persone in pericolo in mare e di chiunque si trovi in una situazione di particolare vulnerabilità, e affronta tali esigenze nell'ambito del proprio mandato. La guardia e di frontiera e costiera europea presta particolare attenzione ai diritti dei minori in modo da garantire che in tutte le sue attività sia rispettato il loro interesse superiore.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Nell'esecuzione dei suoi compiti, nelle sue relazioni con gli Stati membri e nell'ambito della cooperazione con i paesi terzi, l'Agenzia tiene conto delle relazioni redatte dal forum consultivo di cui all'articolo 108 e delle relazioni del responsabile dei diritti fondamentali.</p>\n</div>"]]}, "81": {"label": "Articolo 81", "heading": "Codice di condotta", "anchor": "art_81", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in cooperazione con il forum consultivo, elabora e sviluppa ulteriormente un codice di condotta che si applica a tutte le operazioni di controllo di frontiera coordinate dall'Agenzia e da tutti coloro che prendono parte alle attività dell'Agenzia. Il codice di condotta stabilisce procedure intese a garantire i principi dello Stato di diritto e il rispetto dei diritti fondamentali, con particolare attenzione nel caso delle persone vulnerabili, compresi i minori, i minori non accompagnati e altre persone vulnerabili, come anche delle persone che chiedono protezione internazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia, in cooperazione con il forum consultivo, elabora e sviluppa ulteriormente un codice di condotta per le operazioni di rimpatrio e gli interventi di rimpatrio, che si applica durante tutte le operazioni di rimpatrio e gli interventi di rimpatrio coordinati o organizzati dall'Agenzia. Il codice di condotta descrive procedure standard comuni dirette a semplificare l'organizzazione delle operazioni di rimpatrio e degli interventi di rimpatrio e a garantire che esse si svolgano in maniera umana e nel pieno rispetto dei diritti fondamentali, in particolare la dignità umana, la proibizione della tortura e delle pene o trattamenti inumani o degradanti, il diritto alla libertà e alla sicurezza e il diritto alla protezione dei dati personali e la non discriminazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il codice di condotta per i rimpatri tiene conto in particolare dell'obbligo degli Stati membri di prevedere un sistema di monitoraggio efficace dei rimpatri forzati di cui all'articolo 8, paragrafo 6, della direttiva 2008/115/CE, e della strategia in materia di diritti fondamentali.</p>\n</div>"]]}, "82": {"label": "Articolo 82", "heading": "Compiti e competenze dei membri delle squadre", "anchor": "art_82", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I membri delle squadre posseggono le capacità per svolgere i compiti ed esercitare le competenze relativi ai controlli di frontiera e ai rimpatri, nonché quelle necessarie per conseguire gli obiettivi del regolamento (UE) n. 656/2014, del regolamento (UE) 2016/399 e della direttiva 2008/115/CE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Lo svolgimento dei compiti e l'esercizio dei poteri da parte dei membri delle squadre, in particolare quelli che richiedono poteri esecutivi, sono soggetti all'autorizzazione dello Stato membro ospitante sul suo territorio nonché al diritto dell'Unione, nazionale o internazionale applicabile, in particolare al regolamento (UE) n. 656/2014, quale descritto nel piano operativo di cui all'articolo 38.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nello svolgimento dei loro compiti e nell'esercizio delle loro competenze, i membri delle squadre assicurano pienamente il rispetto dei diritti fondamentali e osservano il diritto dell'Unione e quello internazionale, e la legislazione nazionale dello Stato membro ospitante.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Fatto salvo l'articolo 95, paragrafo 1, relativo al personale statutario, i membri delle squadre devono svolgere compiti ed esercitare competenze esclusivamente sotto il controllo e, di norma, in presenza di guardie di frontiera o di personale coinvolto nei compiti attinenti al rimpatrio dello Stato membro ospitante. Lo Stato membro ospitante può autorizzare i membri delle squadre ad agire per suo conto.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Lo Stato membro ospitante può riferire all'Agenzia, attraverso il funzionario di coordinamento, episodi connessi alla mancata osservanza del piano operativo, anche in relazione ai diritti fondamentali, da parte di membri delle squadre, per un eventuale seguito, comprese misure disciplinari.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il personale statutario che costituisce i membri delle squadre indossa l'uniforme del corpo permanente nello svolgimento dei loro compiti e nell'esercizio delle loro competenze. I membri delle squadre distaccati dagli Stati membri per un impiego di lunga durata o inviati per un impiego di breve durata indossano le proprie uniformi nello svolgimento dei loro compiti e nell'esercizio delle loro competenze.</p>\n<p class=\"oj-normal\">In deroga al primo comma del presente paragrafo, la decisione del consiglio di amministrazione di cui all'articolo 54, paragrafo 4, lettera a), indica i profili ai quali non si applica l'obbligo di indossare un'uniforme a causa della natura specifica dell'attività operativa.</p>\n<p class=\"oj-normal\">Tutti i membri delle squadre portano sull'uniforme un'identificazione personale visibile e un bracciale blu con il distintivo dell'Unione e dell'Agenzia, che li identifica come partecipanti a un'operazione congiunta, un intervento di una squadra di sostegno per la gestione della migrazione, un progetto pilota, un intervento rapido alle frontiere, un'operazione di rimpatrio o un intervento di rimpatrio. Perché siano identificabili dalle autorità nazionali dello Stato membro ospitante, i membri delle squadre sono sempre muniti di un documento di accreditamento, che esibiscono su richiesta.</p>\n<p class=\"oj-normal\">Il modello e le specifiche delle uniformi del personale statutario sono stabiliti da una decisione del consiglio di amministrazione, sulla base di una proposta del direttore esecutivo effettuata dopo la ricezione del parere della Commissione.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Per il personale distaccato presso l'Agenzia o inviato da uno Stato membro per un breve termine, la possibilità di portare e utilizzare armi d'ordinanza, munizioni ed equipaggiamento è soggetta alla legislazione nazionale dello Stato membro di appartenenza.</p>\n<p class=\"oj-normal\">La possibilità di portare e utilizzare armi d'ordinanza, munizioni ed equipaggiamento da parte dei membri del personale statutario distaccati come membri delle squadre è soggetta al quadro e alle regole dettagliate di cui al presente articolo e all'allegato V.</p>\n<p class=\"oj-normal\">Ai fini dell'attuazione del presente paragrafo, il direttore esecutivo può autorizzare il personale statutario a portare e utilizzare armi ai sensi delle norme adottate dal consiglio di amministrazione, in linea con l'articolo 55, paragrafo 5, lettera b).</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I membri delle squadre, compresi i membri del personale statutario, sono autorizzati per i pertinenti profili dallo Stato membro ospitante allo svolgimento di compiti durante l'impiego che richiedano l'uso della forza, inclusi il porto e l'uso delle armi di ordinanza, delle munizioni e dell'equipaggiamento, e sono soggetti al consenso dello Stato membro di appartenenza o, per il personale statutario, dell'Agenzia. L'uso della forza, compreso il porto e l'utilizzo di armi d'ordinanza, munizioni ed equipaggiamento, è esercitato ai sensi della legislazione nazionale dello Stato membro ospitante e in presenza delle guardie di frontiera dello Stato membro ospitante. Lo Stato membro ospitante può, con il consenso dello Stato membro di appartenenza o, se del caso, dell'Agenzia, autorizzare i membri delle squadre a usare la forza sul suo territorio in assenza di guardie di frontiera dello Stato membro ospitante.</p>\n<p class=\"oj-normal\">Lo Stato membro ospitante può vietare il porto di determinate armi di ordinanza, munizioni ed equipaggiamento, a condizione che la sua normativa applichi il medesimo divieto alle proprie guardie di frontiera o al personale quando impegnato in compiti attinenti ai rimpatri. Prima dell'impiego dei membri delle squadre, lo Stato membro ospitante informa l'Agenzia in merito alle armi di ordinanza, alle munizioni e all'equipaggiamento autorizzati e alle relative condizioni d'uso. L'Agenzia mette tali informazioni a disposizione degli Stati membri.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Le armi di ordinanza, le munizioni e l'equipaggiamento possono essere usati per legittima difesa personale o per legittima difesa dei membri delle squadre o di altre persone ai sensi della legislazione nazionale dello Stato membro ospitante, in linea con i pertinenti principi del diritto internazionale in materia di diritti umani e con la Carta.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Ai fini del presente regolamento, lo Stato membro ospitante autorizza i membri delle squadre a consultare le banche dati dell'Unione se tale consultazione è necessaria a conseguire gli obiettivi operativi specificati nel piano operativo per i controlli di frontiera, la sorveglianza di frontiera e i rimpatri mediante le loro interfacce nazionali o altra forma di accesso prevista negli atti giuridici dell'Unione che istituiscono tali banche dati, a seconda dei casi. Lo Stato membro ospitante può anche autorizzare i membri delle squadre a consultare le proprie banche dati nazionali, se necessario, per i medesimi obiettivi. Gli Stati membri provvedono a fornire l'accesso alle banche dati in modo efficiente ed efficace. I membri delle squadre consultano soltanto i dati strettamente necessari per lo svolgimento dei loro compiti e per l'esercizio delle loro competenze. Prima dell'impiego dei membri delle squadre, lo Stato membro ospitante informa l'Agenzia in merito alle banche dati nazionali e dell'Unione che possono essere consultate. L'Agenzia mette tali informazioni a disposizione di tutti gli Stati membri che partecipano alla missione.</p>\n<p class=\"oj-normal\">Tale consultazione è svolta nel rispetto del diritto dell'Unione in materia di protezione dei dati e della legislazione nazionale dello Stato membro ospitante in materia di protezione dei dati.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   I provvedimenti di respingimento ai sensi dell'articolo 14 del regolamento (UE) 2016/399 e le decisioni di rifiuto del visto alla frontiera ai sensi dell'articolo 35 del regolamento (CE) n. 810/2009 sono adottati soltanto dalle guardie di frontiera dello Stato membro ospitante o dai membri delle squadre se autorizzati dallo Stato membro ospitante ad agire per suo conto.</p>\n</div>"]]}, "83": {"label": "Articolo 83", "heading": "Documento di accreditamento", "anchor": "art_83", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in collaborazione con lo Stato membro ospitante, rilascia ai membri delle squadre un documento, redatto nella lingua ufficiale dello Stato membro ospitante e in un'altra lingua ufficiale delle istituzioni dell'Unione, che identifica il titolare e ne attesta il diritto di svolgere i compiti e di esercitare le competenze di cui all'articolo 82. In tale documento figurano i seguenti dati di ciascun membro delle squadre:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nome e cittadinanza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">grado o funzione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">una fotografia digitale recente; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compiti che è autorizzato a svolgere durante la missione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il documento è restituito all'Agenzia al termine di ciascuna operazione congiunta, dell'impiego di una squadra di sostegno per la gestione della migrazione, del progetto pilota, dell'intervento rapido alle frontiere, dell'operazione di rimpatrio o dell'intervento di rimpatrio.</p>\n</div>"]]}, "84": {"label": "Articolo 84", "heading": "Responsabilità civile dei membri delle squadre", "anchor": "art_84", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatto salvo l'articolo 95, quando i membri delle squadre operano in uno Stato membro ospitante, tale Stato membro è responsabile, ai sensi della sua normativa nazionale, degli eventuali danni da loro causati durante le loro operazioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ove tali danni siano causati da negligenza grave o comportamento doloso dei membri delle squadre distaccati o inviati dagli Stati membri, lo Stato membro ospitante può chiedere allo Stato membro di appartenenza il rimborso di eventuali risarcimenti versati alle parti offese o agli aventi diritto.</p>\n<p class=\"oj-normal\">Ove tali danni siano causati da negligenza grave o comportamento doloso del personale statutario, lo Stato membro ospitante può chiedere all'Agenzia il rimborso di eventuali risarcimenti versati alle parti offese o agli aventi diritto. Ciò lascia impregiudicato qualsiasi ricorso dinanzi alla Corte di giustizia dell'Unione europea («Corte di giustizia») contro l'Agenzia ai sensi dell'articolo 98.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo l'esercizio dei suoi diritti nei confronti di terzi, ciascuno Stato membro rinuncia a chiedere allo Stato membro ospitante o a qualsiasi altro Stato membro il risarcimento dei danni subiti, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Eventuali controversie tra gli Stati membri o tra uno Stato membro e l'Agenzia quanto all'applicazione dei paragrafi 2 e 3 del presente articolo, che tali Stati non possano risolvere mediante negoziati tra loro, sono da essi sottoposte alla Corte di giustizia.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fatto salvo l'esercizio dei suoi diritti nei confronti di terzi, l'Agenzia sostiene le spese connesse ai danni causati alle proprie attrezzature durante la missione, a meno che il danno non sia dovuto a negligenza grave o comportamento doloso.</p>\n</div>"]]}, "85": {"label": "Articolo 85", "heading": "Responsabilità penale dei membri delle squadre", "anchor": "art_85", "frags": [[null, "<p class=\"oj-normal\">Fatto salvo l'articolo 95, durante un'operazione congiunta, un progetto pilota, l'impiego di una squadra di sostegno per la gestione della migrazione, un intervento rapido alle frontiere, un'operazione di rimpatrio o un intervento di rimpatrio, i membri delle squadre, ivi compreso il personale statutario, sono assimilati, nel territorio dello Stato membro ospitante, al personale dello Stato membro ospitante per quanto riguarda i reati di cui potrebbero essere vittime o che potrebbero commettere.</p>"]]}, "86": {"label": "Articolo 86", "heading": "Norme generali sul trattamento dei dati personali da parte dell'Agenzia", "anchor": "art_86", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il regolamento (UE) 2018/1725 si applica al trattamento dei dati personali da parte dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione adotta norme interne sull'applicazione del regolamento (UE) 2018/1725 da parte dell'Agenzia, anche le norme sul responsabile della protezione dei dati dell'Agenzia.</p>\n<p class=\"oj-normal\">L'Agenzia può, ai sensi dell'articolo 25 del regolamento (UE) 2018/1725, adottare norme interne volte a limitare l'applicazione degli articoli da 14 a 22 e agli articoli 35 e 36 di tale regolamento. In particolare, l'Agenzia può prevedere, per lo svolgimento dei propri compiti nel settore del rimpatrio, disposizioni sulla limitazione, caso per caso, dell'applicazione di tali diritti nella misura in cui l'applicazione di tali disposizioni possa compromettere la procedura di rimpatrio. Tali limitazioni rispettano l'essenza dei diritti e delle libertà fondamentali, sono necessarie e proporzionate agli obiettivi perseguiti e contengono disposizioni specifiche, se del caso, di cui all'articolo 25, paragrafo 2, del regolamento (UE) 2018/1725.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia può trasferire i dati personali di cui agli articoli 49, 88 e 89 a un paese terzo o a un'organizzazione internazionale ai sensi deal capo V del regolamento (UE) 2018/1725, nella misura in cui tale trasferimento sia necessario per lo svolgimento dei compiti dell'Agenzia. L'Agenzia provvede affinché i dati personali trasferiti a un paese terzo o a un'organizzazione internazionale siano trattati esclusivamente per il fine per il quale sono stati forniti. L'Agenzia indica, al momento del trasferimento di dati personali a un paese terzo o a un'organizzazione internazionale, le eventuali limitazioni al loro accesso o uso, in termini generali o specifici, anche per quanto concerne il trasferimento, la cancellazione o la distruzione. Qualora tali limitazioni si rendano necessarie dopo il trasferimento dei dati personali, l'Agenzia ne informa il paese terzo o l'organizzazione internazionale di conseguenza. L'Agenzia provvede affinché il paese terzo o l'organizzazione internazionale interessati rispettino tali limitazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I trasferimenti di dati personali verso paesi terzi non pregiudicano i diritti dei richiedenti protezione internazionale e dei beneficiari di protezione internazionale, in particolare per quanto riguarda il non respingimento e il divieto di rivelare o ottenere informazioni di cui all'articolo 30 della direttiva 2013/32/UE del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">43</span>).</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli Stati membri e l'Agenzia, se del caso, garantiscono che le informazioni trasferite o divulgate a paesi terzi a norma del presente regolamento non siano trasmesse ulteriormente ad altri paesi terzi o parti terze. Disposizioni in tal senso sono incluse in qualsiasi accordo o intesa concluso con un paese terzo che preveda lo scambio di informazioni.</p>\n</div>"]]}, "87": {"label": "Articolo 87", "heading": "Finalità del trattamento dei dati personali", "anchor": "art_87", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia può trattare i dati personali solo per i seguenti scopi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolgimento dei suoi compiti di organizzazione e coordinamento di operazioni congiunte, progetti pilota, interventi rapidi alle frontiere e nell'ambito delle squadre di sostegno per la gestione della migrazione di cui agli articoli da 37 a 40;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolgimento dei suoi compiti di sostegno agli Stati membri e ai paesi terzi nelle attività precedenti al rimpatrio e di rimpatrio, di fornitura di sistemi di gestione dei rimpatri, così come di coordinamento o di organizzazione di operazioni di rimpatrio e di apporto di assistenza tecnica e operativa agli Stati membri e ai paesi terzi ai sensi dell'articolo 48;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitazione dello scambio di informazioni con gli Stati membri, la Commissione, il SEAE e i seguenti organi, uffici e agenzie dell'Unione e organizzazioni internazionali: l'EASO, il Centro satellitare dell'Unione europea, l'EFCA, l'EMSA, l'AESA e il gestore di EATMN, ai sensi dell'articolo 88;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitazione dello scambio di informazioni con le autorità di contrasto degli Stati membri, Europol o Eurojust ai sensi dell'articolo 90;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">analisi dei rischi da parte dell'Agenzia ai sensi dell'articolo 29;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolgimento dei suoi compiti nell'ambito di Eurosur ai sensi dell'articolo 89;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gestione del sistema FADO ai sensi dell'articolo 79;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">compiti amministrativi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri e le loro autorità di contrasto, la Commissione, il SEAE e gli organi, uffici e agenzie dell'Unione e le organizzazioni interazionali di cui al paragrafo 1, lettere c) e d), che forniscano dati personali all'Agenzia stabiliscono la o le finalità per cui tali dati devono essere trattati, ai sensi del paragrafo 1. L'Agenzia può decidere di trattare tali dati personali per una finalità diversa, sempre prevista dal paragrafo 1 solo caso per caso, dopo aver stabilito che tale trattamento per una finalità diversa è compatibile con la finalità iniziale per la quale sono stati raccolti i dati e se autorizzata dal fornitore dei dati personali. L'Agenzia conserva registrazioni scritte di una valutazione della compatibilità caso per caso.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia, gli Stati membri e le loro autorità di contrasto, la Commissione, il SEAE e gli organi, uffici e agenzie dell'Unione e le organizzazioni internazionali di cui al paragrafo 1, lettere c) e d), possono indicare, al momento della trasmissione di dati personali, le eventuali limitazioni al loro accesso o uso, in termini generali o specifici, anche per quanto concerne il trasferimento, la cancellazione o la distruzione. Qualora tali limitazioni si rendano necessarie dopo il trasferimento dei dati personali, essi ne informano i destinatari. I destinatari si conformano a tali limitazioni.</p>\n</div>"]]}, "88": {"label": "Articolo 88", "heading": "Trattamento dei dati personali raccolti durante le operazioni congiunte, le operazioni di rimpatrio, gli interventi di rimpatrio, i progetti pilota, gli interventi rapidi alle frontiere e gli impieghi delle squadre di sostegno per la gestione della migrazione", "anchor": "art_88", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Prima di ogni operazione congiunta, operazione di rimpatrio, gli interventi di rimpatrio, progetto pilota, intervento rapido alle frontiere o impiego di una squadra di sostegno per la gestione della migrazione, l'Agenzia e lo Stato membro ospitante stabiliscono in modo trasparente le responsabilità relative al rispetto degli obblighi in materia di protezione dei dati. Qualora la finalità e i mezzi del trattamento siano stabiliti congiuntamente dall'Agenzia e dallo Stato membro ospitante, questi ultimi sono, mediante la conclusione di un accordo interno, contitolari del trattamento.</p>\n<p class=\"oj-normal\">Per i fini di cui all'articolo 87, paragrafo 1, lettere a), b), c), e) e f), l'Agenzia tratta esclusivamente le seguenti categorie di dati personali raccolti dagli Stati membri, dai membri delle squadre, dal suo personale o dall'EASO, che le sono stati trasmessi nel contesto di operazioni congiunte, operazioni di rimpatrio, interventi di rimpatrio, progetti pilota, interventi rapidi alle frontiere, e impieghi di squadre di sostegno per la gestione della migrazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dati personali di persone che attraversano le frontiere esterne senza autorizzazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">dati personali necessari a confermare l'identità e la cittadinanza dei cittadini di paesi terzi nell'ambito delle attività di rimpatrio, compresi gli elenchi di passeggeri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">numeri di targa, numeri di identificazione dei veicoli, numeri di telefono o numeri di identificazione delle navi e degli aerei, che sono legati alle persone di cui alla lettera a) e sono necessari per analizzare le rotte e i metodi utilizzati ai fini dell'immigrazione illegale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I dati personali di cui al paragrafo 1 possono essere trattati dall'Agenzia nei seguenti casi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando la trasmissione di tali dati alle autorità dei pertinenti Stati membri responsabili del controllo delle frontiere, della migrazione, dell'asilo o dei rimpatri o ai pertinenti organi, uffici e agenzie dell'Unione è necessaria per l'adempimento dei loro compiti ai sensi del diritto dell'Unione e nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando la trasmissione di tali dati alle autorità dei pertinenti Stati membri, ai pertinenti organi, uffici e agenzie dell'Unione, ai paesi terzi di rimpatrio o alle pertinenti organizzazioni internazionali è necessaria per l'identificazione dei cittadini di paesi terzi e l'<span class=\"oj-italic\">acquis</span>izione dei documenti di viaggio, o per permettere o facilitare il rimpatrio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">quando ciò è necessario per l'elaborazione delle analisi dei rischi.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "89": {"label": "Articolo 89", "heading": "Trattamento dei dati personali nell'ambito di Eurosur", "anchor": "art_89", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando l'ambito situazionale nazionale richiede il trattamento di dati personali, tali dati sono trattati ai sensi del regolamento (UE) 2016/679 e, se del caso, alla direttiva (UE) 2016/680. Ciascuno Stato membro designa l'autorità che deve essere considerata titolare del trattamento ai sensi dell'articolo 4, punto 7, del regolamento (UE) 2016/679 o all'articolo 3, punto 8, della direttiva (UE) 2016/680, a seconda dei casi, e che ha la responsabilità centrale per il trattamento dei dati personali da parte di tale Stato membro. Ciascuno Stato membro notifica gli estremi di tale autorità alla Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I numeri di identificazione delle navi e degli aerei sono i soli dati personali ai quali è possibile accedere nell'ambito situazionale europeo e nei quadri situazionali specifici, nonché nei servizi Eurosur per la fusione dei dati.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualora il trattamento delle informazioni in Eurosur, in via eccezionale, richieda il trattamento di dati personali diversi dai numeri di identificazione delle navi e degli aerei, tale trattamento è rigorosamente limitato a quanto necessario ai fini di Eurosur ai sensi dell'articolo 18.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Lo scambio di dati personali con paesi terzi nell'ambito di Eurosur è rigorosamente limitato a quanto assolutamente necessario ai fini del presente regolamento. Esso è effettuato ai sensi del capo V del regolamento (UE) 2018/1725, da parte dell'Agenzia, e ai sensi del capo V del regolamento (UE) 2016/679 e del capo V della direttiva (UE) 2016/680 a seconda dei casi, e con le pertinenti disposizioni nazionali di recepimento di tale direttiva in materia di protezione dei dati, dagli Stati membri.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   È vietato ogni scambio di informazioni ai sensi dell'articolo 72, paragrafo 2, dell'articolo 73, paragrafo 3, e dell'articolo 74, paragrafo 3, che fornisca a un paese terzo dati che potrebbero essere utilizzati per identificare persone o gruppi di persone la cui richiesta di accesso alla protezione internazionale è in fase d'esame o che rischiano gravemente di essere sottoposte a tortura, trattamenti o pene inumani o degradanti o altra violazione dei diritti fondamentali.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Gli Stati membri e l'Agenzia conservano registri delle attività di trattamento a norma dell'articolo 30 del regolamento (UE) 2016/679, dell'articolo 24 della direttiva (UE) 2016/680 e dell'articolo 31 del regolamento (UE) 2018/1725, a seconda dei casi.</p>\n</div>"]]}, "90": {"label": "Articolo 90", "heading": "Trattamento dei dati personali operativi", "anchor": "art_90", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Qualora, nell'esercizio delle sue funzioni a norma dell'articolo 10, paragrafo 1, lettera q), del presente regolamento, tratti dati personali che ha raccolto durante il monitoraggio dei flussi migratori, lo svolgimento di analisi dei rischi o durante le operazioni volte a identificare persone sospettate di criminalità transfrontaliera, l'Agenzia tratta tali dati personali ai sensi del capo IX del regolamento (UE) 2018/1725. I dati personali trattati a tale scopo, compresi numeri di targa, numeri di identificazione dei veicoli, numeri di telefono o numeri di identificazione delle navi o degli aerei, sono relativi a persone fisiche sospettate, sulla base di fondati motivi, dalle autorità competenti degli Stati membri, da Europol, da Eurojust o dall'Agenzia di coinvolgimento nella criminalità transfrontaliera. Tali dati personali possono includere dati personali riguardanti le vittime o i testimoni laddove integrino i dati personali sulle persone sospettate trattati dall'Agenzia ai sensi del presente articolo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia scambia soltanto i dati personali di cui al paragrafo 1 del presente articolo con:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Europol o Eurojust, qualora siano strettamente necessari allo svolgimento dei rispettivi mandati e ai sensi dell'articolo 68;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità di contrasto competenti degli Stati membri, qualora siano strettamente necessari a tali autorità al fine di prevenire, accertare, indagare o perseguire gravi forme di criminalità transfrontaliera.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "91": {"label": "Articolo 91", "heading": "Conservazione dei dati", "anchor": "art_91", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia cancella i dati personali non appena essi sono stati trasmessi alle autorità competenti degli Stati membri, ad altri organi, uffici e agenzie dell'Unione e, in particolare, all'EASO o sono stati trasferiti a paesi terzi od organizzazioni internazionali o utilizzati per l'elaborazione di analisi dei rischi. Il periodo di conservazione dei dati non supera in nessun caso i 90 giorni dalla data della loro raccolta. Nei risultati delle analisi dei rischi, i dati sono resi anonimi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I dati personali trattati allo scopo di svolgere compiti attinenti al rimpatrio sono cancellati non appena sia stato conseguito lo scopo per il quale sono stati raccolti e al più tardi 30 giorni dopo il termine di tali compiti.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I dati personali operativi trattati ai fini dell'articolo 90 sono cancellati non appena l'Agenzia abbia conseguito lo scopo per il quale sono stati raccolti. L'Agenzia riesamina costantemente la necessità di conservare tali dati, in particolare i dati personali delle vittime e dei testimoni. In ogni caso, l'Agenzia riesamina la necessità di conservare tali dati entro tre mesi dall'avvio del trattamento iniziale degli stessi, e successivamente ogni sei mesi. L'Agenzia decide in merito alla conservazione continuativa dei dati personali, in particolare i dati personali delle vittime e dei testimoni, fino alla successiva revisione, solo se tale conservazione è ancora necessaria per lo svolgimento dei compiti dell'Agenzia di cui all'articolo 90.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il presente articolo non si applica ai dati personali raccolti nell'ambito del sistema FADO.</p>\n</div>"]]}, "92": {"label": "Articolo 92", "heading": "Norme di sicurezza per la protezione delle informazioni classificate e delle informazioni sensibili non classificate", "anchor": "art_92", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia adotta le proprie norme di sicurezza sulla base dei principi e delle regole stabiliti nelle norme di sicurezza della Commissione per la protezione delle informazioni classificate dell'Unione europea (ICUE) e delle informazioni sensibili non classificate, tra cui le disposizioni relative allo scambio con paesi terzi, al trattamento e alla conservazione di tali informazioni stabilite nelle decisioni (UE, Euratom) 2015/443 (<span class=\"oj-super oj-note-tag\">44</span>) e (UE, Euratom) 2015/444 (<span class=\"oj-super oj-note-tag\">45</span>) della Commissione. Qualsiasi accordo amministrativo sullo scambio di informazioni classificate con le autorità competenti di un paese terzo o, in assenza di tale accordo, qualsiasi comunicazione eccezionale ad hoc di ICUE a tali autorità, è approvato dalla Commissione in via preliminare.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione adotta le norme di sicurezza dell'Agenzia, previa approvazione della Commissione. Quando valuta le norme di sicurezza proposte, la Commissione ne assicura la compatibilità con le decisioni (UE, Euratom) 2015/443 e (UE, Euratom) 2015/444.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La classificazione non osta a che le informazioni siano messe a disposizione del Parlamento europeo. La trasmissione e la gestione delle informazioni e dei documenti trasmessi al Parlamento europeo ai sensi del presente regolamento sono conformi alle norme concernenti la trasmissione e il trattamento delle informazioni classificate applicabili tra il Parlamento europeo e la Commissione.</p>\n</div>"]]}, "93": {"label": "Articolo 93", "heading": "Natura giuridica e sede", "anchor": "art_93", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia è un organismo dell'Unione. Essa ha personalità giuridica.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia gode in tutti gli Stati membri della più ampia capacità giuridica riconosciuta alle persone giuridiche dalle rispettive legislazioni. In particolare, essa può <span class=\"oj-italic\">acquis</span>tare o alienare beni mobili e immobili e può stare in giudizio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia è indipendente per quanto attiene all'adempimento del suo mandato tecnico e operativo.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'agenzia è rappresentata dal suo direttore esecutivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia ha sede a Varsavia (Polonia).</p>\n</div>"]]}, "94": {"label": "Articolo 94", "heading": "Accordo di sede", "anchor": "art_94", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le necessarie disposizioni relative all'insediamento dell'Agenzia nello Stato membro che ne ospita la sede e alle strutture da questo messe a disposizione, nonché le norme specifiche applicabili in tale Stato membro al direttore esecutivo, ai vicedirettori esecutivi, ai membri del consiglio di amministrazione, al personale dell'Agenzia e ai loro familiari sono stabilite in un accordo di sede fra l'Agenzia e lo Stato membro che ne ospita la sede.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'accordo di sede è concluso previa approvazione del consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Lo Stato membro che ospita la sede garantisce le migliori condizioni possibili per il buon funzionamento dell'Agenzia, offrendo anche una scolarizzazione multilingue e a orientamento europeo e collegamenti di trasporto adeguati.</p>\n</div>"]]}, "95": {"label": "Articolo 95", "heading": "Personale", "anchor": "art_95", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al personale statutario si applicano lo statuto dei funzionari, il regime applicabile agli altri agenti dell'Unione e le regole adottate di comune accordo dalle istituzioni dell'Unione europea per l'applicazione di detto statuto e regime applicabile agli altri agenti dell'Unione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La sede di servizio è, in linea di principio, lo Stato membro in cui ha sede l'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In linea di principio, il personale statutario soggetto al regime applicabile agli altri agenti dell'Unione è inizialmente assunto a tempo determinato per un periodo di cinque anni. I loro contratti possono, in linea di principio, essere rinnovati una sola volta per un periodo determinato di massimo cinque anni. Qualsiasi rinnovo successivo ha durata indeterminata.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Ai fini dell'attuazione degli articoli 31 e 44, può essere nominato funzionario di coordinamento o funzionario di collegamento soltanto un membro del personale statutario soggetto allo statuto dei funzionari o al titolo II del regime applicabile agli altri agenti dell'Unione. Ai fini dell'attuazione dell'articolo 55, possono essere impiegati come membri delle squadre soltanto membri del personale statutario soggetti allo statuto dei funzionari o al regime applicabile agli altri agenti dell'Unione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il consiglio di amministrazione adotta disposizioni di attuazione per dare effetto allo statuto dei funzionari e al regime applicabile agli altri agenti dell'Unione, ai sensi dell'articolo 110, paragrafo 2, dello statuto dei funzionari.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Previa approvazione della Commissione, il consiglio di amministrazione adotta norme relative al personale degli Stati membri da distaccare presso l'Agenzia a norma dell'articolo 56, e le aggiorna se necessario. Tali norme comprendono, in particolare, le disposizioni finanziarie connesse a tali distacchi, ivi compresa l'assicurazione, nonché gli accordi di finanziamento connessi alla formazione. Tali norme tengono conto del fatto che i membri del personale sono distaccati per essere impiegati come membri delle squadre con i compiti e le competenze di cui all'articolo 82. Tali norme includono disposizioni sulle condizioni di impiego. Se del caso, il consiglio di amministrazione mira a garantire la coerenza con le regole applicabili al rimborso delle spese di missione del personale statutario.</p>\n</div>"]]}, "96": {"label": "Articolo 96", "heading": "Privilegi e immunità", "anchor": "art_96", "frags": [[null, "<p class=\"oj-normal\">All'Agenzia e al suo personale statutario si applica il protocollo n. 7 sui privilegi e sulle immunità dell'Unione europea allegato al trattato sull'Unione europea (TUE) e al TFUE.</p>"]]}, "97": {"label": "Articolo 97", "heading": "Responsabilità", "anchor": "art_97", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi gli articoli 84 e 85, l'agenzia è responsabile delle attività svolte ai sensi del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La responsabilità contrattuale dell'Agenzia è disciplinata dalla normativa applicabile al contratto interessato.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Corte di giustizia è competente a giudicare in virtù di clausole compromissorie contenute nel contratto concluso dall'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   In materia di responsabilità extracontrattuale l'Agenzia risarcisce, secondo i principi generali comuni agli ordinamenti degli Stati membri, i danni causati dai suoi servizi o dal suo personale nell'esercizio delle loro funzioni, compresi quelli connessi all'esercizio dei suoi poteri esecutivi.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La Corte di giustizia è competente a pronunciarsi in merito alle controversie relative al risarcimento dei danni di cui al paragrafo 4.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   La responsabilità personale dei membri del personale statutario nei confronti dell'Agenzia è disciplinata dalle disposizioni dello statuto dei funzionari e del regime applicabile agli altri agenti dell'Unione a essi applicabili.</p>\n</div>"]]}, "98": {"label": "Articolo 98", "heading": "Ricorso dinanzi alla Corte di giustizia", "anchor": "art_98", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Può essere presentato un ricorso dinanzi alla Corte di giustizia per l'annullamento di atti dell'Agenzia destinati a produrre effetti giuridici nei confronti di terzi, ai sensi dell'articolo 263 TFUE, e per l'inazione, ai sensi dell'articolo 265 TFUE, per responsabilità extracontrattuale in relazione a danni causati dall'Agenzia e, in virtù di una clausola compromissoria, responsabilità contrattuale in relazione a danni causati da atti dell'Agenzia, ai sensi dell'articolo 340 TFUE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia adotta tutti i provvedimenti necessari per conformarsi alle sentenze della Corte di giustizia.</p>\n</div>"]]}, "99": {"label": "Articolo 99", "heading": "Struttura amministrativa e di gestione dell'Agenzia", "anchor": "art_99", "frags": [[null, "<p class=\"oj-normal\">La struttura amministrativa e di gestione dell'Agenzia comprende:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un direttore esecutivo;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">vicedirettori esecutivi; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un responsabile dei diritti fondamentali.</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">Un forum consultivo assiste l'Agenzia come organo consultivo.</p>"]]}, "100": {"label": "Articolo 100", "heading": "Funzioni del consiglio di amministrazione", "anchor": "art_100", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Al consiglio di amministrazione compete l'adozione delle decisioni strategiche dell'Agenzia ai sensi del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il consiglio di amministrazione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il direttore esecutivo su proposta della Commissione ai sensi dell'articolo 107;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina i vicedirettori esecutivi su proposta della Commissione ai sensi dell'articolo 107;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sull'istituzione di uffici antenna o proroga la durata delle loro attività ai sensi dell'articolo 60, paragrafo 5, a maggioranza dei due terzi dei membri aventi diritto di voto:</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sulla realizzazione della valutazione delle vulnerabilità ai sensi dell'articolo 32, paragrafi 1 e 10; le decisioni che stabiliscono misure ai sensi dell'articolo 32, paragrafo 10, e sono adottate a maggioranza dei due terzi dei membri aventi diritto di voto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sull'elenco delle informazioni e dei dati obbligatori che le autorità nazionali responsabili della gestione delle frontiere, comprese le guardie costiere, nella misura in cui svolgono compiti di controllo alle frontiere, nonché le autorità nazionali responsabili dei rimpatri, devono scambiare con l'Agenzia per consentirle di svolgere i suoi compiti, fatti salvi gli obblighi stabiliti dal presente regolamento, in particolare agli articoli 49 e da 86 a 89;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sull'istituzione di un modello comune di analisi integrata dei rischi ai sensi dell'articolo 29, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta decisioni sulla natura e sulle condizioni dell'impiego dei funzionari di collegamento negli Stati membri ai sensi dell'articolo 31, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una strategia tecnica e operativa per la gestione europea integrata delle frontiere ai sensi dell'articolo 8, paragrafo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una decisione sul numero e sui profili del personale operativo per la gestione delle frontiere e la migrazione nell'ambito del corpo permanente ai sensi dell'articolo 54, paragrafo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta la relazione annuale sulle attività svolte dall'Agenzia nell'anno precedente e la trasmette entro il 1<span class=\"oj-super\">o</span> luglio di ogni anno al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">entro il 30 novembre di ogni anno, tenuto in debita considerazione il parere della Commissione, adotta, a maggioranza dei due terzi dei membri con diritto di voto, un documento unico di programmazione contenente, fra l'altro, la programmazione pluriennale dell'Agenzia e il suo programma di lavoro per l'anno successivo, e lo trasmette al Parlamento europeo, al Consiglio e alla Commissione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">predispone procedure per l'adozione da parte del direttore esecutivo di decisioni in merito ai compiti tecnici e operativi dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, a maggioranza dei due terzi dei membri con diritto di voto, il bilancio annuale dell'Agenzia ed esercita altre funzioni in relazione al bilancio dell'Agenzia a norma della sezione 4 del presente capo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esercita l'autorità disciplinare nei confronti del direttore esecutivo e, in consultazione con il direttore esecutivo, dei vicedirettori esecutivi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce il proprio regolamento interno;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce la struttura organizzativa dell'Agenzia e adotta la politica relativa al personale dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta una strategia antifrode, proporzionata al rischio di frode, tenendo conto dei costi e dei benefici delle misure da attuare;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta norme interne di prevenzione e gestione dei conflitti di interesse in relazione ai suoi membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ai sensi del paragrafo 8, esercita, nei confronti del personale statutario, i poteri conferiti dallo statuto dei funzionari all'autorità che ha il potere di nomina e dal regime applicabile agli altri agenti dell'Unione all'autorità abilitata a concludere i contratti di assunzione («poteri dell'autorità che ha il potere di nomina»);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta disposizioni di attuazione per dare effetto allo statuto dei funzionari e al regime applicabile agli altri agenti dell'Unione, ai sensi dell'articolo 110, paragrafo 2, dello statuto dei funzionari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">u)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicura un seguito adeguato alle osservazioni e alle raccomandazioni risultanti dalle relazioni di audit e valutazioni interne ed esterne e dalle indagini dell'Ufficio europeo per la lotta antifrode (OLAF);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">v)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta e aggiorna regolarmente i piani di comunicazione e divulgazione di cui all'articolo 10, paragrafo 2, secondo comma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">w)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un contabile, soggetto allo statuto dei funzionari e al regime applicabile agli altri agenti dell'Unione, che opera in completa indipendenza nell'esercizio delle sue funzioni;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">x)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decide in merito a una metodologia comune per la valutazione delle vulnerabilità, inclusi i criteri oggettivi in virtù dei quali l'Agenzia effettua la valutazione delle vulnerabilità, la frequenza di tali valutazioni e come effettuare valutazioni consecutive delle vulnerabilità;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">y)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decide in merito alla valutazione e al monitoraggio rafforzati di uno Stato membro di cui all'articolo 32, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">z)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina il responsabile dei diritti fondamentali e un responsabile aggiunto dei diritti fondamentali ai sensi dell'articolo 109;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">aa)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">stabilisce norme speciali per garantire l'indipendenza del responsabile dei diritti fondamentali nell'esercizio delle sue funzioni;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ab)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">approva gli accordi di lavoro con i paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ac)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adotta, previa approvazione della Commissione, le norme di sicurezza dell'Agenzia per la protezione delle informazioni classificate UE e delle informazioni sensibili non classificate di cui all'articolo 92;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ad)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nomina un responsabile della sicurezza, soggetto allo statuto dei funzionari e al regime applicabile agli altri agenti dell'Unione, incaricato della sicurezza all'interno dell'Agenzia, anche per la protezione delle informazioni classificate e delle informazioni sensibili non classificate;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ae)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">decide in merito a qualsiasi altra questione laddove previsto dal presente regolamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">La relazione annuale di attività di cui alla lettera j) è resa pubblica.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le proposte di decisione del consiglio di amministrazione di cui al paragrafo 2 relative ad attività specifiche dell'Agenzia da svolgere alle frontiere esterne di un determinato Stato membro, o nelle immediate vicinanze delle stesse, o gli accordi di lavoro con paesi terzi di cui all'articolo 73, paragrafo 4, richiedono il voto favorevole alla loro adozione da parte del membro del consiglio di amministrazione che rappresenta detto specifico Stato membro o uno Stato membro confinante con tale paese terzo, rispettivamente.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il consiglio di amministrazione può consigliare il direttore esecutivo su qualsiasi questione legata allo sviluppo della gestione operativa delle frontiere esterne e alla formazione, comprese le attività in materia di ricerca.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Su richiesta dell'Irlanda o del Regno Unito, il consiglio di amministrazione delibera in merito alla loro partecipazione ad attività specifiche.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione delibera caso per caso. Nelle sue decisioni il consiglio di amministrazione valuta se la partecipazione dell'Irlanda o del Regno Unito contribuisca alla realizzazione dell'attività in questione. Nelle decisioni è stabilito il contributo finanziario dell'Irlanda o del Regno Unito all'attività per la quale hanno presentato richiesta di partecipazione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione trasmette ogni anno al Parlamento europeo e al Consiglio («autorità di bilancio») tutte le informazioni pertinenti all'esito delle procedure di valutazione svolte dall'Agenzia.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il consiglio di amministrazione può istituire un comitato esecutivo composto da un massimo di quattro suoi rappresentanti, fra cui il presidente, e un rappresentante della Commissione, che assista il consiglio stesso e il direttore esecutivo nel predisporre decisioni, programmi e attività che saranno adottati dal consiglio di amministrazione e che prenda certe decisioni provvisorie e urgenti per conto del consiglio di amministrazione, qualora necessario. Il comitato esecutivo non adotta decisioni che richiedono una maggioranza dei due terzi in seno al consiglio di amministrazione. Il consiglio di amministrazione può delegare determinati compiti chiaramente definiti al comitato esecutivo, in particolare quando ciò migliora l'efficacia dell'Agenzia. Non può delegare al comitato esecutivo compiti collegati a decisioni che richiedono una maggioranza dei due terzi in seno al consiglio di amministrazione.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il consiglio di amministrazione adotta, ai sensi dell'articolo 110 dello statuto dei funzionari, una decisione basata sull'articolo 2, paragrafo 1, dello statuto dei funzionari e sull'articolo 6 del regime applicabile agli altri agenti dell'Unione, con cui delega al direttore esecutivo i poteri dell'autorità che ha il potere di nomina e stabilisce le condizioni di sospensione della delega di tali poteri. Il direttore esecutivo è autorizzato a subdelegare tali poteri.</p>\n<p class=\"oj-normal\">Qualora circostanze eccezionali lo richiedano, il consiglio di amministrazione può, mediante decisione, sospendere temporaneamente i poteri dell'autorità che ha il potere di nomina delegati al direttore esecutivo e quelli subdelegati da quest'ultimo. Può pertanto esercitarli esso stesso o delegarli a uno dei suoi membri o a un membro del personale statutario diverso dal direttore esecutivo.</p>\n</div>"]]}, "101": {"label": "Articolo 101", "heading": "Composizione del consiglio di amministrazione", "anchor": "art_101", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatto salvo il paragrafo 3, il consiglio di amministrazione è composto da un rappresentante di ciascuno Stato membro e da due rappresentanti della Commissione, ciascuno con un diritto di voto. A tal fine ogni Stato membro nomina un membro del consiglio di amministrazione e un supplente per rappresentarlo in caso di assenza. La Commissione nomina due membri e due supplenti. La durata del mandato è di quattro anni. Il mandato è rinnovabile.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I membri del consiglio di amministrazione sono nominati in base al loro elevato livello di esperienza, alle loro competenze nel settore della cooperazione operativa in materia di gestione delle frontiere e di rimpatri e alle loro pertinenti competenze gestionali, amministrative e di bilancio. Gli Stati membri e la Commissione hanno l'obiettivo di conseguire una rappresentanza di genere equilibrata nel consiglio di amministrazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I paesi associati all'attuazione, all'applicazione e allo sviluppo dell'<span class=\"oj-italic\">acquis</span> di Schengen prendono parte alle attività dell'Agenzia. Ciascuno di essi ha un rappresentante e il relativo supplente nel consiglio di amministrazione. Si applicano gli accordi elaborati in base alle pertinenti disposizioni dei rispettivi accordi di associazione, che precisano la natura, la portata e le modalità particolareggiate della partecipazione di tali paesi al lavoro dell'Agenzia, comprese disposizioni sui contributi finanziari e sul personale.</p>\n</div>"]]}, "102": {"label": "Articolo 102", "heading": "Programmazione pluriennale e programma di lavoro annuale", "anchor": "art_102", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 30 novembre di ogni anno, il consiglio di amministrazione adotta un documento di programmazione unico contenente fra l'altro la programmazione pluriennale e il programma annuale dell'Agenzia per l'anno successivo, in base a un progetto presentato dal direttore esecutivo e approvato dal consiglio di amministrazione. Il documento di programmazione unico è adottato previo parere favorevole della Commissione e, per quanto riguarda la programmazione pluriennale, previa consultazione del Parlamento europeo e del Consiglio. Qualora decida di non tener conto di elementi del parere della Commissione, il consiglio di amministrazione fornisce una giustificazione dettagliata. L'obbligo di fornire una motivazione dettagliata si applica anche agli elementi sollevati dal Parlamento europeo e dal Consiglio durante la consultazione. Il consiglio di amministrazione trasmette senza indugio il documento al Parlamento europeo, al Consiglio e alla Commissione.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il documento di cui al paragrafo 1 diventa definitivo dopo l'approvazione definitiva del bilancio generale. Se necessario, è adeguato di conseguenza.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In linea con il ciclo politico strategico pluriennale per la gestione europea integrata delle frontiere, la programmazione pluriennale definisce la programmazione strategica complessiva per il medio e lungo termine, che include gli obiettivi, i risultati attesi, gli indicatori di risultato e la pianificazione delle risorse, inclusi il bilancio pluriennale, il personale e le capacità proprie dell'Agenzia, compresa la pianificazione pluriennale indicativa dei profili del personale del corpo permanente. La programmazione pluriennale definisce i settori strategici di intervento e illustra le azioni necessarie per conseguire gli obiettivi. Essa comprende azioni strategiche per l'attuazione della strategia in materia di diritti fondamentali di cui all'articolo 80, paragrafo 1, e una strategia per il monitoraggio e il rispetto dei diritti fondamentali e per le relazioni con i paesi terzi e le organizzazioni internazionali, nonché le azioni connesse a tale strategia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La programmazione pluriennale è attuata attraverso programmi di lavoro annuali e, se del caso, è aggiornata in base all'esito di una valutazione condotta ai sensi dell'articolo 121. Se del caso, le conclusioni di tali valutazioni sono tenute in considerazione anche nel programma di lavoro annuale per l'anno successivo.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il programma di lavoro annuale contiene una descrizione delle attività da finanziare, comprendente gli obiettivi dettagliati e i risultati attesi, inclusi gli indicatori di risultato. Esso contiene inoltre un'indicazione delle risorse finanziarie e umane assegnate a ciascuna attività, ai sensi dei principi di formazione del bilancio per attività e gestione per attività. Il programma di lavoro annuale è coerente con la programmazione pluriennale. Esso indica chiaramente i compiti aggiunti, modificati o soppressi rispetto all'esercizio finanziario precedente.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il programma di lavoro annuale è adottato secondo il programma legislativo dell'Unione nei pertinenti settori della gestione delle frontiere esterne e del rimpatrio.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Qualora, dopo l'adozione di un programma di lavoro annuale, all'Agenzia sia affidato un nuovo compito, il consiglio di amministrazione modifica il programma di lavoro annuale.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Le modifiche sostanziali del programma di lavoro annuale, specialmente le modifiche che danno luogo a una riassegnazione delle risorse di bilancio per più del 2 % del bilancio annuale, sono adottate con la stessa procedura che si applica all'adozione del programma di lavoro annuale iniziale. Il consiglio di amministrazione può delegare al direttore esecutivo il potere di presentare modifiche non sostanziali del programma di lavoro annuale.</p>\n</div>"]]}, "103": {"label": "Articolo 103", "heading": "Presidenza del consiglio di amministrazione", "anchor": "art_103", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione elegge un presidente e un vicepresidente scegliendoli tra i suoi membri aventi diritto di voto. Il presidente e il vicepresidente sono eletti a maggioranza di due terzi dei membri del consiglio di amministrazione aventi diritto di voto. Il vicepresidente sostituisce il presidente in caso di impedimento di quest'ultimo a svolgere le sue funzioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il mandato del presidente e quello del vicepresidente scadono nel momento in cui cessa la loro appartenenza al consiglio di amministrazione. Nel rispetto della presente disposizione, la durata del mandato del presidente e del vicepresidente è di quattro anni. Tale mandato è rinnovabile una volta.</p>\n</div>"]]}, "104": {"label": "Articolo 104", "heading": "Riunioni del consiglio di amministrazione", "anchor": "art_104", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione si riunisce su convocazione del presidente.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo partecipa alle deliberazioni del consiglio di amministrazione, senza diritto di voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione tiene almeno due riunioni ordinarie all'anno. Si riunisce inoltre su istanza del presidente, su richiesta della Commissione o su richiesta di almeno un terzo dei membri del consiglio di amministrazione. Se necessario, il consiglio di amministrazione può tenere riunioni congiunte con i consigli di amministrazione dell'EASO e di Europol.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L'Irlanda è invitata a partecipare alle riunioni del consiglio d'amministrazione.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il Regno Unito è invitato a partecipare alle riunioni del consiglio di amministrazione che hanno luogo prima del giorno in cui i trattati cessano di applicarsi al Regno Unito ai sensi dell'articolo 50, paragrafo 3, TUE.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Sono invitati a partecipare alle riunioni del consiglio d'amministrazione anche rappresentanti dell'EASO e di Europol. Un rappresentante della FRA è invitato a partecipare alle riunioni del consiglio di amministrazione laddove vi siano punti all'ordine del giorno pertinenti per la protezione dei diritti.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il presidente del consiglio di amministrazione può inoltre invitare un esperto del Parlamento europeo a partecipare alle riunioni del consiglio di amministrazione. Il consiglio di amministrazione può invitare inoltre rappresentanti di altre istituzioni, altri organi, altri uffici e altre agenzie dell'Unione competenti. Il consiglio di amministrazione può invitare a presenziare alle riunioni in veste di osservatore, conformemente al proprio regolamento interno, qualsiasi altra persona il cui parere possa presentare un interesse.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I membri del consiglio di amministrazione possono essere assistiti da consiglieri o esperti, fatte salve le disposizioni del regolamento interno.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L'Agenzia provvede al segretariato del consiglio di amministrazione.</p>\n</div>"]]}, "105": {"label": "Articolo 105", "heading": "Votazioni", "anchor": "art_105", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi l'articolo 100, paragrafo 2, lettere c), d), k) e m), l'articolo 103, paragrafo 1, e l'articolo 107, paragrafi 2 e 4, il consiglio di amministrazione adotta le sue decisioni a maggioranza assoluta dei membri aventi diritto di voto.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni membro dispone di un voto. In assenza di un membro il suo supplente può esercitare il diritto di voto. Il direttore esecutivo non partecipa al voto.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il regolamento interno stabilisce disposizioni più dettagliate in materia di voto. Tale regolamento include le condizioni alle quali un membro può agire per conto di un altro membro nonché, se del caso, le regole in materia di quorum.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I rappresentanti dei paesi associati all'attuazione, all'applicazione e allo sviluppo dell'<span class=\"oj-italic\">acquis</span> di Schengen hanno diritti di voto limitati in corrispondenza con i rispettivi accordi. Al fine di consentire ai paesi associati di esercitare il loro diritto di voto, l'Agenzia indica in dettaglio l'ordine del giorno, individuando i punti per i quali è stato concesso un diritto di voto limitato.</p>\n</div>"]]}, "106": {"label": "Articolo 106", "heading": "Funzioni e poteri del direttore esecutivo", "anchor": "art_106", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia è diretta dal suo direttore esecutivo, che è totalmente indipendente nell'espletamento delle sue funzioni. Ferme restando le rispettive competenze delle istituzioni dell'Unione e del consiglio di amministrazione, il direttore esecutivo non sollecita né accetta istruzioni da alcun governo o altro organo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il Parlamento europeo o il Consiglio possono invitare il direttore esecutivo a riferire sull'esercizio delle sue funzioni. Ciò include informazioni sulle attività dell'Agenzia, sull'attuazione e sul monitoraggio della strategia in materia di diritti fondamentali, sulla relazione annuale di attività sulle attività dell'Agenzia nell'anno precedente, sul programma di lavoro per l'anno successivo e sulla programmazione pluriennale dell'Agenzia e su qualsiasi altra questione connessa alle attività dell'Agenzia. Il direttore esecutivo rilascia inoltre una dichiarazione dinanzi al Parlamento europeo, ove richiesto, e risponde per iscritto a qualsiasi domanda rivolta da un deputato al Parlamento europeo entro 15 giorni civili dal ricevimento di tale domanda. Il direttore esecutivo informa regolarmente gli opportuni organi e commissioni del Parlamento europeo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Salvo nei casi in cui siano previste scadenze specifiche nel presente regolamento, il direttore esecutivo provvede affinché le relazioni siano trasmesse al Parlamento europeo, al Consiglio o alla Commissione quanto prima possibile e, in ogni caso, entro sei mesi dalla fine del periodo di riferimento, a meno che il direttore esecutivo giustifichi debitamente il ritardo per iscritto.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il direttore esecutivo è responsabile della preparazione e dell'attuazione delle decisioni strategiche adottate dal consiglio di amministrazione e dell'adozione delle decisioni connesse alle attività operative dell'Agenzia ai sensi del presente regolamento. Il direttore esecutivo è investito delle funzioni e delle competenze seguenti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">proporre, preparare e attuare le decisioni strategiche e i programmi e le attività adottati dal consiglio di amministrazione nei limiti previsti dal presente regolamento, dalle relative norme di attuazione e dalla legislazione applicabile;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adottare tutte le iniziative opportune, comprese l'adozione di istruzioni amministrative interne e la pubblicazione di comunicazioni, per garantire la gestione e il funzionamento quotidiani dell'Agenzia, ai sensi del presente regolamento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparare ogni anno il progetto di documento unico di programmazione e presentarlo al consiglio di amministrazione per approvazione prima dell'invio di tale progetto al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparare ogni anno la relazione annuale di attività sulle attività dell'Agenzia e presentarla al consiglio di amministrazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">redigere un progetto di stato di previsione delle entrate e delle spese dell'Agenzia, come parte del documento unico di programmazione, a norma dell'articolo 115, paragrafo 3, ed eseguire il bilancio a norma dell'articolo 116, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">delegare i suoi poteri ad altri membri del personale statutario, nel rispetto delle regole da adottare a norma dell'articolo 100, paragrafo 2, lettera o);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">adottare una raccomandazione relativa a misure ai sensi dell'articolo 32, paragrafo 7, ivi comprese decisioni che propongono agli Stati membri di avviare e realizzare operazioni congiunte, interventi rapidi alle frontiere o un'altra azione di cui all'articolo 36, paragrafo 2;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare, approvare e coordinare le proposte degli Stati membri relative alle operazioni congiunte o agli interventi rapidi alle frontiere ai sensi dell'articolo 37, paragrafo 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare, approvare e coordinare le richieste degli Stati membri relative a operazioni di rimpatrio o a interventi di rimpatrio ai sensi degli articoli 50 e 53;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedere all'attuazione dei piani operativi di cui agli articoli 38 e 42 e all'articolo 53, paragrafo 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicurare l'attuazione della decisione del Consiglio di cui all'articolo 42, paragrafo 1;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">l)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">revocare il finanziamento delle attività ai sensi dell'articolo 46;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">m)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare prima di qualsiasi attività operativa dell'Agenzia se vi siano violazioni dei diritti fondamentali o degli obblighi in materia di protezione internazionale di natura grave o destinate a persistere ai sensi dell'articolo 46, paragrafi 4 e 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">n)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutare i risultati delle attività ai sensi dell'articolo 47;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">o)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">individuare il numero minimo di attrezzature tecniche necessarie a soddisfare il fabbisogno dell'Agenzia, in particolare per quanto riguarda la realizzazione di operazioni congiunte, l'impiego di squadre di sostegno per la gestione della migrazione, gli interventi rapidi alle frontiere, le operazioni e gli interventi di rimpatrio, ai sensi dell'articolo 64, paragrafo 6;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">p)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">proporre l'istituzione di uffici antenna o la proroga della durata del loro funzionamento ai sensi dell'articolo 60, paragrafo 5;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">q)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nominare i capi degli uffici antenna ai sensi dell'articolo 60, paragrafo 4;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">r)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparare un piano di azione che dia seguito alle conclusioni delle relazioni di audit interne ed esterne, delle valutazioni e delle indagini dell'OLAF, e informare, su base semestrale, la Commissione e, periodicamente, il consiglio di amministrazione e il comitato esecutivo in merito ai progressi compiuti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">s)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">tutelare gli interessi finanziari dell'Unione mediante l'applicazione di misure di prevenzione contro le frodi, la corruzione e qualsiasi altra attività illecita, attraverso controlli effettivi e, nel caso in cui siano riscontrate irregolarità, il recupero delle somme indebitamente corrisposte nonché, se del caso, l'applicazione di sanzioni amministrative e pecuniarie effettive, proporzionate e dissuasive;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">t)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">elaborare una strategia antifrode dell'Agenzia e presentarla al consiglio di amministrazione per approvazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Il direttore esecutivo risponde delle sue attività al consiglio di amministrazione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il direttore esecutivo è il rappresentante legale dell'Agenzia.</p>\n</div>"]]}, "107": {"label": "Articolo 107", "heading": "Nomina del direttore esecutivo e dei vicedirettori esecutivi", "anchor": "art_107", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione propone almeno tre candidati per il posto di direttore esecutivo e per i posti di ciascuno dei vicedirettori esecutivi sulla base di un elenco, successivamente alla pubblicazione del posto nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span> e, se del caso, sulla stampa o su siti Internet.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il direttore esecutivo è nominato dal consiglio di amministrazione, su proposta della Commissione di cui al paragrafo 1, sulla base del merito e della provata competenza di alto livello in materia amministrativa e gestionale, inclusa un'estesa e pertinente esperienza professionale in materia di gestione delle frontiere esterne e di rimpatri. Prima della nomina, i candidati proposti dalla Commissione sono invitati a rendere una dichiarazione dinanzi alla commissione o alle commissioni competenti del Parlamento europeo e a rispondere alle domande dei membri di tali commissioni.</p>\n<p class=\"oj-normal\">A seguito di tale dichiarazione il Parlamento europeo adotta un parere nel quale espone la sua opinione e può esprimere una preferenza per un candidato.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione nomina il direttore esecutivo tenendo conto di tale opinione. Il consiglio di amministrazione delibera alla maggioranza dei due terzi dei membri aventi diritto di voto.</p>\n<p class=\"oj-normal\">Se il consiglio di amministrazione decide di nominare un candidato diverso da quello per il quale il Parlamento europeo aveva espresso una preferenza, informa per iscritto il Parlamento europeo e il Consiglio del modo in cui è stato tenuto conto del parere del Parlamento europeo.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione, agendo su proposta della Commissione, ha potere di revoca del direttore esecutivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo è affiancato da tre vicedirettori esecutivi. A ciascun vicedirettore esecutivo è assegnato un settore di competenza specifico. In caso di assenza o indisponibilità del direttore esecutivo, ne fa le veci uno dei tre vicedirettori esecutivi.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   I vicedirettori esecutivi sono nominati dal consiglio di amministrazione, su proposta della Commissione di cui al paragrafo 1, sulla base del merito e della adeguata competenza in materia amministrativa e gestionale, compresa una pertinente esperienza professionale in materia di gestione delle frontiere esterne e di rimpatri. Il direttore esecutivo è coinvolto nel processo di selezione. Il consiglio di amministrazione delibera alla maggioranza dei due terzi dei membri aventi diritto di voto.</p>\n<p class=\"oj-normal\">Il consiglio di amministrazione ha il potere di revocare i vicedirettori esecutivi secondo la procedura di cui al primo comma.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La durata del mandato del direttore esecutivo è di cinque anni. Entro la fine di tale periodo, la Commissione effettua una valutazione che tiene conto dei risultati ottenuti dal direttore esecutivo, nonché dei compiti e delle sfide futuri dell'Agenzia.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Agendo su proposta della Commissione, la quale tiene conto della valutazione di cui al paragrafo 5, il consiglio di amministrazione può prorogare il mandato del direttore esecutivo una sola volta, per un altro periodo della durata massima di cinque anni.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il mandato dei vicedirettori esecutivi è di cinque anni. Esso può essere prorogato una sola volta dal consiglio di amministrazione, che agisce su proposta della Commissione, per un altro periodo della durata massima di cinque anni.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Il direttore esecutivo e i vicedirettori esecutivi sono assunti come agenti temporanei dell'Agenzia a norma dell'articolo 2, lettera a), del regime applicabile agli altri agenti dell'Unione.</p>\n</div>"]]}, "108": {"label": "Articolo 108", "heading": "Forum consultivo", "anchor": "art_108", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia istituisce un forum consultivo che la assiste nelle questioni legate ai diritti fondamentali fornendole una consulenza indipendente. Il direttore esecutivo e il consiglio di amministrazione, in coordinamento con il responsabile dei diritti fondamentali, possono consultare il forum consultivo in merito a qualsiasi questione connessa ai diritti fondamentali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia invita l'EASO, la FRA, l'Alto commissario delle Nazioni Unite per i rifugiati e altre pertinenti organizzazioni a partecipare al forum consultivo. Sulla base di una proposta del responsabile dei diritti fondamentali, presentata previa consultazione del direttore esecutivo, il consiglio di amministrazione decide in merito alla composizione del forum consultivo e alle modalità di comunicazione delle informazioni allo stesso. Il forum consultivo definisce i propri metodi di lavoro e stabilisce il proprio programma di lavoro previa consultazione del consiglio di amministrazione e del direttore esecutivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il forum consultivo è consultato sull'ulteriore sviluppo e attuazione della strategia in materia di diritti fondamentali, sul funzionamento del meccanismo di denuncia, sui codici di condotta e sul programma comune di base per la formazione. L'Agenzia informa il forum consultivo sul seguito dato alle sue raccomandazioni.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il forum consultivo prepara una relazione annuale sulle sue attività. Tale relazione è resa pubblica.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fermi restando i compiti del responsabile dei diritti fondamentali, il forum consultivo dispone di un accesso effettivo in modo tempestivo ed efficace a tutte le informazioni riguardanti il rispetto dei diritti fondamentali, anche mediante visite in loco effettuate durante le operazioni congiunte o gli interventi rapidi alle frontiere con l'accordo dello Stato membro ospitante o del paese terzo a seconda dei casi, presso i punti di crisi e durante le operazioni di rimpatrio e gli interventi di rimpatrio, anche nei paesi terzi. Se lo Stato membro ospitante è contrario a una visita in loco del forum consultivo a un'operazione congiunta o a un intervento rapido alle frontiere effettuato sul suo territorio, esso motiva debitamente per iscritto il proprio disaccordo all'Agenzia.</p>\n</div>"]]}, "109": {"label": "Articolo 109", "heading": "Responsabile dei diritti fondamentali", "anchor": "art_109", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il consiglio di amministrazione nomina un responsabile dei diritti fondamentali, sulla base di un elenco di tre candidati previa consultazione del forum consultivo. Il responsabile dei diritti fondamentali dispone delle qualifiche, della conoscenza specialistica e dell'esperienza professionale necessarie nel settore dei diritti fondamentali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il responsabile dei diritti fondamentali svolge i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuire alla strategia dell'Agenzia in materia di diritti fondamentali e al relativo piano d'azione, anche formulando raccomandazioni volte a migliorarli;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitorare il rispetto dei diritti fondamentali da parte dell'Agenzia, anche svolgendo indagini su qualsiasi sua attività;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">promuovere il rispetto dei diritti fondamentali da parte dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornire consulenza all'Agenzia, ove lo ritenga necessario o su richiesta, su qualsiasi attività dell'Agenzia senza ritardare tali attività;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornire pareri in merito ai piani operativi per le attività operative dell'Agenzia e ai progetti pilota e di assistenza tecnica nei paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">formulare pareri sugli accordi di lavoro;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">effettuare visite in loco durante eventuali operazioni congiunte, interventi rapidi alle frontiere, progetti pilota, l'impiego di squadre di sostegno per la gestione della migrazione, operazioni o interventi di rimpatrio, anche nei paesi terzi;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">provvedere al segretariato del forum consultivo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informare il direttore esecutivo in merito a eventuali violazioni dei diritti fondamentali nel corso delle attività dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">selezionare e gestire gli osservatori dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">svolgere qualsiasi altro compito, ove previsto dal presente regolamento.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il segretariato di cui al primo comma, lettera h), riceve istruzioni direttamente dal forum consultivo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Ai fini del paragrafo 2, primo comma, lettera j), il responsabile dei diritti fondamentali provvede in particolare a:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">designare gli osservatori dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assegnare agli osservatori dei diritti fondamentali operazioni e attività come previsto all'articolo 110, paragrafo 3;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nominare, tra gli osservatori dei diritti fondamentali, gli osservatori per i rimpatri forzati della riserva di cui all'articolo 51;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire che gli osservatori dei diritti fondamentali siano adeguatamente formati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">riferire al direttore esecutivo in merito a possibili violazioni dei diritti fondamentali segnalategli dagli osservatori dei diritti fondamentali, ove il responsabile dei diritti fondamentali lo ritenga necessario.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il direttore esecutivo risponde al responsabile dei diritti fondamentali in merito al modo in cui sono state affrontate le preoccupazioni relative a possibili violazioni dei diritti fondamentali di cui al primo comma, lettera e).</p>\n<p class=\"oj-normal\">Il responsabile dei diritti fondamentali può affidare qualsiasi compito di cui al paragrafo 2, primo comma, lettere da a) a i) e k), a uno degli osservatori dei diritti fondamentali.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le norme speciali applicabili al responsabile dei diritti fondamentali sono stabilite dal consiglio di amministrazione al fine di garantire che il responsabile dei diritti fondamentali e il suo personale siano indipendenti nell'espletamento delle loro funzioni. Il responsabile dei diritti fondamentali rende direttamente conto al consiglio di amministrazione e collabora con il forum consultivo. Il consiglio di amministrazione garantisce che sia dato seguito alle raccomandazioni del responsabile dei diritti fondamentali. Inoltre, il responsabile dei diritti fondamentali pubblica una relazione annuale sulle sue attività e sulla portata del rispetto dei diritti fondamentali di tutte le attività dell'Agenzia. Tali relazioni includono informazioni sul meccanismo di denuncia e sull'attuazione della strategia sui diritti fondamentali.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'Agenzia garantisce che il responsabile dei diritti fondamentali sia in grado di agire in modo autonomo e indipendente nell'esercizio delle sue funzioni. Il responsabile dei diritti fondamentali dispone di risorse umane e finanziarie sufficienti e adeguate, necessarie per l'adempimento dei suoi compiti.</p>\n<p class=\"oj-normal\">Il responsabile dei diritti fondamentali seleziona il suo personale che riferisce esclusivamente a esso.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il responsabile dei diritti fondamentali è assistito da un responsabile aggiunto. Il responsabile aggiunto dei diritti fondamentali è nominato dal consiglio di amministrazione sulla base di un elenco di tre candidati presentati dal responsabile dei diritti fondamentali. Il responsabile aggiunto dei diritti fondamentali dispone delle qualifiche e dell'esperienza necessarie nel settore dei diritti fondamentali ed è indipendente nell'esercizio delle sue funzioni. In caso di assenza o indisponibilità del responsabile dei diritti fondamentali, il responsabile aggiunto assume i suoi doveri e le sue responsabilità.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Il responsabile dei diritti fondamentali ha accesso a tutte le informazioni riguardanti il rispetto dei diritti fondamentali in relazione a tutte le attività dell'Agenzia.</p>\n</div>"]]}, "110": {"label": "Articolo 110", "heading": "Osservatori dei diritti fondamentali", "anchor": "art_110", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli osservatori dei diritti fondamentali, impiegati come personale statutario, valutano costantemente la conformità delle attività operative ai diritti fondamentali, forniscono consulenza e assistenza al riguardo e contribuiscono alla promozione dei diritti fondamentali nell'ambito della gestione europea integrata delle frontiere.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli osservatori dei diritti fondamentali svolgono i seguenti compiti:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitorare il rispetto dei diritti fondamentali e fornire consulenza e assistenza in materia di diritti fondamentali nella preparazione, nello svolgimento e nella valutazione delle attività operative dell'Agenzia che sono stati incaricati di controllare dal responsabile dei diritti fondamentali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fungere da osservatori per i rimpatri forzati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuire alle attività di formazione dell'Agenzia in materia di diritti fondamentali ai sensi dell'articolo 62, anche impartendo formazioni sui diritti fondamentali.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Ai fini del primo comma, lettera a), gli osservatori dei diritti fondamentali, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">seguono la preparazione dei piani operativi e riferiscono al responsabile dei diritti fondamentali per consentirgli di svolgere i compiti di cui all'articolo 109, paragrafo 2, lettera e);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">effettuano visite, anche a lungo termine, in cui si svolgono attività operative;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">collaborano e mantengono i contatti con l'agente di coordinamento di cui all'articolo 44 e gli forniscono consulenza e assistenza;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">informano l'agente di coordinamento e riferiscono al responsabile dei diritti fondamentali in merito a qualsiasi preoccupazione relativa a possibili violazioni dei diritti fondamentali nell'ambito delle attività operative dell'Agenzia; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">contribuiscono alla valutazione delle attività di cui all'articolo 47.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Fatto salvo il paragrafo 4, il responsabile dei diritti fondamentali assegna almeno un osservatore dei diritti fondamentali per ciascuna operazione. Il responsabile dei diritti fondamentali può decidere inoltre di assegnare un osservatore per monitorare qualsiasi altra attività operativa che dovesse ritenere pertinente.</p>\n<p class=\"oj-normal\">Gli osservatori dei diritti fondamentali hanno accesso a tutti i settori in cui si svolge l'attività operativa dell'Agenzia e a tutti i suoi documenti pertinenti ai fini dello svolgimento di tale attività.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli osservatori dei diritti fondamentali possono essere nominati dal responsabile dei diritti fondamentali in qualità di osservatori per il rimpatrio forzato della riserva di cui all'articolo 51. Quando gli osservatori dei diritti fondamentali fungono da osservatori per i rimpatri forzati, si applicano loro <span class=\"oj-italic\">mutatis mutandis</span> l'articolo 50, paragrafo 5, e l'articolo 51.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli osservatori dei diritti fondamentali sono nominati dal responsabile dei diritti fondamentali che è il loro superiore gerarchico. Gli osservatori dei diritti fondamentali esercitano le loro funzioni in piena indipendenza. Quando sono presenti in un'area operativa, gli osservatori dei diritti fondamentali indossano un distintivo che consente di identificarli chiaramente come osservatori dei diritti fondamentali.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Entro il 5 dicembre 2020, l'Agenzia provvede ad assumere almeno 40 osservatori dei diritti fondamentali. Il direttore esecutivo valuta annualmente se vi è la necessità di aumentare il loro numero in consultazione con il responsabile dei diritti fondamentali. In seguito a tale valutazione, il direttore esecutivo, se necessario, propone al consiglio di amministrazione di aumentare il numero di osservatori dei diritti fondamentali per l'anno successivo in funzione delle esigenze operative.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Dopo la loro assunzione, gli osservatori dei diritti fondamentali seguono una formazione intensiva in materia di diritti fondamentali che tiene conto delle qualifiche e dell'esperienza professionale precedentemente <span class=\"oj-italic\">acquis</span>ite nei settori pertinenti. L'Agenzia assicura che, per l'intera durata del loro impiego, gli osservatori dei diritti fondamentali assolvano alle loro funzioni conformemente agli standard più elevati. Per tutti gli osservatori dei diritti fondamentali sono stabiliti percorsi di formazione adeguati per garantire che siano continuamente in possesso dello sviluppo professionali necessario per consentire loro di adempiere al ruolo di osservatori dei diritti fondamentali.</p>\n</div>"]]}, "111": {"label": "Articolo 111", "heading": "Meccanismo di denuncia", "anchor": "art_111", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'Agenzia, in cooperazione con il responsabile dei diritti fondamentali, adotta le misure necessarie a istituire e sviluppare ulteriormente un meccanismo di denuncia indipendente ed efficace ai sensi del presente articolo, inteso a monitorare e assicurare il rispetto dei diritti fondamentali in tutte le attività dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualsiasi persona che sia direttamente interessata dalle azioni o dall'inazione da parte del personale che partecipa a un'operazione congiunta, a un progetto pilota, a un intervento rapido alle frontiere, all'invio di squadre di sostegno per la gestione della migrazione, a un'operazione di rimpatrio, a un intervento di rimpatrio o a un'azione operativa dell'Agenzia in un paese terzo, e che ritenga di essere stata oggetto di una violazione dei suoi diritti fondamentali a seguito di tali azioni o dell'inazione, o la parte che rappresenta tale persona, può presentare una denuncia per iscritto all'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Sono ricevibili solo le denunce comprovate riguardanti violazioni concrete dei diritti fondamentali.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il responsabile dei diritti fondamentali è competente per la gestione delle denunce ricevute dall'Agenzia in conformità del diritto a una buona amministrazione. A tal fine, il responsabile dei diritti fondamentali esamina la ricevibilità delle denunce, registra le denunce ricevibili, inoltra tutte le denunce registrate al direttore esecutivo e le denunce riguardanti i membri delle squadre allo Stato membro di appartenenza, compresi l'autorità o l'organo competenti in materia di diritti fondamentali di uno Stato membro per un'ulteriore azione in linea con il rispettivo mandato. Inoltre, il responsabile dei diritti fondamentali registra e assicura il seguito dato alla denuncia dall'Agenzia o da detto Stato membro.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   In conformità del diritto a una buona amministrazione, se una denuncia è ricevibile, il denunciante è informato del fatto che la denuncia è stata registrata, che è stata avviata una valutazione e che riceverà una risposta non appena sarà disponibile. Se la denuncia è trasmessa alle autorità o agli organi nazionali, il denunciante ne riceve le informazioni di contatto. Se la denuncia è dichiarata irricevibile, il denunciante è informato dei motivi e riceve, ove possibile, informazioni sulle soluzioni alternative per affrontare il suo problema.</p>\n<p class=\"oj-normal\">L'Agenzia prevede una procedura adeguata nei casi in cui una denuncia sia dichiarata irricevibile o infondata.</p>\n<p class=\"oj-normal\">Ogni decisione è redatta per iscritto ed è motivata. Se il caso è stato dichiarato irricevibile o infondato, il responsabile dei diritti fondamentali lo riesamina qualora il denunciante presenti nuove prove.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   In caso di denuncia registrata nei confronti di un membro del personale dell'Agenzia, il responsabile dei diritti fondamentali raccomanda al direttore esecutivo un seguito appropriato, comprese misure disciplinari, e, se del caso, l'avvio di procedimenti di giustizia civile o penale, ai sensi del presente regolamento e del diritto nazionale. Il direttore esecutivo garantisce un seguito adeguato e riferisce al responsabile dei diritti fondamentali, entro un termine stabilito, e successivamente, se necessario, a intervalli regolari, in merito all'attuazione di misure disciplinari, ai risultati e al seguito dato dall'Agenzia alla denuncia.</p>\n<p class=\"oj-normal\">Se una denuncia è connessa a questioni relative alla protezione dei dati, il direttore esecutivo consulta il responsabile della protezione dei dati dell'Agenzia prima di adottare una decisione in merito alla denuncia. Il responsabile dei diritti fondamentali e il responsabile della protezione dei dati concludono per iscritto un protocollo d'intesa, precisando la ripartizione dei loro compiti e la cooperazione in relazione alle denunce ricevute.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   In caso di denuncia registrata nei confronti di un membro delle squadre di uno Stato membro ospitante o di un altro Stato membro partecipante, compresi un membro distaccato della squadra o un esperto nazionale distaccato, lo Stato membro di appartenenza assicura un seguito appropriato, comprese, se necessarie, misure disciplinari, l'avvio di procedimenti di giustizia civile o penale e altre misure ai sensi del diritto nazionale. Lo Stato membro interessato riferisce al responsabile dei diritti fondamentali entro un determinato periodo di tempo i risultati e il seguito dato alla denuncia e successivamente, se necessario, a intervalli regolari. L'Agenzia dà seguito alla questione se non riceve alcuna informazione in proposito dallo Stato membro interessato.</p>\n<p class=\"oj-normal\">Se entro il periodo di tempo determinato lo Stato membro interessato non riferisce o fornisce una risposta incompleta, il responsabile dei diritti fondamentali ne informa il direttore esecutivo e il consiglio di amministrazione.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Qualora sia stata accertata una violazione dei diritti fondamentali o degli obblighi di protezione internazionale da parte di un membro delle squadre, l'Agenzia chiede allo Stato membro di rimuovere immediatamente tale persona dall'attività dell'Agenzia o dal corpo permanente.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Ai sensi dell'articolo 109, paragrafo 4, il responsabile dei diritti fondamentali include nella sua relazione annuale informazioni sul meccanismo di denuncia, tra cui riferimenti specifici ai risultati e al seguito dato alle denunce da parte dell'Agenzia e degli Stati membri.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il responsabile dei diritti fondamentali, ai sensi dei paragrafi da 1 a 9 e previa consultazione del forum consultivo, elabora un modulo di denuncia standardizzato che richiede informazioni dettagliate e specifiche sull'asserita violazione di diritti fondamentali. Il responsabile dei diritti fondamentali elabora altresì qualsiasi altra regola specifica, se del caso. Il responsabile dei diritti fondamentali sottopone tale modulo e tali altre regole specifiche al direttore esecutivo e al consiglio di amministrazione.</p>\n<p class=\"oj-normal\">L'Agenzia provvede a che le informazioni inerenti alla possibilità di presentare denuncia e alla relativa procedura siano prontamente disponibili, anche per le persone vulnerabili. Il modulo di denuncia standardizzato è reso disponibile sul sito web dell'Agenzia e su supporto cartaceo nel corso di tutte le attività dell'Agenzia, nelle lingue che i cittadini di paesi terzi comprendono o che ragionevolmente si suppone comprendano. Il modulo di denuncia standardizzato è facilmente accessibile anche da dispositivi mobili. L'Agenzia provvede affinché i denuncianti dispongano di ulteriori orientamenti e assistenza per la procedura di reclamo. Il responsabile dei diritti fondamentali prende in considerazione le denunce anche quando non sono state presentate mediante il modulo di denuncia standardizzato.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   I dati personali contenuti in una denuncia sono gestiti e trattati dall'Agenzia, incluso il responsabile dei diritti fondamentali, ai sensi del regolamento (UE) 2018/1725, e dagli Stati membri ai sensi del regolamento (UE) 2016/679 e della direttiva (UE) 2016/680.</p>\n<p class=\"oj-normal\">Ogniqualvolta un denunciante presenta una denuncia, si considera che esso acconsenta al trattamento dei suoi dati personali da parte dell'Agenzia e del responsabile dei diritti fondamentali ai sensi dell'articolo 5, paragrafo 1, lettera d), del regolamento (UE) 2018/1725.</p>\n<p class=\"oj-normal\">Al fine di tutelare gli interessi dei denuncianti, le denunce sono trattate in maniera riservata dal responsabile dei diritti fondamentali ai sensi del diritto nazionale e dell'Unione, a meno che il denunciante non rinunci esplicitamente al diritto alla riservatezza. Se rinuncia al diritto alla riservatezza, si considera che il denunciante accetti che il responsabile dei diritti fondamentali o l'Agenzia ne divulghi l'identità alle autorità o agli organi competenti in relazione alla questione oggetto della denuncia, se necessario.</p>\n</div>"]]}, "112": {"label": "Articolo 112", "heading": "Cooperazione interparlamentare", "anchor": "art_112", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per far fronte alla natura specifica della guardia di frontiera e costiera europea, composta dalle autorità nazionali e dall'Agenzia, e per garantire che le funzioni di controllo da parte del Parlamento europeo sull'Agenzia e dei parlamenti nazionali sulle rispettive autorità nazionali competenti siano esercitate efficacemente, come disposto rispettivamente dai trattati e dalla normativa nazionale, il Parlamento europeo e i parlamenti nazionali possono cooperare nell'ambito dell'articolo 9 del protocollo n. 1 sul ruolo dei Parlamenti nazionali nell'Unione europea allegato al TUE e al TFUE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Su invito del Parlamento europeo e dei parlamenti nazionali riuniti nel contesto del paragrafo 1, il direttore esecutivo e il presidente del consiglio di amministrazione partecipano a tali riunioni.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia trasmette la sua relazione annuale di attività ai parlamenti nazionali.</p>\n</div>"]]}, "113": {"label": "Articolo 113", "heading": "Regime linguistico", "anchor": "art_113", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   All'Agenzia si applica il regolamento n. 1 (<span class=\"oj-super oj-note-tag\">46</span>).</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Fatte salve le decisioni prese in base all'articolo 342 TFUE, sia la relazione annuale di attività, sia il programma di lavoro, sono redatti in tutte le lingue ufficiali dell'Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I servizi di traduzione necessari per il funzionamento dell'Agenzia sono forniti dal Centro di traduzione degli organi dell'Unione europea.</p>\n</div>"]]}, "114": {"label": "Articolo 114", "heading": "Trasparenza e comunicazione", "anchor": "art_114", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Quando tratta le domande di accesso ai documenti in suo possesso, l'Agenzia è soggetta al regolamento (CE) n. 1049/2001.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'Agenzia comunica di propria iniziativa informazioni sulle materie rientranti nell'ambito dei suoi compiti. Essa rende pubbliche le informazioni pertinenti, compresi la relazione annuale di attività, il programma di lavoro annuale, il codice di condotta, le analisi strategiche dei rischi, informazioni esaustive sulle operazioni congiunte precedenti e in corso, interventi rapidi alle frontiere, progetti pilota, progetti di assistenza tecnica con paesi terzi, impiego di squadre di sostegno alla gestione della migrazione, operazioni di rimpatrio o interventi di rimpatrio, anche in paesi terzi, e accordi di lavoro, e garantisce in particolare, fatto salvo l'articolo 92, che i cittadini e qualsiasi soggetto interessato dispongano rapidamente di informazioni obiettive, dettagliate, complete, affidabili e facilmente comprensibili riguardanti la sua attività. Nel fare ciò essa non rivela informazioni operative che, se rese pubbliche, comprometterebbero il conseguimento dell'obiettivo delle operazioni.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il consiglio di amministrazione stabilisce le modalità pratiche per l'applicazione dei paragrafi 1 e 2.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Qualsiasi persona fisica o giuridica ha il diritto di rivolgersi per iscritto all'Agenzia in una delle lingue ufficiali dell'Unione. Ha inoltre diritto di ricevere una risposta nella medesima lingua.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Le decisioni adottate dall'Agenzia ai sensi dell'articolo 8 del regolamento (CE) n. 1049/2001 possono costituire oggetto di denuncia presso il Mediatore europeo o di ricorso dinanzi alla Corte di giustizia alle condizioni, rispettivamente, di cui agli articoli 228 e 263 TFUE.</p>\n</div>"]]}, "115": {"label": "Articolo 115", "heading": "Bilancio", "anchor": "art_115", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatti salvi altri tipi di risorse, le entrate dell'agenzia comprendono:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dell'Unione iscritto nel bilancio generale dell'Unione europea (sezione Commissione);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un contributo dei paesi terzi associati all'attuazione, all'applicazione e allo sviluppo dell'<span class=\"oj-italic\">acquis</span> di Schengen, secondo quanto previsto nei rispettivi accordi che stabiliscono il loro contributo finanziario;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">un finanziamento dell'Unione, sotto forma di accordi di contributo o di sovvenzioni ad hoc ai sensi delle regole finanziarie dell'Agenzia di cui all'articolo 120 e delle disposizioni dei pertinenti strumenti di sostegno delle politiche dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i compensi per i servizi forniti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">ogni contributo volontario da parte degli Stati membri.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le spese dell'Agenzia comprendono le proprie spese per l'amministrazione, le infrastrutture, il funzionamento e il personale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Il direttore esecutivo predispone un progetto di stato di previsione delle entrate e delle spese dell'Agenzia per l'esercizio finanziario successivo, che comprende una tabella dell'organico, e lo trasmette al consiglio di amministrazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Le entrate e le spese risultano in pareggio.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Sulla base del progetto di stato di previsione predisposto dal direttore esecutivo, il consiglio di amministrazione adotta un progetto provvisorio di stato di previsione delle entrate e delle spese dell'Agenzia, che comprende una tabella provvisoria dell'organico. Il consiglio di amministrazione lo trasmette, come parte del progetto di documento unico di programmazione, al Parlamento europeo, al Consiglio e alla Commissione entro il 31 gennaio di ogni anno.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione trasmette alla Commissione il progetto definitivo di stato di previsione delle entrate e delle spese, che include il progetto di tabella dell'organico corredato del programma preliminare di lavoro, entro il 31 marzo di ogni anno.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   La Commissione trasmette lo stato di previsione all'autorità di bilancio unitamente al progetto di bilancio generale dell'Unione europea.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   Sulla base di tale stato di previsione, la Commissione inserisce nel progetto di bilancio generale dell'Unione europea le previsioni ritenute necessarie per la tabella dell'organico nonché l'importo del contributo da iscrivere al bilancio generale, che sottopone all'autorità di bilancio a norma degli articoli 313 e 314 TFUE.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   L'autorità di bilancio autorizza gli stanziamenti a titolo di contributo destinato all'Agenzia.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   L'autorità di bilancio adotta la tabella dell'organico per l'Agenzia.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Il consiglio di amministrazione adotta il bilancio dell'Agenzia. Questo diventa definitivo dopo l'adozione definitiva del bilancio generale dell'Unione europea. Se del caso, è sottoposto agli opportuni adeguamenti.</p>\n</div>"], [12, "<div>\n<p class=\"oj-normal\">12.   Qualsiasi modifica del bilancio, inclusa la tabella dell'organico, segue la medesima procedura.</p>\n</div>"], [13, "<div>\n<p class=\"oj-normal\">13.   Ai progetti riguardanti gli immobili che possono avere implicazioni significative per il bilancio dell'Agenzia si applicano le disposizioni del regolamento delegato (UE) 2019/715 della Commissione (<span class=\"oj-super oj-note-tag\">47</span>).</p>\n</div>"], [14, "<div>\n<p class=\"oj-normal\">14.   Per finanziare interventi rapidi alle frontiere e interventi di rimpatrio, il bilancio dell'Agenzia adottato dal consiglio di amministrazione comprende una riserva finanziaria operativa pari almeno al 2 % della dotazione prevista congiuntamente per le operazioni congiunte alle frontiere esterne e le attività operative nel settore del rimpatrio. Dopo la fine di ogni mese, il direttore esecutivo può decidere di riassegnare un importo equivalente a un dodicesimo degli stanziamenti iscritti in riserva ad altre attività operative dell'Agenzia. In tal caso, il direttore esecutivo informa il consiglio di amministrazione.</p>\n</div>"], [15, "<div>\n<p class=\"oj-normal\">15.   Gli impegni di bilancio per azioni la cui realizzazione si estende su più esercizi possono essere ripartiti su più esercizi in frazioni annue.</p>\n</div>"]]}, "116": {"label": "Articolo 116", "heading": "Esecuzione e controllo del bilancio", "anchor": "art_116", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il direttore esecutivo esegue il bilancio dell'Agenzia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro il 1<span class=\"oj-super\">o</span> marzo di un esercizio finanziario N + 1, il contabile dell'Agenzia comunica i conti provvisori per l'esercizio finanziario n al contabile della Commissione e alla Corte dei conti. Il contabile della Commissione consolida i conti provvisori delle istituzioni e degli organismi decentrati ai sensi dell'articolo 245 del regolamento (UE, Euratom) 2018/1046.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Agenzia trasmette al Parlamento europeo, al Consiglio e alla Corte dei conti una relazione sulla gestione finanziaria e di bilancio per l'anno N entro il 31 marzo dell'anno N+ 1.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Il contabile della Commissione trasmette alla Corte dei conti i conti provvisori dell'Agenzia per l'anno N, consolidati con i conti della Commissione, entro il 31 marzo dell'anno N + 1.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Al ricevimento delle osservazioni formulate dalla Corte dei conti sui conti provvisori dell'Agenzia per l'anno n, ai sensi dell'articolo 246 del regolamento (UE, Euratom) 2018/1046, il direttore esecutivo stabilisce i conti definitivi dell'Agenzia sotto la propria responsabilità e li trasmette al consiglio di amministrazione per parere.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Il consiglio di amministrazione formula un parere sui conti definitivi dell'Agenzia per l'anno N.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Entro il 1<span class=\"oj-super\">o</span> luglio dell'anno N + 1, il direttore esecutivo trasmette i conti definitivi, unitamente al parere del consiglio di amministrazione, al Parlamento europeo, al Consiglio, alla Commissione e alla Corte dei conti.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I conti definitivi per l'anno n sono pubblicati nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span> entro il 15 novembre dell'anno N + 1.</p>\n</div>"], [9, "<div>\n<p class=\"oj-normal\">9.   Al più tardi il 30 settembre dell'anno N + 1, il direttore esecutivo invia alla Corte dei conti una risposta alle osservazioni di quest'ultima. Invia inoltre tale risposta al consiglio di amministrazione.</p>\n</div>"], [10, "<div>\n<p class=\"oj-normal\">10.   Il direttore esecutivo presenta al Parlamento europeo, su richiesta dello stesso e a norma dell'articolo 261, paragrafo 3, del regolamento (UE, Euratom) 2018/1046, tutte le informazioni necessarie per il corretto svolgimento della procedura di discarico per l'esercizio n.</p>\n</div>"], [11, "<div>\n<p class=\"oj-normal\">11.   Il Parlamento europeo, su raccomandazione del Consiglio che delibera a maggioranza qualificata, dà discarico al direttore esecutivo, prima del 15 maggio dell'anno N + 2, per l'esecuzione del bilancio dell'esercizio n.</p>\n</div>"]]}, "117": {"label": "Articolo 117", "heading": "Lotta antifrode", "anchor": "art_117", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per la lotta alle frodi, alla corruzione e ad altre attività illegali, si applicano senza restrizioni le disposizioni del regolamento (UE, Euratom) n. 883/2013. L'Agenzia aderisce all'accordo interistituzionale del 25 maggio 1999 relativo alle indagini interne svolte dall'Ufficio europeo per la lotta antifrode (OLAF) e adotta immediatamente le opportune disposizioni applicabili a tutto il personale dell'Agenzia utilizzando i modelli riportati nell'allegato di tale accordo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Corte dei conti ha il potere di revisione contabile, esercitabile sulla base di documenti e mediante ispezioni sul posto, su tutti i beneficiari di sovvenzioni, contraenti e subcontraenti che hanno ottenuto finanziamenti dell'Unione da parte dell'Agenzia.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'OLAF può svolgere indagini amministrative, compresi controlli e verifiche sul posto, ai sensi delle disposizioni e secondo le procedure di cui al regolamento (UE, Euratom) n. 883/2013 e al regolamento (Euratom, CE) n. 2185/96 del Consiglio (<span class=\"oj-super oj-note-tag\">48</span>), per accertare eventuali frodi, casi di corruzione o altre attività illecite lesive degli interessi finanziari dell'Unione in relazione a convenzioni o decisioni di sovvenzione o a contratti finanziati dall'Agenzia.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   A norma del regolamento (UE) 2017/1939, la Procura europea (EPPO) può indagare e perseguire le frodi e altre attività illegali lesive degli interessi finanziari dell'Unione secondo quanto disposto dalla direttiva (UE) 2017/1371.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Fatti salvi i paragrafi da 1 a 4, gli accordi di lavoro con paesi terzi e organizzazioni internazionali, le convenzioni di sovvenzione, le decisioni di sovvenzione e i contratti dell'Agenzia contengono disposizioni che autorizzano esplicitamente la Corte dei conti, l'OLAF e l'EPPO a procedere a tali revisioni contabili e indagini conformemente alle loro rispettive competenze.</p>\n</div>"]]}, "118": {"label": "Articolo 118", "heading": "Prevenzione dei conflitti di interesse", "anchor": "art_118", "frags": [[null, "<p class=\"oj-normal\">L'Agenzia adotta norme interne che impongono ai membri dei suoi organi e del suo personale di evitare, durante il rapporto di impiego o il mandato, qualsiasi situazione suscettibile di causare un conflitto di interesse, e di segnalare tali situazioni.</p>"], [null, "<p class=\"oj-normal\">L'Agenzia garantisce la trasparenza delle lobby mediante un registro per la trasparenza e rendendo noti tutti i suoi incontri con terzi interessati. Nel registro per la trasparenza sono riportati tutti gli incontri e i contatti tra le parti interessate terze e il direttore esecutivo, dei vicedirettori esecutivi e dei capi divisione per quanto riguarda questioni attinenti ad appalti e gare per servizi, attrezzature o progetti e studi esternalizzati. L'Agenzia tiene un registro di tutti gli incontri del proprio personale con terzi interessati per quanto riguarda questioni attinenti ad appalti e gare per servizi, attrezzature o progetti e studi esternalizzati.</p>"]]}, "119": {"label": "Articolo 119", "heading": "Indagini amministrative", "anchor": "art_119", "frags": [[null, "<p class=\"oj-normal\">Le attività dell'Agenzia sono soggette alle indagini del Mediatore europeo ai sensi dell'articolo 228 TFUE.</p>"]]}, "120": {"label": "Articolo 120", "heading": "Disposizioni finanziarie", "anchor": "art_120", "frags": [[null, "<p class=\"oj-normal\">Le regole finanziarie applicabili all'Agenzia sono adottate dal consiglio di amministrazione previa consultazione della Commissione. Esse si discostano dal regolamento delegato (UE) n. 1271/2013 solo per esigenze specifiche di funzionamento dell'Agenzia e previo accordo della Commissione. In tale contesto, il consiglio di amministrazione adotta regole finanziarie specifiche applicabili alle attività dell'Agenzia nel settore della cooperazione con i paesi terzi in materia di rimpatrio.</p>"]]}, "121": {"label": "Articolo 121", "heading": "Valutazione", "anchor": "art_121", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Fatto salvo l'articolo 59, entro il 5 dicembre 2023, e successivamente ogni quattro anni, la Commissione effettua una valutazione del presente regolamento. La valutazione verte in particolare sui seguenti elementi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i risultati conseguiti dall'Agenzia in relazione ai suoi obiettivi, al suo mandato, alle sue risorse e ai suoi compiti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'incidenza, l'efficacia e l'efficienza delle prestazioni dell'Agenzia e delle sue prassi di lavoro in relazione ai suoi obiettivi, al suo mandato e ai suoi compiti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la cooperazione tra agenzie a livello europeo, compresa l'attuazione della cooperazione europea in materia di funzioni di guardia costiera;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'eventuale necessità di modificare il mandato dell'Agenzia;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le implicazioni finanziarie di tali modifiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il funzionamento del corpo permanente e, a partire dalla seconda valutazione, il numero complessivo dei suoi effettivi e la sua composizione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il livello di formazione, competenza specializzata e professionalità del corpo permanente.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">La valutazione comporta un'analisi specifica del modo in cui sono stati osservati la Carta dei diritti fondamentali e il pertinente diritto dell'Unione nell'applicazione del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La valutazione esamina anche l'attrattiva dell'Agenzia in quanto datore di lavoro per l'assunzione di personale statutario, al fine di garantire la qualità dei candidati e l'equilibrio geografico.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nell'effettuare la valutazione la Commissione consulta le parti interessate, compresi il forum consultivo e la FRA.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione trasmette relazioni di valutazione, corredate delle proprie conclusioni al riguardo, al Parlamento europeo, al Consiglio e al consiglio di amministrazione. Il consiglio di amministrazione può formulare raccomandazioni alla Commissione in merito a modifiche del presente regolamento. Le relazioni di valutazione e le conclusioni sulle relazioni sono rese pubbliche. Gli Stati membri e l'Agenzia forniscono alla Commissione le informazioni necessarie per redigere le relazioni di valutazione. Se necessario, le relazioni di valutazione sono corredate di proposte legislative.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Entro il 1<span class=\"oj-super\">o</span> dicembre 2021 e, in seguito, ogni due anni, l'Agenzia presenta al Parlamento europeo e al Consiglio una relazione sul funzionamento di Eurosur.</p>\n<p class=\"oj-normal\">Gli Stati membri trasmettono all'Agenzia le informazioni necessarie per redigere tali relazioni.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Nell'ambito della valutazione di cui al paragrafo 1, la Commissione fornisce una valutazione globale di Eurosur corredata, se necessario, di proposte appropriate per migliorarne il funzionamento.</p>\n<p class=\"oj-normal\">Gli Stati membri e l'Agenzia forniscono alla Commissione le informazioni necessarie per elaborare la valutazione globale di cui al primo comma.</p>\n<p class=\"oj-normal\">Nell'effettuare la valutazione globale di cui al primo comma la Commissione consulta le parti interessate, compresi il forum consultivo e la FRA.</p>\n</div>"]]}, "122": {"label": "Articolo 122", "heading": "Procedura di comitato", "anchor": "art_122", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione è assistita da un comitato («comitato per la guardia di frontiera e costiera europea»). Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</p>\n</div>"]]}, "123": {"label": "Articolo 123", "heading": "Abrogazione e disposizioni transitorie", "anchor": "art_123", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il regolamento (UE) n. 1052/2013 è abrogato a eccezione dell'articolo 9, paragrafi 3, 5 e da 7 a 10, e dell'articolo 10, paragrafi 5 e 7, che sono abrogati con effetto a decorrere dalla data dell'entrata in vigore dell'atto di esecuzione di cui all'articolo 24, paragrafo 3, del presente regolamento.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il regolamento (UE) 2016/1624 è abrogato a eccezione degli articoli 20, 30 e 31, che sono abrogati a decorrere dal 1<span class=\"oj-super\">o</span> gennaio 2021.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli impieghi a norma degli articoli da 55 a 58 hanno luogo a decorrere dal 1<span class=\"oj-super\">o</span> gennaio 2021.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Per gli impieghi previsti nel 2021, il consiglio di amministrazione adotta le decisioni di cui all'articolo 54, paragrafo 4, e all'articolo 64, paragrafo 6, entro il 31 marzo 2020.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Al fine di sostenere lo sviluppo delle risorse umane per assicurare il contributo degli Stati membri al corpo permanente della guardia di frontiera e costiera europea, gli Stati membri hanno diritto a ricevere finanziamenti nel 2020 ai sensi dell'articolo 61, paragrafo 1, lettera a). Le cifre di cui all'allegato III per l'anno 2022 fungono da riferimento per il pertinente finanziamento nel 2020.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Al fine di contribuire efficacemente alle capacità di personale di categoria I, richieste per i primi impieghi del corpo permanente della guardia di frontiera e costiera europea, e all'istituzione dell'unità centrale ETIAS, l'Agenzia avvia i preparativi necessari, anche in materia di assunzioni e formazione, a decorrere dal 4 dicembre 2019 e conformemente alle regole di bilancio.</p>\n</div>"], [7, "<div>\n<p class=\"oj-normal\">7.   Fino al 5 dicembre 2021, gli Stati membri possono fornire informazioni a Eurosur sui controlli di frontiera e sulla sorveglianza delle frontiere aeree su base volontaria.</p>\n</div>"], [8, "<div>\n<p class=\"oj-normal\">8.   I riferimenti agli atti abrogati si intendono fatti al presente regolamento e si leggono secondo la tavola di concordanza di cui all'allegato VI del presente regolamento.</p>\n</div>"]]}, "124": {"label": "Articolo 124", "heading": "Entrata in vigore e applicabilità", "anchor": "art_124", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span>.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'articolo 79 si applica a decorrere dalla data del trasferimento effettivo del sistema di cui a tale articolo.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'articolo 12, paragrafo 3, l'articolo 70 e l'articolo 100, paragrafo 5, nella misura in cui riguardano la cooperazione con il Regno Unito, si applicano fino alla data in cui i trattati cesseranno di applicarsi al Regno Unito ai sensi dell'articolo 50, paragrafo 3, TUE oppure, a condizione che entri in vigore un accordo di recesso concluso con il Regno Unito a norma dell'articolo 50, paragrafo 2, TUE entro tale data, fino alla fine del periodo di transizione previsto in tale accordo di recesso.</p>\n</div>"]]}}, "recitals": {}};